import Link from '../../components/Link';
import ScrollContainer from '../../components/ScrollContainer';
import InnerLink from '../../components/InnerLink';
const _pact_parchment = {title: "Pact Parchment", jsx: <><h2 id="magic-wondrous-pact_parchment-pact-parchment">Pact Parchment</h2>
<p><strong>Sources</strong> <Link to="/source/cheliax_empire_of_devils">Cheliax, Empire of Devils pg. 21</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 11th<br/><strong>Slot</strong> none; <strong>Price</strong> 3,500 gp; <strong>Weight</strong> -</p>
<p>Written and signed in blood, a pact parchment ensures the utter and undeniable fulfillment of the actions stated within. Upon a pact parchment, you can inscribe a contract, defining a certain service or course of action by one or more creatures. If all listed creatures willingly (without magical influence, threats, and so on) sign this pact in blood, they are bound to fulfill this agreement. Henceforth everyone breaking the pact suffers a -4 penalty on attack rolls, saves, ability checks, and skill checks, until they either satisfy the pact's conditions (if still possible) or the parchment is destroyed.</p>
<h3 id="magic-wondrous-pact_parchment-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/geas_quest">geas/quest</Link>; <strong>Cost</strong> 1,750 gp</p>
</>};
const _padma_blossom = {title: "Padma Blossom", jsx: <><h2 id="magic-wondrous-padma_blossom-padma-blossom">Padma Blossom</h2>
<p><strong>Sources</strong> <Link to="/source/cult_of_the_ebon_destroyers">Cult of the Ebon Destroyers pg. 28</Link><br/><strong>Aura</strong> faint abjuration and enchantment; <strong>CL</strong> 3rd<br/><strong>Slot</strong> none; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> -</p>
<p>This perfect lotus flower formed from pink jade offers purity of mind and spiritual calm. While grasped, the blossom grants its holder a +3 competence bonus on <Link to="/rule/concentration">concentration</Link> checks and suppresses the following on its holder: morale bonuses, fear effects, and the <Link to="/misc/confused">confused</Link>, <Link to="/misc/dazed">dazed</Link>, or <Link to="/misc/stunned">stunned</Link> conditions. Twice per day, the bearer can cast <em>calm emotions.</em></p>
<h3 id="magic-wondrous-padma_blossom-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/calm_emotions">calm emotions</Link>, <Link to="/spell/remove_fear">remove fear</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _page_of_spell_knowledge_1st = {title: "Page of Spell Knowledge (1st)", jsx: <><h2 id="magic-wondrous-page_of_spell_knowledge_1st-page-of-spell-knowledge">Page of Spell Knowledge</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 314</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 17th<br/><strong>Slot</strong> none; <strong>Price</strong> 1,000 gp (1st), 4,000 gp (2nd), 9,000 gp (3rd), 16,000 gp (4th), 25,000 gp (5th), 36,000 gp (6th), 49,000 gp (7th), 64,000 gp (8th), 81,000 gp (9th); <strong>Weight</strong> -</p>
<p>This page is covered in densely-worded arcane or divine magical runes. It contains the knowledge of a single arcane or divine spell (chosen by the creator when the item is crafted). If the bearer is a spontaneous spellcaster and has that spell on her class spell list, she may use her spell slots to cast that spell as if it were one of her spells known. A page of spell knowledge is priced based on the spell's cleric or sorcerer/wizard spell level, unless the spell doesn't appear on either of those spell lists, in which case it is based on the highest spell level as it appears on any other spell list. For example, a spell that is on the 4th-level inquisitor list and the 2nd-level paladin list is priced as a 4th-level spell.</p>
<h3 id="magic-wondrous-page_of_spell_knowledge_1st-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, creator must be able to cast the spell contained in the page; <strong>Cost</strong> 500 gp (1st), 2,000 gp (2nd), 4,500 gp (3rd), 8,000 gp (4th), 12,500 gp (5th), 18,000 gp (6th), 24,500 gp (7th), 32,000 gp (8th), 40,500 gp (9th)</p>
</>};
const _palelight_torch = {title: "Palelight Torch", jsx: <><h2 id="magic-wondrous-palelight_torch-palelight-torch">Palelight Torch</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_shadows">Blood of Shadows pg. 21</Link><br/><strong>Aura</strong> faint evocation; <strong>CL</strong> 2nd<br/><strong>Slot</strong> none; <strong>Price</strong> 250 gp; <strong>Weight</strong> 1 lb.</p>
<p>This torch is made from a dull, gray wood that bears intricate carvings. It burns like a normal torch, but only gives off <Link to="/rule/dim_light">dim light</Link> in a 40-foot radius. In areas of normal light, the torch reduces the light level to dim. The torch has no effect in areas of bright light.</p>
<h3 id="magic-wondrous-palelight_torch-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/light">light</Link>; <strong>Cost</strong> 125 gp</p>
</>};
const _panacea_flask = {title: "Panacea Flask", jsx: <><h2 id="magic-wondrous-panacea_flask-panacea-flask">Panacea Flask</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_runescars_1">Pathfinder Runescars #1 pg. 28</Link><br/><strong>Aura</strong> faint evocation; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> 1/2 lb.</p>
<p>This unassuming pewter flask is dented and tarnished. When filled with alcohol of any kind, a panacea flask imparts the benefits of <em>remove disease</em> once per day on whoever drinks out of it. Whether or not the <em>remove disease</em> effect is successful, the drinker gains a +1 morale bonus to saving throws for 1 hour, after which he is <Link to="/misc/sickened">sickened</Link> until he sleeps for 8 hours.</p>
<h3 id="magic-wondrous-panacea_flask-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/remove_disease">remove disease</Link>, <Link to="/spell/resistance">resistance</Link>, creator must worship <Link to="/faith/cayden_cailean">Cayden Cailean</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _papyrus_of_eternal_rest = {title: "Papyrus of Eternal Rest", jsx: <><h2 id="magic-wondrous-papyrus_of_eternal_rest-papyrus-of-eternal-rest">Papyrus of Eternal Rest</h2>
<p><strong>Sources</strong> <Link to="/source/haunted_heroes_handbook">Haunted Heroes Handbook pg. 31</Link><br/><strong>Aura</strong> faint necromancy; <strong>CL</strong> 1st<br/><strong>Slot</strong> none; <strong>Price</strong> 4,000 gp; <strong>Weight</strong> -</p>
<p>This 12-inch-long scroll is scribed on papyrus that has been anointed with <Link to="/eq-weapon/holy_water">holy water</Link>. Written on the scroll's face in Minkaian are three to four pictographs that bid the reader a peaceful rest. A papyrus of eternal rest grants its owner a <Link to="/umr/gaze">gaze</Link> attack with a range of 30 feet whenever she wields the item in one hand and clearly presents it before her. Haunts and incorporeal undead must succeed at a DC 12 Will save or take 1d6 points of damage and become <Link to="/misc/sickened">sickened</Link> for 1 round. A successful Will save prevents the sickened condition and reduces the damage by half. Haunts can't avoid looking at a papyrus of eternal rest, but incorporeal undead can as normal.</p>
<p>The user of a papyrus of eternal rest cannot wield both a weapon and the papyrus in the same hand, and the hand presenting the papyrus cannot be used to complete the somatic components of spells. Because of the item's light weight, however, wielding a papyrus of eternal rest does not count as having an occupied hand for the purpose of the <Link to="/feat/fencing_grace">Fencing Grace</Link>, <Link to="/feat/slashing_grace">Slashing Grace</Link>, or <Link to="/feat/starry_grace">Starry Grace</Link> feats, a swashbuckler's <Link to="/swashdeed/precise_strike">precise strike</Link> deed, and similar effects.</p>
<h3 id="magic-wondrous-papyrus_of_eternal_rest-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bane">bane</Link>, <Link to="/spell/disrupt_undead">disrupt undead</Link>; <strong>Cost</strong> 2,000 gp</p>
</>};
const _paradox_box = {title: "Paradox Box", jsx: <><h2 id="magic-wondrous-paradox_box-paradox-box">Paradox Box</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_61_shards_of_sin">Pathfinder #61: Shards of Sin pg. 64</Link><br/><strong>Aura</strong> moderate abjuration and conjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> none; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> 30 lbs.</p>
<p>A paradox box resembles a small stone chest of ornate design that measures approximately 1-1/2 feet by 1-1/2 feet by 1 foot. Closer inspection reveals the paradox box to be a solid piece of stone that's been carved to resemble a box - it has no seam for a lid or hinges to allow opening. It is a secure storage device that can be accessed only by use of the proper command word or combination. Until the command word is intoned or the combination is correctly entered (the box's creator decides which method of opening works for the box - most boxes have combination locks), the box is effectively a solid piece of stone with no lid or aperture or even an interior, and as such, attempts to open the box by bypassing a lock (with <Link to="/skill/disable_device">Disable Device</Link> or <Link to="/spell/knock">knock</Link>) do not work. Some creators also build magical traps into paradox boxes (<Link to="/trap/summon_monster_trap">summon monster traps</Link> are particularly popular), but these traps are not included in the standard model.</p>
<p>Once the proper command is given, a seam appears around the chest, and nested hinges within allow this lid to open, revealing an extradimensional space 1 cubic foot in size. Anything that will fit completely within that space (regardless of weight) can be successfully stored within, and the chest can be sealed again simply by closing it. The contents of the storage space do not change the weight of the chest, since they actually stay in an otherwise inaccessible extradimensional space. If the chest is destroyed (hardness 8, hp 90), the extradimensional space collapses and any contents are jettisoned randomly into the Ethereal Plane.</p>
<p>Paradox boxes were especially popular in Thassilon for their relative inexpensiveness as well as their superior security and durability. Many Thassilonian creators, burdened with arrogance and hubris, constructed their paradox boxes such that their surfaces were decorated with elaborate and carefully constructed riddles or wordplays that gave clues to their command words. These items are prize finds for organizations such as the <Link to="/rule/pathfinder_society">Pathfinder Society</Link>, because a particularly clever investigator can often still open them, revealing their time-lost secrets even though the command word might have been lost millennia ago.</p>
<h3 id="magic-wondrous-paradox_box-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/arcane_lock">arcane lock</Link>, <Link to="/spell/secret_chest">secret chest</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _paralyzing_snare = {title: "Paralyzing Snare", jsx: <><h2 id="magic-wondrous-paralyzing_snare-paralyzing-snare">Paralyzing Snare</h2>
<p><strong>Sources</strong> <Link to="/source/kobolds_of_golarion">Kobolds of Golarion pg. 31</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 9th<br/><strong>Slot</strong> none; <strong>Price</strong> 2,250 gp; <strong>Weight</strong> 2 lbs.</p>
<p>Once the command word is spoken, this 5-foot-diameter loop of wire blends with its surroundings. To find it, a character with the <Link to="/ability/trapfinding">trapfinding</Link> ability must succeed at a DC 30 <Link to="/skill/perception">Perception</Link> check. Setting the snare is a full-round action that provokes attacks of opportunity. Any creature that steps into the snare must succeed at a DC 26 Will save or become magically <Link to="/rule/paralyzed">paralyzed</Link>, as the spell <em>hold monster.</em> This effect can be ended by uttering the command word, succeeding at a DC 30 <Link to="/skill/disable_device">Disable Device</Link> check, or succeeding at the Will save. The snare is destroyed when the effect ends.</p>
<h3 id="magic-wondrous-paralyzing_snare-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/snare">snare</Link>, <Link to="/spell/hold_monster">hold monster</Link>; <strong>Cost</strong> 1,200 gp</p>
</>};
const _parley_ward = {title: "Parley Ward", jsx: <><h2 id="magic-wondrous-parley_ward-parley-ward">Parley Ward</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 249</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 11th<br/><strong>Slot</strong> none; <strong>Price</strong> 52,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>This hemispherical dome of jet-black crystal has no discernible markings on its curved surface, but faint runes (including the command word) are visible on the flat side. Three times per week, whenever it is placed flat side down and the command word is spoken, the parley ward hums and projects a black dome-shaped field that slowly expands for 1 minute and then finally snaps into place, covering up to a 30-foot-radius area, though the area can be reduced and shaped to encompass the interior of a room or structure (such as a meeting hall or pavilion) in order to make it less obvious to those on the outside. The affected area becomes a protected zone that provides complete privacy, preventing sound, light, and divination and scrying spells from penetrating, as per the <em>mage's private sanctum</em> spell. Additionally, the protected zone discourages any creatures within from committing deliberate hostile acts, as though they were affected by the <em>serenity</em> spell (with no save allowed). Each use of the magic of the parley ward can function for up to 24 hours, or until the user deactivates it. Once the parley ward is activated, neither the item nor its zone can be moved; attempting to do so deactivates it, consuming one of its 3 weekly charges.</p>
<h3 id="magic-wondrous-parley_ward-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/mages_private_sanctum">mage's private sanctum</Link>, <Link to="/spell/serenity">serenity</Link>; <strong>Cost</strong> 26,000 gp</p>
</>};
const _parting_glass = {title: "Parting Glass", jsx: <><h2 id="magic-wondrous-parting_glass-parting-glass">Parting Glass</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_temples">Inner Sea Temples pg. 22</Link><br/><strong>Aura</strong> strong enchantment; <strong>CL</strong> 12th<br/><strong>Slot</strong> none; <strong>Price</strong> 23,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Not every adventurer returns to the tavern, and Cayden's Hall has seen many a drink raised in remembrance of a fallen comrade. A parting glass, engraved with the names of adventuring companies and their honored dead, is a rare gift given by senior priests of <Link to="/faith/cayden_cailean">Cayden Cailean's</Link> church to survivors of quests that fit with the church's ideals but demanded a high cost.</p>
<p>Once per day when used in a toast with at least one other creature, a single creature drinking from a parting glass gains a +5 morale bonus on the next saving throw it attempts within 24 hours, and one poison (other than alcohol) currently affecting the drinker is targeted by <em>neutralize poison.</em></p>
<h3 id="magic-wondrous-parting_glass-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/greater_heroism">greater heroism</Link>, <Link to="/spell/neutralize_poison">neutralize poison</Link>; <strong>Cost</strong> 11,500 gp</p>
</>};
const _pathfinder_pouch = {title: "Pathfinder Pouch", jsx: <><h2 id="magic-wondrous-pathfinder_pouch-pathfinder-pouch">Pathfinder Pouch</h2>
<p><strong>Sources</strong> <Link to="/source/seekers_of_secrets">Seekers of Secrets pg. 56</Link><br/><strong>Aura</strong> none; <strong>CL</strong> 9th<br/><strong>Slot</strong> none; <strong>Price</strong> 1,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This nondescript belt pouch is quite popular among Pathfinders who need to smuggle items past snooping guards or government officials. Detect magic does not detect that it is magical (as per the <em>magic aura</em> spell), but the pouch acts as a very small <Link to="/magic-wondrous/bag_of_holding">bag of holding</Link> (contents limit 10 pounds, volume limit 2 cubic feet).</p>
<p>With a command word, the wearer can close or open the extradimensional space within the pouch; when closed, the pouch holds no more than a mundane belt pouch the size of a human fist, though objects within the extradimensional space remain stored, unreachable until the pouch is unsealed again. This allows the user to empty his pockets or even turn the pouch inside-out to prove he carries no contraband, and access the hidden goods later when in a safe place. Because of their nonmagical auras, these pouches sometimes hold secret treasures for generations without their owners realizing their nature.</p>
<h3 id="magic-wondrous-pathfinder_pouch-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/magic_aura">magic aura</Link>, <Link to="/spell/secret_chest">secret chest</Link>; <strong>Cost</strong> 1,000 gp</p>
</>};
const _pathfinders_coin = {title: "Pathfinder's Coin", jsx: <><h2 id="magic-wondrous-pathfinders_coin-pathfinders-coin">Pathfinder's Coin</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_society_field_guide">Pathfinder Society Field Guide pg. 53</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 3rd<br/><strong>Slot</strong> none; <strong>Price</strong> 1,500 gp; <strong>Weight</strong> -</p>
<p>This apparently simple coin, usually styled to resemble ancient currency, hides intricate gold and platinum wires within. This matrix, carefully modeled after fragmentary Azlanti coins, causes the Pathfinder's coin to rise an inch into the air and slowly spin in place if placed atop a <Link to="/magic-wondrous/wayfinder">wayfinder</Link>. In addition, when levitating above a wayfinder, the coin can be given a message of 25 words or fewer. This message repeats in the speaker's voice the next time the coin is floated above a wayfinder. Only one message may be stored at a time, and once it is triggered, the message is expended and a new one may be recorded.</p>
<h3 id="magic-wondrous-pathfinders_coin-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/identify">identify</Link>, <Link to="/spell/levitate">levitate</Link>, <Link to="/spell/magic_mouth">magic mouth</Link>; <strong>Cost</strong> 750 gp</p>
</>};
const _pearl_of_power = {title: "Pearl of Power", jsx: <><h2 id="magic-wondrous-pearl_of_power-pearl-of-power">Pearl of Power</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 315</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 525</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 17th<br/><strong>Slot</strong> none; <strong>Price</strong> 1,000 gp (1st), 4,000 gp (2nd), 9,000 gp (3rd), 16,000 gp (4th), 25,000 gp (5th), 36,000 gp (6th), 49,000 gp (7th), 64,000 gp (8th), 70,000 gp (Two Spells), 81,000 gp (9th); <strong>Weight</strong> -</p>
<p>This seemingly normal pearl of average size and luster is a potent aid to all spellcasters who prepare spells. Once per day on command, a pearl of power enables the possessor to recall any one spell that she had prepared and then cast that day. The spell is then prepared again, just as if it had not been cast. The spell must be of a particular level, depending on the pearl. Different pearls exist for recalling one spell per day of each level from 1st through 9th and for the recall of two spells per day (each of a different level, 6th or lower).</p>
<h3 id="magic-wondrous-pearl_of_power-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, creator must be able to cast spells of the spell level to be recalled; <strong>Cost</strong> 500 gp (1st), 2,000 gp (2nd), 4,500 gp (3rd), 8,000 gp (4th), 12,500 gp (5th), 18,000 gp (6th), 24,500 gp (7th), 32,000 gp (8th), 35,000 gp (Two Spells), 40,500 gp (9th)</p>
</>};
const _pearl_of_the_sirines = {title: "Pearl of the Sirines", jsx: <><h2 id="magic-wondrous-pearl_of_the_sirines-pearl-of-the-sirines">Pearl of the Sirines</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 315</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 525</Link><br/><strong>Aura</strong> moderate abjuration and transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> none; <strong>Price</strong> 15,300 gp; <strong>Weight</strong> -</p>
<p>This pearl is worth at least 1,000 gp for its beauty alone, yet if it is clasped firmly in hand or held to the breast while the possessor attempts actions related to the pearl's powers, she understands and is able to employ the item.</p>
<p>The pearl enables its possessor to breathe in water as if she were in clean, fresh air. Her swim speed is 60 feet, and she can cast spells and act underwater without hindrance.</p>
<h3 id="magic-wondrous-pearl_of_the_sirines-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/freedom_of_movement">freedom of movement</Link>, <Link to="/spell/water_breathing">water breathing</Link>; <strong>Cost</strong> 8,150 gp</p>
</>};
const _penetrating_whetstone = {title: "Penetrating Whetstone", jsx: <><h2 id="magic-wondrous-penetrating_whetstone-penetrating-whetstone">Penetrating Whetstone</h2>
<p><strong>Sources</strong> <Link to="/source/monster_hunters_handbook">Monster Hunter's Handbook pg. 29</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 8th<br/><strong>Slot</strong> none; <strong>Price</strong> 2,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This whetstone is made from finely worked <Link to="/eq-material/obsidian">obsidian</Link>. Sharpening a blade with this whetstone requires 15 minutes of work and grants the weapon the ability to ignore up to 3 points of natural armor for its next five attacks. If the target of the weapon's attack has a natural armor bonus of less than +3, the weapon deals 1 additional point of damage for each point of natural armor below 3 the target has. The process of honing the blade shatters a portion of the whetstone's enchanted obsidian, dispelling its magic and turning it into a mundane whetstone afterward.</p>
<h3 id="magic-wondrous-penetrating_whetstone-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/keen_edge">keen edge</Link>; <strong>Cost</strong> 1,000 gp</p>
</>};
const _pentacle_token = {title: "Pentacle Token", jsx: <><h2 id="magic-wondrous-pentacle_token-pentacle-token">Pentacle Token</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_108_hell_comes_to_westcrown">Pathfinder #108: Hell Comes to Westcrown pg. 22</Link><br/><strong>Aura</strong> strong conjuration; <strong>CL</strong> 13th<br/><strong>Slot</strong> none; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> 1/2 lb.</p>
<p>Roughly the size of a saucer, this thin ceramic disc is painted red and marked with an inverted pentagram, the unholy symbol of <Link to="/faith/asmodeus">Asmodeus</Link>. A pentacle token must first be attuned to a <Link to="/family/devil">devil</Link> by touching the token to a devil as a standard action. A single pentacle token can be attuned to one devil of CR 9 or higher, or up to five devils of CR 8 or lower. An individual devil can be attuned to only one pentacle token at a time. Attuning a pentacle token to additional devils beyond these limits replaces earlier attunements, starting with the earliest attunement.</p>
<p>An attuned pentacle token can be broken as a standard action, immediately alerting all devils attuned to that token of the owner's location and the distance and direction to it. If the devil has the <Link to="/spell/greater_teleport">greater teleport</Link> spell-like ability, it can use that ability as an immediate action to transport itself to a square adjacent to the broken pentacle token. Teleporting to the token's location in this way increases the devil's damage reduction by 5 (for example, from DR 10/good to DR 15/good) for 1 hour (if the devil does not already have damage reduction, it gains DR 5/good for 1 hour). The creature breaking a pentacle token has no control over or command of any devils attuned to that token. Once a pentacle token is broken, it loses its magic and cannot be used again.</p>
<h3 id="magic-wondrous-pentacle_token-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/refuge">refuge</Link>, creator must be a cleric of Asmodeus; <strong>Cost</strong> 3,750 gp</p>
</>};
const _perfect_tuning_fork = {title: "Perfect Tuning Fork", jsx: <><h2 id="magic-wondrous-perfect_tuning_fork-perfect-tuning-fork">Perfect Tuning Fork</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 267</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> none; <strong>Price</strong> 600 gp; <strong>Weight</strong> -</p>
<p><Link to="/faith/shelyn">Shelyn's</Link> association with harmony and music inspires many composers to pen glorious songs in the Eternal Rose's honor, and numerous tools have been devised by her church to improve the performances of such melodies. The perfect tuning fork provides the ideal pitch to quickly begin an inspirational tune. When holding a perfect tuning fork in the hand, the wielder can strike the fork as part of the action of beginning a <Link to="/ability/bardic_performance">bardic performance</Link>. If the wielder can start a bardic performance as a standard action, she can do so as a move action instead. If the wielder can start a bardic performance as a move action, she can do so as a swift action instead. A perfect tuning fork loses its magic after one use, but it can be used as an ordinary tuning fork thereafter.</p>
<h3 id="magic-wondrous-perfect_tuning_fork-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/haste">haste</Link>; <strong>Cost</strong> 300 gp</p>
</>};
const _perilous_puzzle_box = {title: "Perilous Puzzle Box", jsx: <><h2 id="magic-wondrous-perilous_puzzle_box-perilous-puzzle-box">Perilous Puzzle Box</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 222</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> none; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Brass latticework decorates the faces of this cubical mahogany puzzle box. While in its solved configuration, the puzzle box is safe to open and close, and the user can access an extradimensional compartment that can store up to 10 pounds of objects. The user can store a single touch spell of 4th level or lower in the box by casting the spell and touching the box. This spell has no effect until the box is changed to an unsolved state and someone subsequently tries and fails to solve it.</p>
<p>Any creature can close the box and twist its segments, at which point the puzzle box becomes unsolved and requires a successful DC 20 Intelligence check to solve and open. Each subsequent consecutive round spent randomly twisting the segments increases the number of Intelligence checks needed to solve the puzzle, to a maximum of three checks after 3 rounds of scrambling. As soon as the creature ceases twisting the segments, it is no longer safe to change the configuration. Thereafter, twisting any segment triggers a 1-minute timer, during which the holder can safely attempt to solve the puzzle with a series of Intelligence checks. This requires two hands and a full-round action for each Intelligence check. If the timer runs out before the puzzle is solved or the creature pauses for 1 round in the middle of attempting to solve the puzzle, the touch spell stored in the perilous puzzle box (if any) discharges, automatically hitting any creature holding the box.</p>
<p>Unless the attempt to solve the puzzle succeeds, after 1 minute, the box automatically reverts to the configuration it had before the attempt to solve the puzzle and locks itself for 24 hours. If a perilous puzzle box is destroyed (hardness 10, 20 hp), any contents stored in the extradimensional space are lost on the Ethereal Plane.</p>
<p>A found puzzle box has a 75% chance of having a touch spell stored within it, usually <Link to="/spell/bestow_curse">bestow curse</Link>, <Link to="/spell/contagion">contagion</Link>, or <Link to="/spell/inflict_critical_wounds">inflict critical wounds</Link>.</p>
<h3 id="magic-wondrous-perilous_puzzle_box-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/imbue_with_spell_ability">imbue with spell ability</Link>, <Link to="/spell/secret_chest">secret chest</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _phantasmal_gem = {title: "Phantasmal Gem", jsx: <><h2 id="magic-wondrous-phantasmal_gem-phantasmal-gem">Phantasmal Gem</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 38</Link><br/><strong>Aura</strong> faint illusion; <strong>CL</strong> 3rd<br/><strong>Slot</strong> none; <strong>Price</strong> 4,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This small cut crystal appears to be filled with hazy, indistinct images that constantly shift and vary. If a spellcaster holding the phantasmal gem casts an illusion spell with a duration of concentration (or concentration + a number of rounds), the illusion lasts up to an additional 10 rounds after the spellcaster ceases concentrating on it. The spellcaster may end the illusion early as a swift action. The phantasmal gem can be used multiple times in a day, but cannot grant more than a total of 10 additional rounds of illusion spells per day. A <Link to="/race/gnome">gnome</Link> using a phantasmal gem can recharge it by expending uses of spell-like abilities gained through the gnome magic racial trait. Each spell-like ability expended as a standard action recharges 1 round of duration to the phantasmal gem (up to a maximum of 10 rounds).</p>
<h3 id="magic-wondrous-phantasmal_gem-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, creator must be a gnome or a wizard specialized in the school of <Link to="/arcaneschool/illusion">illusion</Link>; <strong>Cost</strong> 2,000 gp</p>
</>};
const _philter_of_love = {title: "Philter of Love", jsx: <><h2 id="magic-wondrous-philter_of_love-philter-of-love">Philter of Love</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 315</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 308</Link><br/><strong>Aura</strong> strong enchantment; <strong>CL</strong> 15th<br/><strong>Slot</strong> none; <strong>Price</strong> 3,000 gp; <strong>Weight</strong> -</p>
<p>This potent preparation causes a creature who drinks it to fall madly in love with the first creature he or she perceives after consuming it. The drinker's <Link to="/skill/attitude">attitude</Link> toward that creature becomes helpful. If a romantic attraction is possible toward the first person viewed, the drinker falls in love with that person. Otherwise, the drinker's love is a platonic adoration. The effects of the philter are permanent unless removed by a <Link to="/spell/break_enchantment">break enchantment</Link>, <Link to="/spell/dispel_magic">dispel magic</Link>, <Link to="/spell/limited_wish">limited wish</Link>, <Link to="/spell/miracle">miracle</Link>, <Link to="/spell/remove_curse">remove curse</Link>, or <Link to="/spell/wish">wish</Link>.</p>
<h3 id="magic-wondrous-philter_of_love-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/charm_monster">charm monster</Link>, <Link to="/spell/permanency">permanency</Link>; <strong>Cost</strong> 1,500 gp</p>
</>};
const _phlogiston_vial = {title: "Phlogiston Vial", jsx: <><h2 id="magic-wondrous-phlogiston_vial-phlogiston-vial">Phlogiston Vial</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_elements">Blood of the Elements pg. 23</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 11th<br/><strong>Slot</strong> none; <strong>Price</strong> 3,300 gp; <strong>Weight</strong> -</p>
<p>This 1-inch-long, clear glass vial is filled with a dark, amber-colored fluid that resembles the twisting, flickering form of a <Link to="/monster/fire_elemental">fire elemental</Link>. The vial is sealed with a brass cap and attached to a lightweight gold chain. When the chain is wrapped around a divine caster's holy symbol, the saving throw DC of the next <em>banishment</em> or <Link to="/spell/dismissal">dismissal</Link> spell he casts on an outsider with the fire subtype is increased by 4, and additionally, the caster gains a +2 alchemical bonus on the caster level check to overcome the creature's spell resistance against the spell. If the spell is successful, the outsider leaves behind a small pile of magical ashes and the phlogiston vial cannot be used to banish outsiders again until the oil inside is replaced as a standard action (see below).</p>
<p>If the ashes are collected and placed inside the vial, and the vial is used as an additional material component for a <em>planar ally</em> spell, the spell conjures the exact same outsider, provided the creature is a viable target of that spell. The owner of the vial receives a +4 bonus on her Charisma check to negotiate with the creature. The ashes are consumed after an agreement with the creature is made.</p>
<p>A phlogiston vial is a single-use item that can be recharged with a rare alchemical agent called phlogiston oil, which can only be found on the Plane of Fire and costs 2,000 gp when sold on the open market. The listed price is for a phlogiston vial full of phlogiston oil.</p>
<h3 id="magic-wondrous-phlogiston_vial-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/banishment">banishment</Link>, <Link to="/spell/planar_ally">planar ally</Link>; <strong>Cost</strong> 1,650 gp</p>
</>};
const _phoenix_feather = {title: "Phoenix Feather", jsx: <><h2 id="magic-wondrous-phoenix_feather-phoenix-feather">Phoenix Feather</h2>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook pg. 30</Link><br/><strong>Aura</strong> moderate conjuration and necromancy; <strong>CL</strong> 9th<br/><strong>Slot</strong> none; <strong>Price</strong> 4,500 gp; <strong>Weight</strong> -</p>
<p>This vibrant red feather is surrounded by a faint, soothing golden glow that makes it appear preternaturally shiny and pristine. As an immediate action, the user can activate the phoenix feather to attempt a saving throw against a spell or effect with the death descriptor, even if the spell or effect does not normally allow a saving throw. If the spell or effect normally allows a saving throw for reduced damage or a partial effect, the bearer suffers only the reduced damage or partial effect on a failed saving throw, and completely negates all damage and effects on a successful saving throw. If the spell or effect does not normally allow a saving throw, calculate the DC of the saving throw this item provides as if it did.</p>
<p>Alternatively, when a single attack, spell, or effect deals hit point damage to the user that would reduce her to negative hit points, after the hit point damage is rolled but before it is applied to her, she can activate the phoenix feather as a free action. If she does, she reduces the amount of hit point damage she takes by up to 5d8 + 9 points. (She can never reduce the amount of damage taken to less than 0.) A phoenix feather is usable once, after which it immediately burns away in a fiery flash before being reduced to ash.</p>
<h3 id="magic-wondrous-phoenix_feather-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/breath_of_life">breath of life</Link>, <Link to="/spell/death_ward">death ward</Link>, creator must be good; <strong>Cost</strong> 2,250 gp</p>
</>};
const _pipe_of_revealing_mists = {title: "Pipe of Revealing Mists", jsx: <><h2 id="magic-wondrous-pipe_of_revealing_mists-pipe-of-revealing-mists">Pipe of Revealing Mists</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 249</Link><br/><strong>Aura</strong> faint evocation; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 2,592 gp; <strong>Weight</strong> 1/2 lb.</p>
<p>A pair of angry, squinting eyes is carved into the bowl of this wooden smoking pipe. The pipe defies any attempts to light it; even when it's unlit, pale wafts of smoke constantly crawl out from the pipe's bowl, despite being unlit. Three times per day as a standard action, the user can inhale the smoke and blow it out in a 30-foot cone. While most of the smoke quickly dissipates, a thin layer of it clings to any corporeal invisible creatures caught in the cone. The creatures are revealed as blurred shapes, rather than being invisible, but attacks against them still suffer a 20% miss chance. This effect lasts for 6 rounds.</p>
<h3 id="magic-wondrous-pipe_of_revealing_mists-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/invisibility_purge">invisibility purge</Link>, <Link to="/spell/obscuring_mist">obscuring mist</Link>; <strong>Cost</strong> 1,296 gp</p>
</>};
const _pipes_of_dissolution = {title: "Pipes of Dissolution", jsx: <><h2 id="magic-wondrous-pipes_of_dissolution-pipes-of-dissolution">Pipes of Dissolution</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 315</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 12,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>Carvings of winter scenes decorate this set of pan pipes. Activating the pipes requires a DC 15 <Link to="/skill/perform">Perform (wind)</Link> check. Creatures within 30 feet gain a +2 competence bonus on caster level checks to <em>dispel</em> magical effects and overcome spell resistance. Maintaining the performance is challenging, requiring a move action and a new Perform check each round, with the DC increasing by +1 for each round the instrument is played. The magic ends when the player voluntarily stops or fails the Perform check, after which the pipes cannot be used again for 1 hour.</p>
<h3 id="magic-wondrous-pipes_of_dissolution-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/dispel_magic">dispel magic</Link>; <strong>Cost</strong> 6,000 gp</p>
</>};
const _pipes_of_haunting = {title: "Pipes of Haunting", jsx: <><h2 id="magic-wondrous-pipes_of_haunting-pipes-of-haunting">Pipes of Haunting</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 315</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 526</Link><br/><strong>Aura</strong> faint necromancy; <strong>CL</strong> 4th<br/><strong>Slot</strong> none; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This magic item appears to be a small set of pan pipes. When played by a person who succeeds on a DC 15 <Link to="/skill/perform">Perform (wind)</Link> check, the pipes create an eerie, spellbinding tune. Those within 30 feet who hear the tune must succeed at a DC 13 Will save or become <Link to="/misc/frightened">frightened</Link> for 4 rounds. Creatures with 6 or more Hit Dice are unaffected. Pipes of haunting can be sounded twice a day.</p>
<h3 id="magic-wondrous-pipes_of_haunting-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/scare">scare</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _pipes_of_pain = {title: "Pipes of Pain", jsx: <><h2 id="magic-wondrous-pipes_of_pain-pipes-of-pain">Pipes of Pain</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 315</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 6th<br/><strong>Slot</strong> none; <strong>Price</strong> 12,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>By making a DC 15 <Link to="/skill/perform">Perform (wind)</Link> check, the bearer can use these pipes to create a wondrous melody which <Link to="/misc/fascinate">fascinates</Link> creatures within 30 feet for as long as the bearer continues to play (Will DC 14 negates). This is a mind-affecting sonic compulsion effect. The bearer is immune to the sound of the pipes. When the bearer stops playing, for the next 2d4 rounds all creatures who were fascinated by the music are stricken by intense pain at even the slightest noise. Unless a creature is in a totally silent area, it takes 1d4 points of damage per round on its turn, and it has sonic vulnerability until this time expires. Thereafter, the creature is <Link to="/misc/shaken">shaken</Link> unless it is in a totally silent area; this hypersensitivity to noise is a curse effect.</p>
<h3 id="magic-wondrous-pipes_of_pain-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/sound_burst">sound burst</Link>, creator must have the <Link to="/ability/bardic_performance">bardic performance</Link> class ability; <strong>Cost</strong> 6,000 gp</p>
</>};
const _pipes_of_shifting_tempo = {title: "Pipes of Shifting Tempo", jsx: <><h2 id="magic-wondrous-pipes_of_shifting_tempo-pipes-of-shifting-tempo">Pipes of Shifting Tempo</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_society_field_guide">Pathfinder Society Field Guide pg. 53</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 18,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>In outer construction and manner of play, pipes of shifting tempo resemble a typical set of unremarkable pan pipes, but the complex chambers within the pipes are modeled after difficult-to-duplicate Azlanti instruments. Music created by these pipes sounds unusually mournful, with a strange, almost warbling subtext to the notes. Up to three times per day, a user can attempt to harness these pipes' power by making a DC 15 <Link to="/skill/perform">Perform (wind)</Link> check as a standard action. With a successful check, the possessor can play a grave melody to cast <em>slow</em> or an allegro melody to cast <em>haste.</em> The resulting spell functions as normal for the item's caster level, affecting five creatures per casting.</p>
<h3 id="magic-wondrous-pipes_of_shifting_tempo-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/haste">haste</Link>, <Link to="/spell/slow">slow</Link>, Perform (wind) 5 ranks; <strong>Cost</strong> 9,000 gp</p>
</>};
const _pipes_of_sounding = {title: "Pipes of Sounding", jsx: <><h2 id="magic-wondrous-pipes_of_sounding-pipes-of-sounding">Pipes of Sounding</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 315</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 526</Link><br/><strong>Aura</strong> faint illusion; <strong>CL</strong> 2nd<br/><strong>Slot</strong> none; <strong>Price</strong> 1,800 gp; <strong>Weight</strong> 3 lbs.</p>
<p>When played by a character who has the <Link to="/skill/perform">Perform (wind)</Link> skill, these shiny metallic pan pipes create a variety of sounds that can imitate creatures, environmental sounds, or most other sounds. The figment sounds are the equivalent of <em>ghost sound.</em></p>
<h3 id="magic-wondrous-pipes_of_sounding-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/ghost_sound">ghost sound</Link>; <strong>Cost</strong> 900 gp</p>
</>};
const _pipes_of_the_sewers = {title: "Pipes of the Sewers", jsx: <><h2 id="magic-wondrous-pipes_of_the_sewers-pipes-of-the-sewers">Pipes of the Sewers</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 316</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 526</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 2nd<br/><strong>Slot</strong> none; <strong>Price</strong> 1,150 gp; <strong>Weight</strong> 3 lbs.</p>
<p>If the possessor learns the proper tune, he can use these pipes to attract 1d3 <Link to="/monster/rat_swarm">rat swarms</Link> if any rats are within 400 feet. For each 50-foot distance the rats have to travel, there is a 1-round delay. The piper must continue playing until the rats appear, and when they do so, the piper must make a DC 10 <Link to="/skill/perform">Perform (wind)</Link> check. Success means that they obey the piper's telepathic commands so long as he continues to play. Failure indicates that they turn on the piper. If for any reason the piper ceases playing, the rats leave immediately. The Perform DC increases by +5 for each time the rats have been successfully called in a 24-hour period.</p>
<p>If the rats are under the control of another creature, add the HD of the controller to the Perform check DC. Once control is assumed, another check is required each round to maintain it if the other creature is actively seeking to reassert its control.</p>
<h3 id="magic-wondrous-pipes_of_the_sewers-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/charm_animal">charm animal</Link>, <Link to="/spell/summon_natures_ally_i">summon nature's ally I</Link>, <Link to="/ability/wild_empathy">wild empathy</Link> ability; <strong>Cost</strong> 575 gp</p>
</>};
const _pipes_of_the_warren_guardian = {title: "Pipes of the Warren Guardian", jsx: <><h2 id="magic-wondrous-pipes_of_the_warren_guardian-pipes-of-the-warren-guardian">Pipes of the Warren Guardian</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 155</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> -</p>
<p>These finely crafted yellow-ivory pipes are bound in bronze and decorated with bits of amber. If the possessor learns the proper tune, once per day he can use these pipes to summon 1d4+1 <Link to="/monster/dire_rat">dire rats</Link> as if using <em>summon monster III.</em> The summoned dire rats also have the swarming racial trait, and count as <Link to="/race/ratfolk">ratfolk</Link> for the purposes of the ratfolk's swarming racial trait.</p>
<h3 id="magic-wondrous-pipes_of_the_warren_guardian-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/summon_monster_iii">summon monster III</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _planar_carriage = {title: "Planar Carriage", jsx: <><h2 id="magic-wondrous-planar_carriage-planar-carriage">Planar Carriage</h2>
<p><strong>Sources</strong> <Link to="/source/plane_hoppers_handbook">Plane-Hopper's Handbook pg. 11</Link><br/><strong>Aura</strong> moderate conjuration and transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> none; <strong>Price</strong> 121,500 gp; <strong>Weight</strong> 1,500 lbs.</p>
<p>Planar carriages are large metal-and-wood vehicles painted or styled to reflect the appearance of a certain plane. When not being used to travel to another plane, a planar carriage functions as a <Link to="/rule/vehicle_heavy_wagon">heavy wagon</Link>, except for the following changes: instead of muscle propulsion, a planar carriage has built-in magic propulsion that requires a driver to use <Link to="/skill/spellcraft">Spellcraft</Link> or <Link to="/skill/use_magic_device">Use Magic Device</Link> for driving checks. A planar carriage has a maximum speed of 90 feet and an acceleration of 30 feet. Its driving device is a magic item (a 5-foot magical sphere) that occupies the forwardmost square, and its driving space consists of the squares adjacent to the device.</p>
<p>Once per day, the driver of a planar carriage can attempt to transport the carriage and its occupants to a plane of her choosing other than the plane that the carriage is currently on. For the driver to do so, the vehicle must be moving at its maximum speed. While the carriage is moving at maximum speed, the driver can attempt a DC 20 Spellcraft or Use Magic Device check to open a gate in front of the planar carriage to the chosen plane, as per the <em>gate</em> spell, and drive the carriage into the gate. If the driver designates a specific arrival point on the target plane, the carriage arrives at that exact location; otherwise, the carriage appears in a random location on the plane appropriate for the carriage's size.</p>
<p>When the carriage arrives on another plane, it grants its occupants the benefits of <em>planar adaptation</em> for that plane as long as the occupants remain within the carriage; the carriage itself also gains those benefits. A planar carriage can grant the benefits of <em>planar adaptation</em> for only one plane at a time, so when the carriage moves to a different plane, the benefits from <em>planar adaptation</em> change accordingly. Occupants who are native to the plane the planar carriage is on do not gain any benefits from <em>planar adaptation.</em></p>
<h3 id="magic-wondrous-planar_carriage-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/gate">gate</Link>, <Link to="/spell/haste">haste</Link>, <Link to="/spell/planar_adaptation">planar adaptation</Link>, creator must have at least 5 ranks in <Link to="/skill/knowledge_engineering">Knowledge (engineering)</Link>; <strong>Cost</strong> 60,850 gp</p>
</>};
const _planar_guide = {title: "Planar Guide", jsx: <><h2 id="magic-wondrous-planar_guide-planar-guide">Planar Guide</h2>
<p><strong>Sources</strong> <Link to="/source/the_first_world_realm_of_the_fey">The First World, Realm of the Fey pg. 13</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 3rd<br/><strong>Slot</strong> none; <strong>Price</strong> 5,400 gp; <strong>Weight</strong> 1/2 lb.</p>
<p>This small brass device is shaped like a compass or clock, and is designed for travel on planes without magnetic poles or set geography. When activated via a mechanical trigger, its geared arms rotate around to point toward the stronghold of either the plane's ruler or the three closest approximations, as per <em>planar orientation,</em> with the name or holy symbol of the entity in question appearing on the arm. In addition, pressing a lever on the back side can cause the device to switch over to a portal-finding function that acts as per <em>locate portal,</em> with a range of 3 miles.</p>
<p>Planar guides are notoriously tricky to make, and most have a 5% chance each time they're consulted of having their magic twisted to lead the user astray, usually pointing toward a hazard (such as the lair of a dangerous creature). This chance is cumulative each time the guide is consulted, but resets to 5% as soon as the user encounters such a hazard. Planar guides without this flaw are rare and can easily cost twice as much as the standard model. At the same time, those with a higher percentage can be significantly cheaper, and are sometimes even given away freely to Material Plane travelers by locals - these last generally direct the user to a specific hazard known by the giver.</p>
<h3 id="magic-wondrous-planar_guide-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/locate_portal">locate portal</Link>, <Link to="/spell/planar_orientation">planar orientation</Link>; <strong>Cost</strong> 2,700 gp</p>
</>};
const _planar_keystone = {title: "Planar Keystone", jsx: <><h2 id="magic-wondrous-planar_keystone-planar-keystone">Planar Keystone</h2>
<p><strong>Sources</strong> <Link to="/source/planar_adventures">Planar Adventures pg. 54</Link><br/><strong>Aura</strong> strong conjuration; <strong>CL</strong> 17th<br/><strong>Slot</strong> none; <strong>Price</strong> 16,200 gp; <strong>Weight</strong> 2 lbs.</p>
<p>A planar keystone is a small cube etched with runes. Each planar keystone is attuned to a specific site on a particular plane - this site must be determined when the planar keystone is created and cannot be changed at a later date. Anyone examining the etched patterns can determine the plane and location with a successful DC 20 <Link to="/skill/knowledge_planes">Knowledge (planes)</Link> check. Once per day, up to eight intelligent creatures within 20 feet of the planar keystone can concentrate upon its etched patterns for 1 minute. This concentration is tenuous; if any of the creatures are attacked or pause to take other actions during this time, the concentration of all participants is broken and the planar keystone's use for that day is lost. At the end of this time, all creatures concentrating on the planar keystone are transported to the planar keystone's site as if via <Link to="/spell/plane_shift">plane shift</Link>, but arriving precisely on target. The planar keystone travels with the creatures - it is not left behind in the process.</p>
<h3 id="magic-wondrous-planar_keystone-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/gate">gate</Link>; <strong>Cost</strong> 8,100 gp</p>
</>};
const _planar_parchment = {title: "Planar Parchment", jsx: <><h2 id="magic-wondrous-planar_parchment-planar-parchment">Planar Parchment</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 250</Link><br/><strong>Aura</strong> moderate conjuration and evocation; <strong>CL</strong> 11th<br/><strong>Slot</strong> none; <strong>Price</strong> 18,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Resembling ordinary paper, planar parchment is used when negotiating with outsiders via spells like <Link to="/spell/planar_ally">planar ally</Link> or <em>planar binding.</em> Using the parchment as part of negotiations grants the user a +2 bonus on her Charisma check to coerce the called outsider if such a check is required.</p>
<p>Planar parchment offers some autonomy to outsiders called for longer missions via <em>planar ally.</em> The use of planar parchment increases the time for a planar ally from 1 day per caster level to 1 week per caster level for long-term tasks (without increasing the cost of the payment the outsider requires). An outsider that has its term of service increased in this way isn't bound to the plane to which it was called. After negotiations are complete, it can return to its home plane, but is still required to perform the services it agreed to complete.</p>
<p>Regardless of whether the outsider was called via <em>planar ally</em> or <em>planar binding</em> magic, the outsider maintains a connection with the planar parchment for the duration of its service. Any writings added to the parchment are instantly transmitted to the bound outsider, as a <em>sending</em> spell (with no chance of failure if the outsider is on another plane). These words disappear from the parchment 1 hour after being inscribed.</p>
<p>Finally, once an outsider is bound to service with a planar parchment, the parchment is inscribed with script visible only to the creature completing the negotiation, or via <Link to="/spell/true_seeing">true seeing</Link>. Reading this script is a full-round action, akin to reading a scroll. Reading this aloud immediately summons the bound outsider to the location of the scroll.</p>
<p>A planar parchment can be used for only one negotiation, and then turns into a nonmagical piece of parchment.</p>
<h3 id="magic-wondrous-planar_parchment-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/planar_binding">planar binding</Link>, <Link to="/spell/sending">sending</Link>; <strong>Cost</strong> 9,000 gp</p>
</>};
const _planar_strap = {title: "Planar Strap", jsx: <><h2 id="magic-wondrous-planar_strap-planar-strap">Planar Strap</h2>
<p><strong>Sources</strong> <Link to="/source/planar_adventures">Planar Adventures pg. 55</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> none; <strong>Price</strong> 500 gp; <strong>Weight</strong> -</p>
<p>When this worn leather strap is tied around the grip of a weapon, the weapon becomes immune to the harmful environmental effects of a plane, such as heat or acidity. This does not protect the weapon against non-environmental energy effects; although it would apply to the ambient fire damage caused by being on the Plane of Fire, it would not apply to damage caused by a <Link to="/spell/fireball">fireball</Link> spell. If the weapon is destroyed, the planar strap is destroyed with it. It is a full-round action to tie or untie a strap. You can only have one planar strap applied to a weapon at a time.</p>
<h3 id="magic-wondrous-planar_strap-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/planar_adaptation">planar adaptation</Link>; <strong>Cost</strong> 250 gp</p>
</>};
const _platter_of_exquisite_feasting = {title: "Platter of Exquisite Feasting", jsx: <><h2 id="magic-wondrous-platter_of_exquisite_feasting-platter-of-exquisite-feasting">Platter of Exquisite Feasting</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_intrigue">Inner Sea Intrigue pg. 55</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 1st<br/><strong>Slot</strong> none; <strong>Price</strong> 250 gp; <strong>Weight</strong> 1 lb.</p>
<p>This silver, oval-shaped platter can hold up to 1 cubic foot worth of food. Once per day, the platter's user can activate the item to transform its contents into another type or quality of food of the user's choosing. The transformed food looks and smells just like actual food of its new type, but retains its original texture, taste, nourishment, and level of fulfillment. Spoiled or poisoned food remains so and is detectable as such under magical or supernatural scrutiny.</p>
<h3 id="magic-wondrous-platter_of_exquisite_feasting-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/purify_food_and_drink">purify food and drink</Link>; <strong>Cost</strong> 125 gp</p>
</>};
const _players_prize = {title: "Player's Prize", jsx: <><h2 id="magic-wondrous-players_prize-players-prize">Player's Prize</h2>
<p><strong>Sources</strong> <Link to="/source/people_of_the_river">People of the River pg. 28</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 3,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This tiny copper statue of a featureless, dancing humanoid is sometimes awarded to the winners of contests at Pitax's Academy of Grand Arts. The power of a player's prize comes not from possessing it, however, but from giving it to an unsuspecting audience member. By inscribing a personal rune on his player's prize, a bard can cause whoever carries the item (knowingly or not) to be more susceptible to his <Link to="/ability/bardic_performance">bardic performances</Link>. Once inscribed, a player's prize can not be keyed to any other creature. Devious bards use <Link to="/skill/sleight_of_hand">Sleight of Hand</Link> to drop their player's prize on rivals' or foes' persons, usually in a backpack or in among other gear where it would be difficult to locate.</p>
<p>A creature carrying a player's prize keyed to a bard within 30 feet takes a -2 penalty on Will saves against that bard's bardic performances, as well as a -2 penalty on opposed skill checks against any skill checks the bard attempts using his versatile performance class feature. These penalties remain as long as the affected creature continues to carry the player's prize.</p>
<p>Once per day as an immediate action, the character whose personal rune is inscribed on the player's prize can speak the item's command word to cause the statue to instantly appear in his hand. The character must be within 30 feet of the player's prize to activate this ability.</p>
<h3 id="magic-wondrous-players_prize-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bestow_curse">bestow curse</Link>, <Link to="/spell/telekinesis">telekinesis</Link>; <strong>Cost</strong> 1,500 gp</p>
</>};
const _pliability_elixir = {title: "Pliability Elixir", jsx: <><h2 id="magic-wondrous-pliability_elixir-pliability-elixir">Pliability Elixir</h2>
<p><strong>Sources</strong> <Link to="/source/villain_codex">Villain Codex pg. 45</Link><br/><strong>Aura</strong> faint enchantment; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 500 gp; <strong>Weight</strong> -</p>
<p>A creature that drinks this elixir becomes particularly pliable mentally and emotionally for 10 minutes (Will DC 16 negates). <Link to="/skill/bluff">Bluff</Link>, <Link to="/skill/diplomacy">Diplomacy</Link>, and <Link to="/skill/intimidate">Intimidate</Link> checks automatically succeed against a pliable creature, except for Diplomacy checks to improve a pliable creature's attitude, which have the normal DC. This does not allow characters to whom the pliable creature is unfriendly or hostile to make requests of the pliable creature using Diplomacy. After 1 minute, the effects of pliability elixir are noticeable with a successful DC 25 <Link to="/skill/sense_motive">Sense Motive</Link> check. The GM can apply circumstance bonuses to this check based on factors that make the effect more obvious, such as if the affected creature contradicts itself or agrees to something that doesn't make sense. A vial of pliability elixir appears to be an <Link to="/magic-wondrous/elixir_of_truth">elixir of truth</Link> unless the check made to identify it succeeds by 10 or more.</p>
<h3 id="magic-wondrous-pliability_elixir-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/charm_person">charm person</Link>, <Link to="/spell/zone_of_truth">zone of truth</Link>; <strong>Cost</strong> 250 gp</p>
</>};
const _pocket_prey = {title: "Pocket Prey", jsx: <><h2 id="magic-wondrous-pocket_prey-pocket-prey">Pocket Prey</h2>
<p><strong>Sources</strong> <Link to="/source/monster_hunters_handbook">Monster Hunter's Handbook pg. 29</Link><br/><strong>Aura</strong> moderate illusion; <strong>CL</strong> 10th<br/><strong>Slot</strong> none; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This small container features a stone base with a glass cover. The container can hold half a pound of flesh or similar organic matter, preserving it for up to 24 hours. On command, the container emanates the smell of the contained material out to a 100-foot radius. Additionally, the container lets out a cry every minute, imitating that of an injured member of the variety of the flesh within the container. This cry can be clearly heard up to 150 feet from the container.</p>
<h3 id="magic-wondrous-pocket_prey-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/gentle_repose">gentle repose</Link>, <Link to="/spell/major_image">major image</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _poison_gum = {title: "Poison Gum", jsx: <><h2 id="magic-wondrous-poison_gum-poison-gum">Poison Gum</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 267</Link><br/><strong>Aura</strong> faint necromancy; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 1,250 gp; <strong>Weight</strong> -</p>
<p>Poison gum is often used by agents of <Link to="/faith/norgorber">Norgorber</Link>, particularly those alchemists and poisoners who venerate the insidious god as Blackfingers. Chewing a piece of poison gum - which resembles nothing so much as a lump of congealed sap - is a move action that provokes attacks of opportunity, though the user can continue to chew the gum as a free action on consecutive rounds. Doing so fills the user's mouth with three doses of <Link to="/eq-poison/medium_spider_venom">Medium spider venom</Link>. This poison lasts for up to 5 minutes before losing its potency. As a swift action while chewing poison gum, the user can apply the poison to a wielded weapon. If the user lacks the <Link to="/ability/poison_use">poison use</Link> class feature, there is a 5% chance that he exposes herself to the poison while chewing the gum or applying the poison to a weapon, and if he rolls a natural 1 on an attack roll with a poisoned weapon, he also exposes himself to the poison.</p>
<h3 id="magic-wondrous-poison_gum-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/poison">poison</Link>, creator must have the poison use class feature; <strong>Cost</strong> 1,000 gp</p>
</>};
const _poison_popcushion = {title: "Poison Popcushion", jsx: <><h2 id="magic-wondrous-poison_popcushion-poison-popcushion">Poison Popcushion</h2>
<p><strong>Sources</strong> <Link to="/source/magical_marketplace">Magical Marketplace pg. 13</Link><br/><strong>Aura</strong> faint conjuration (creation); <strong>CL</strong> 3rd<br/><strong>Slot</strong> none; <strong>Price</strong> 700 gp; <strong>Weight</strong> 2 lbs.</p>
<p>This squishy, gel-filled sack is the size of a fist, and its exterior is covered with countless tiny metal studs. When set on the ground or somewhere else within line of sight, a poison popcushion can be targeted with a melee or ranged attack (hardness 0, AC 7). A successful attack causes the poison popcushion to explode, sending a spray of needles everywhere within a 10-foot-radius <Link to="/misc/burst">burst</Link> and dealing 1d4+1 points of piercing damage to creatures caught in the area each round for 1d3 rounds. A successful DC 13 Reflex save halves this damage. Additionally, a poison popcushion can be loaded with an injury poison before it is placed. Fully loading a poison popcushion takes 3 doses of poison (not included in the price). In addition to dealing damage, a loaded poison popcushion affects struck creatures with the poison stored within, though the Fortitude save DC to save against this poison is 4 lower than the poison's usual DC.</p>
<h3 id="magic-wondrous-poison_popcushion-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/arrow_eruption">arrow eruption</Link>; <strong>Cost</strong> 350 gp</p>
</>};
const _poison_vial_of_distance = {title: "Poison Vial of Distance", jsx: <><h2 id="magic-wondrous-poison_vial_of_distance-poison-vial-of-distance">Poison Vial of Distance</h2>
<p><strong>Sources</strong> <Link to="/source/magical_marketplace">Magical Marketplace pg. 25</Link><br/><strong>Aura</strong> faint necromancy; <strong>CL</strong> 3rd<br/><strong>Slot</strong> none; <strong>Price</strong> 3,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Favored by assassins, this magical vial allows the application of poisons at a range of up to 30 feet. The poison must be supplied, and must be a contact or ingested poison. The user adds the poison to the vial and then shakes it in the direction of the item or creature she wishes to affect, making a ranged touch attack (a poison vial of distance provides a +4 circumstance bonus on this roll). If the attack is successful, the poison is successfully delivered to the object or creature intended.</p>
<h3 id="magic-wondrous-poison_vial_of_distance-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/mage_hand">mage hand</Link>; <strong>Cost</strong> 1,500 gp</p>
</>};
const _polish_of_inconspicuous_armor = {title: "Polish of Inconspicuous Armor", jsx: <><h2 id="magic-wondrous-polish_of_inconspicuous_armor-polish-of-inconspicuous-armor">Polish of Inconspicuous Armor</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 250</Link>, <Link to="/source/pathfinder_society_primer">Pathfinder Society Primer pg. 25</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 750 gp; <strong>Weight</strong> 1/2 lb.</p>
<p>This pungent, tar-black armor polish comes in a small, circular tin. The 1 dose contained in the tin is enough to apply to a single Medium suit of armor or two Small suits of armor. Applying the polish takes 10 minutes, during which time the user must visualize an alternative appearance for the armor to take on, such as a normal set of clothes or another set of armor. After the polish is applied, its noxious scent dissipates and the armor appears the way the user visualized, as the <Link to="/magic-enh/glamered">glamered</Link> magic armor special ability. The armor maintains all properties other than its physical appearance, including weight, armor check penalty, and maximum Dexterity bonus. This effect remains for 24 hours before wearing off.</p>
<h3 id="magic-wondrous-polish_of_inconspicuous_armor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/disguise_self">disguise self</Link>; <strong>Cost</strong> 375 gp</p>
</>};
const _poltergeist_knot = {title: "Poltergeist Knot", jsx: <><h2 id="magic-wondrous-poltergeist_knot-poltergeist-knot">Poltergeist Knot</h2>
<p><strong>Sources</strong> <Link to="/source/daughters_of_fury">Daughters of Fury pg. 62</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> none; <strong>Price</strong> 650 gp; <strong>Weight</strong> 1/2 lb.</p>
<p>This hopelessly knotted ball of golden twine defies any efforts to untangle it, forming new snarls out of nowhere just when it appears to be nearly unraveled.</p>
<p>On command, the twine unrolls and snakes out through the air toward a target within 50 feet. Unless the target succeeds at a DC 13 Reflex save to avoid the poltergeist knot, at the twine's touch, the bindings of any containers the target is carrying (packs, pouches, sheaths, quivers, and so on) come undone and all their contents are swept up in a whirlwind, performing a madcap dance around the target's head.</p>
<p>Anyone can grab an item as it spins by succeeding at a <Link to="/rule/steal">steal</Link> combat maneuver against a CMD of 12. In addition, the spinning objects obstruct the target's sight; other creatures gain <Link to="/rule/concealment">concealment</Link> against attacks made by the target. The equipment moves with the victim, whirling around her head for 3 rounds before falling to the ground.</p>
<p>A poltergeist knot affects laces and buckles only on exterior containers - bottles in a pouch or a bag of <Link to="/eq-misc/caltrops">caltrops</Link> in a backpack, for example, are swept into the whirlwind but don't spill their contents. The poltergeist knot works on inanimate objects, but can't open locks. A creature who isn't carrying a significant amount of gear may be immune to the poltergeist knot's effect, at the GM's discretion.</p>
<p>Once used, the knot loses its magic and becomes 50 feet of tangled, mundane twine.</p>
<h3 id="magic-wondrous-poltergeist_knot-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/open_close">open/close</Link>, <Link to="/spell/pilfering_hand">pilfering hand</Link>; <strong>Cost</strong> 325 gp</p>
</>};
const _polychrome_cover = {title: "Polychrome Cover", jsx: <><h2 id="magic-wondrous-polychrome_cover-polychrome-cover">Polychrome Cover</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_darklands">Heroes of the Darklands pg. 16</Link><br/><strong>Aura</strong> moderate illusion; <strong>CL</strong> 7th<br/><strong>Slot</strong> none; <strong>Price</strong> 2,000 gp; <strong>Weight</strong> 4 lbs.</p>
<p>This multicolored tarp is made from intricately woven cloth that gives its exterior the texture of stonework. It covers a 10-foot by 10-foot area and can be placed vertically, magically supporting its own weight. A polychrome cover magically takes on the same coloration of nearby stone, imitating any terrain it's in contact with. The coloration of the cover is an illusion effect that can be disbelieved (Will DC 16). Those who successfully disbelieve the effect instead see the cover's true coloration.</p>
<p>When a polychrome cover is crafted, the maker designates any number of creatures present at its creation to be immune to the cover's illusory effect. The crafter can instead exclude a specific race from the item's illusion. Most polychrome covers are set to exclude <Link to="/monster/svirfneblin">svirfneblin</Link>.</p>
<h3 id="magic-wondrous-polychrome_cover-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/hallucinatory_terrain">hallucinatory terrain</Link>; <strong>Cost</strong> 1,000 gp</p>
</>};
const _polymorphic_pouch = {title: "Polymorphic Pouch", jsx: <><h2 id="magic-wondrous-polymorphic_pouch-polymorphic-pouch">Polymorphic Pouch</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 316</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> none; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This leather pouch is usually decorated with a druidic motif. Within is an extradimensional space that can hold 4 cubic feet or 40 pounds worth of items and otherwise functions as a small <Link to="/magic-wondrous/bag_of_holding">bag of holding</Link>. If the bearer uses a polymorph effect or wild shape to transform into an animal, dragon, elemental, magical beast, plant, or vermin, the pouch never merges with her body. It automatically relocates to an easily-accessible place on her body (such as on a belt or a cord around her neck), allowing her to access the pouch and items within it while she is transformed.</p>
<h3 id="magic-wondrous-polymorphic_pouch-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/polymorph">polymorph</Link>, <Link to="/spell/secret_chest">secret chest</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _portable_hole = {title: "Portable Hole", jsx: <><h2 id="magic-wondrous-portable_hole-portable-hole">Portable Hole</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 316</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 526</Link><br/><strong>Aura</strong> strong conjuration; <strong>CL</strong> 12th<br/><strong>Slot</strong> none; <strong>Price</strong> 20,000 gp; <strong>Weight</strong> -</p>
<p>A portable hole is a circle of cloth spun from the webs of a <Link to="/monster/phase_spider">phase spider</Link> interwoven with strands of ether and beams of starlight, resulting in a portable extradimensional space. When opened fully, a portable hole is 6 feet in diameter, but it can be folded up to be as small as a pocket handkerchief. When spread upon any surface, it causes an extradimensional space 10 feet deep to come into being. This hole can be picked up from inside or out by simply taking hold of the edges of the cloth and folding it up. Either way, the entrance disappears, but anything inside the hole remains, traveling with the item.</p>
<p>The only air in the hole is that which enters when the hole is opened. It contains enough air to supply one Medium creature or two Small creatures for 10 minutes. The cloth does not accumulate weight even if its hole is filled. Each portable hole opens on its own particular non-dimensional space. If a <Link to="/magic-wondrous/bag_of_holding">bag of holding</Link> is placed within a portable hole, a rift to the Astral Plane is torn in that place. Both the bag and the cloth are sucked into the void and forever lost. If a portable hole is placed within a bag of holding, it opens a gate to the Astral Plane. The hole, the bag, and any creatures within a 10-foot radius are drawn there, the portable hole and bag of holding being destroyed in the process.</p>
<h3 id="magic-wondrous-portable_hole-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/plane_shift">plane shift</Link>; <strong>Cost</strong> 10,000 gp</p>
</>};
const _portable_pit_blunt_pit = {title: "Portable Pit (Blunt pit)", jsx: <><h2 id="magic-wondrous-portable_pit_blunt_pit-portable-pit">Portable Pit</h2>
<p><strong>Sources</strong> <Link to="/source/black_markets">Black Markets pg. 21</Link><br/><strong>Aura</strong> varies; <strong>CL</strong> varies<br/><strong>Slot</strong> none; <strong>Price</strong> 2,890 gp (Blunt pit), 5,410 gp (Spiked pit), 10,090 gp (Acid pit), 14,410 gp (Persistent pit), 16,210 gp (Hungry pit); <strong>Weight</strong> 1 lb.</p>
<p>This rolled cloth resembles a rug or sheet. If the cloth is unfurled on a flat horizontal surface and its command word spoken as a standard action, its 10-foot-by-10-foot surface changes to match the coloration of the surrounding ground. The next time a Small or larger creature walks over the portable pit, it transforms into an extradimensional chasm at least 20 feet deep. Creatures that trigger this effect and those adjacent to the portable pit when it transforms must succeed a DC 20 Reflex save or fall into the pit, taking damage and suffering additional effects (see below). The extradimensional pit persists for 1 minute before collapsing (harmlessly expelling any trapped creatures into an adjacent space) and becoming inert for 24 hours. If the command word is spoken a second time, a portable pit transforms back into cloth and can be picked up, moved, or stored.</p>
<p>Creatures notice a concealed portable pit with a successful DC 20 <Link to="/skill/perception">Perception</Link> check. Those trapped within can attempt to climb out; the <Link to="/skill/climb">Climb</Link> DC for the pit's smooth walls is 20.</p>
<p><strong className="hl">Acid Pit:</strong> Woven from green and yellow fabric, a portable acid pit drops victims 30 feet into a pool of boiling acid. The fall deals 2d6 points of damage and an additional 1d6 points of nonlethal damage, while the acid deals 2d6 points of acid damage every round. The film of slick acid coating the pit walls imposes a -10 circumstance penalty on Climb checks. Moderate conjuration; <strong>CL</strong> 7th; <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/acid_pit">acid pit</Link>.</p>
<p><strong className="hl">Blunt Pit:</strong> Created in a spiraling weave of blue and brown wool, a portable blunt pit drops the victim 20 feet onto hard-packed earth, and the victim takes 2d6 points of damage from the fall. Faint conjuration; <strong>CL</strong> 4th; Craft Wondrous Item, <Link to="/spell/create_pit">create pit</Link>.</p>
<p><strong className="hl">Hungry Pit:</strong> Spun from blood-red silk and studded with tiny teeth, a portable hungry pit transforms into a 40-foot-deep pit, dealing 4d6 points of damage to any victims who fall into it. Its ravenous walls then begin to grind like the stomach of a massive beast, dealing 4d6 points of bludgeoning damage every round to any creature in the pit. The convulsing walls impose a -15 circumstance penalty on Climb checks. Moderate conjuration; <strong>CL</strong> 9th; Craft Wondrous Item, <Link to="/spell/hungry_pit">hungry pit</Link>.</p>
<p><strong className="hl">Persistent Pit:</strong> This pit drops victims 20 feet, dealing 2d6 points of damage, and resumes its disguised form (expelling anyone trapped within) after 1 minute like other portable pits, but doesn't become inert once activated. A portable persistent pit continues to activate whenever a new creature walks across it. Faint conjuration; <strong>CL</strong> 4th; Craft Wondrous Item, <em>create pit.</em></p>
<p><strong className="hl">Spiked Pit:</strong> A portable spiked pit is woven from cotton fibers and thorns. Once activated, it drops victims 20 feet onto a bed of spikes. Each victim takes 2d6 points of damage from the fall, and lands on 1d4 spikes (Atk +10, 1d4+2 damage each). Faint conjuration; <strong>CL</strong> 5th; Craft Wondrous Item, <Link to="/spell/spiked_pit">spiked pit</Link>.</p>
<h3 id="magic-wondrous-portable_pit_blunt_pit-construction">Construction</h3>
<p><strong>Requirements</strong> Varies; <strong>Cost</strong> 5,050 gp (Acid pit), 1,450 gp (Blunt pit), 8,110 gp (Hungry pit), 7,210 gp (Persistent pit), 2,710 gp (Spiked pit)</p>
</>};
const _portal_finding_gloves = {title: "Portal-Finding Gloves", jsx: <><h2 id="magic-wondrous-portal_finding_gloves-portal-finding-gloves">Portal-Finding Gloves</h2>
<p><strong>Sources</strong> <Link to="/source/planar_adventures">Planar Adventures pg. 55</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 12,500 gp; <strong>Weight</strong> -</p>
<p>These tight-fitting, black leather gloves have reinforced fingertips marked with arcane sigils. The gloves prickle slightly when in the presence of portals to other planes. The wearer gains a +5 bonus on <Link to="/skill/perception">Perception</Link> and <Link to="/skill/knowledge_planes">Knowledge (planes)</Link> checks to identify portals and planar connections and can automatically learn where such connections lead by touching the portal or a connected area (such as a wall) within 10 feet of it.</p>
<h3 id="magic-wondrous-portal_finding_gloves-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/detect_magic">detect magic</Link>, <Link to="/spell/divination">divination</Link>; <strong>Cost</strong> 6,250 gp</p>
</>};
const _potion_of_poison = {title: "Potion of Poison", jsx: <><h2 id="magic-wondrous-potion_of_poison-potion-of-poison">Potion of Poison</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 349</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 542</Link><br/><strong>Aura</strong> strong conjuration; <strong>CL</strong> 12th<br/><strong>Slot</strong> none; <strong>Weight</strong> -</p>
<p>This potion has lost its beneficial abilities and become a potent poison. This poison deals 1d3 <Link to="/rule/constitution_damage">Constitution damage</Link> per round for 6 rounds. A poisoned creature can make a DC 14 Fortitude save each round to negate the damage and end the affliction.</p>
<h3 id="magic-wondrous-potion_of_poison-construction">Construction</h3>
<p><strong>Requirements</strong> any potion; <strong>Cost</strong> -</p>
</>};
const _prayer_wheel_of_ethical_strength = {title: "Prayer Wheel of Ethical Strength", jsx: <><h2 id="magic-wondrous-prayer_wheel_of_ethical_strength-prayer-wheel-of-ethical-strength">Prayer Wheel of Ethical Strength</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 316</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>Sacred or profane mantras cover the outer face of this cylindrical wooden block, which rotates around a decorative brass spindle. By holding the spindle in one hand while meditating or resting to regain ki, the bearer may attune his ki points to the wheel. Once attuned, the bearer's ki strikes count as good (if the wheel has sacred mantras) or evil (if the wheel has profane mantras) instead of lawful for the purpose of overcoming damage reduction. This lasts until the next time the bearer rests or meditates to regain ki points. A creature can only be attuned to one prayer wheel at a time, and a prayer wheel can only be attuned to one person at a time. Only creatures who can make lawfully-aligned ki strikes can use a prayer wheel.</p>
<h3 id="magic-wondrous-prayer_wheel_of_ethical_strength-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/align_weapon">align weapon</Link>; <strong>Cost</strong> 5,000 gp</p>
</>};
const _preklikins_book_of_cults = {title: "Preklikin's Book of Cults", jsx: <><h2 id="magic-wondrous-preklikins_book_of_cults-preklikins-book-of-cults">Preklikin's Book of Cults</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 268</Link>, <Link to="/source/gods_and_magic">Gods and Magic pg. 59</Link><br/><strong>Aura</strong> faint conjuration [evil]; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 1,500 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This strange leather-bound book contains erratic handwriting; the words within it appear to have been translated from Gnome into Common (and perhaps some other language before Gnome). It contains notations of strange cult practices, disturbing rants about ancient god-like beings, and confusing diagrams resembling summoning circles, with many parts crossed out or obliterated with ink or fire. The bearer of Preklikin's Book of Cults gains a +1 resistance bonus on Will saving throws while carrying the book.</p>
<p>If the bearer's patron is one of the <Link to="/main/faiths_pantheons">Great Old Ones</Link>, the bearer can hold the book in one hand to use it as a <Link to="/magic-rod/lesser_extend_metamagic_rod">lesser extend metamagic rod</Link>, but only for conjuration spells that summon or call an evil outsider.</p>
<h3 id="magic-wondrous-preklikins_book_of_cults-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/extend_spell">Extend Spell</Link>, <Link to="/spell/resistance">resistance</Link>; <strong>Cost</strong> 750 gp</p>
</>};
const _preserving_flask = {title: "Preserving Flask", jsx: <><h2 id="magic-wondrous-preserving_flask-preserving-flask">Preserving Flask</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 316</Link><br/><strong>Aura</strong> strong abjuration; <strong>CL</strong> 17th<br/><strong>Slot</strong> none; <strong>Price</strong> 1,000 gp (1st), 4,000 gp (2nd), 9,000 gp (3rd), 16,000 gp (4th), 25,000 gp (5th), 36,000 gp (6th); <strong>Weight</strong> -</p>
<p>This small, durable flask is designed to preserve alchemical extracts indefinitely. An extract stored in a preserving flask remains potent until it is consumed or otherwise removed from the flask. Preserved extracts count against an alchemist's extracts per day on the day they are prepared, but not on subsequent days. Each flask is capable of preserving an extract of a particular level. An extract stored in the flask retains duration, caster level, and other properties it had when it was created. The flask works on extracts and infusions, but not mutagens.</p>
<h3 id="magic-wondrous-preserving_flask-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, creator must be able to create alchemical extracts of the extract level to be stored; <strong>Cost</strong> 500 gp (1st), 2,000 gp (2nd), 4,500 gp (3rd), 8,000 gp (4th), 12,500 gp (5th), 18,000 gp (6th)</p>
</>};
const _preyfinder = {title: "Preyfinder", jsx: <><h2 id="magic-wondrous-preyfinder-preyfinder">Preyfinder</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 233</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 9th<br/><strong>Slot</strong> none; <strong>Price</strong> 85,000 gp; <strong>Weight</strong> -</p>
<p>These sturdy brass <Link to="/eq-misc/compass">compasses</Link> are often painted blood red and etched with images of wolves, lions, crocodiles, or sharks stalking their prey. Though preyfinders function as standard compasses, making them useful tools for navigation, they also have the power to magically identify and track down creatures.</p>
<p>To use a preyfinder, its bearer must (as a standard action) take a drop of blood from a creature, smear it onto the compass's glass faceplate, and then touch the compass to his head. The blood must be no more than 1 week old, and can come from a living or dead creature, though a living or undead target can attempt a DC 18 Will save to resist the preyfinder's tracking ability. If the Will save is successful, the preyfinder can't identify or locate the creature, and none of the preyfinder's magical powers function for 24 hours. If the creature fails the Will save, the preyfinder telepathically provides its bearer with an image of the creature to which the drop of blood belonged and marks the creature as the preyfinder's quarry.</p>
<p>After a creature is marked as the preyfinder's quarry, the bearer can spend a standard action to magically divine the creature's current location. As long as the quarry is no more than 100 miles away, the preyfinder provides a series of telepathic images to the bearer, who is then able to determine the direction toward and exact distance to the quarry. This detection ability can be fooled by <Link to="/spell/mislead">mislead</Link>, <Link to="/spell/nondetection">nondetection</Link>, and <Link to="/spell/polymorph">polymorph</Link> spells and effects.</p>
<p>A preyfinder can have only one creature designated as its quarry at any one time. If the bearer adds a new drop of blood, the old quarry is replaced by the new one. The bearer can also spend a full-round action to remove a quarry designation from the preyfinder.</p>
<p>When used by a <Link to="/class/slayer">slayer</Link> with the studied target class feature, a preyfinder grants the slayer a +1 insight bonus on all attack and damage rolls made against a creature designated as the preyfinder's quarry. Additionally, instead of designating another creature as its quarry, a slayer can add a drop of his own blood to the preyfinder (a standard action) to gain a +2 morale bonus on all attack rolls, saves, and skill checks he attempts for 1 minute. After a slayer adds a drop of his own blood to the preyfinder, none of the preyfinder's magical powers functions for 24 hours.</p>
<h3 id="magic-wondrous-preyfinder-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/blood_biography">blood biography</Link>, <Link to="/spell/heroism">heroism</Link>, <Link to="/spell/locate_creature">locate creature</Link>; <strong>Cost</strong> 42,500 gp</p>
</>};
const _primal_dowser = {title: "Primal Dowser", jsx: <><h2 id="magic-wondrous-primal_dowser-primal-dowser">Primal Dowser</h2>
<p><strong>Sources</strong> <Link to="/source/people_of_the_wastes">People of the Wastes pg. 31</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 3rd<br/><strong>Slot</strong> none; <strong>Price</strong> 1,800 gp; <strong>Weight</strong> 1 lb.</p>
<p>This triangular-shaped rod is made from metal tubes and is small enough to fit into a pocket or a pouch. One tube on the item is inlaid with a line of small emeralds, and the other is inlaid with a line of small sapphires. A primal dowser can be activated as a standard action to detect and identify the presence of variant magic within 60 feet for up to 10 minutes per day. In or near an area of <Link to="/rule/primal_magic">primal</Link> or <Link to="/rule/wild_magic">wild magic</Link>, the emeralds glow, and in or near magic dead zones, the sapphires glow. This item's duration need not be used all at once, but it must be used in 1-minute intervals.</p>
<h3 id="magic-wondrous-primal_dowser-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/detect_magic">detect magic</Link>; <strong>Cost</strong> 900 gp</p>
</>};
const _private_palanquin = {title: "Private Palanquin", jsx: <><h2 id="magic-wondrous-private_palanquin-private-palanquin">Private Palanquin</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 250</Link><br/><strong>Aura</strong> moderate abjuration and transmutation; <strong>CL</strong> 11th<br/><strong>Slot</strong> none; <strong>Price</strong> 63,000 gp; <strong>Weight</strong> 500 lbs.</p>
<p>This versatile wooden conveyance provides a safe refuge for its passengers, free from the prying eyes of others. A private palanquin can be commanded to change its appearance, including not only its decorations and appointments but also its physical form, taking the shape of an enclosed litter, two-wheeled cart, four-wheeled light or heavy wagon, carriage, or even a small cabin, though in all shapes it retains the dimensions of a Large object occupying a 10-foot cube. When activated, a private palanquin moves on its own, following its passengers' directions, and has the following statistics: <strong>hp</strong> 150; <strong>hardness</strong> 8; <strong>Speed</strong> 40 ft.; <strong>AC</strong> 18 (-1 size, +9 natural); <strong>Attack</strong> none; <strong>CMD</strong> 24; <strong>Fort</strong> +2, <strong>Ref</strong> +2, <strong>Will</strong> +2.</p>
<p>Once per day, a private palanquin can be commanded to create a set of illusory draft animals or litter bearers that last for 12 hours or until dismissed. These creatures look, sound, feel, and smell just like real creatures of their type, and they appear to move the private palanquin. Up to four Medium creatures (or a single Large creature) can fit inside a private palanquin, and creatures inside it are protected from observation, both mundane and magical, as if in a <em>mage's private sanctum.</em> The door to a private palanquin is locked, as per <em>arcane lock,</em> but opens with a command word. If the door is opened without speaking the command word, it triggers an audible <em>alarm.</em></p>
<h3 id="magic-wondrous-private_palanquin-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_construct">Craft Construct</Link>, <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/alarm">alarm</Link>, <Link to="/spell/animate_objects">animate objects</Link>, <Link to="/spell/arcane_lock">arcane lock</Link>, <Link to="/spell/mages_private_sanctum">mage's private sanctum</Link>, <Link to="/spell/veil">veil</Link>; <strong>Cost</strong> 31,500 gp</p>
</>};
const _propagation_pod = {title: "Propagation Pod", jsx: <><h2 id="magic-wondrous-propagation_pod-propagation-pod">Propagation Pod</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 19</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 15th<br/><strong>Slot</strong> none; <strong>Price</strong> 48,000 gp; <strong>Weight</strong> 250 lbs.</p>
<p>This urn-shaped object is large enough for a full-grown human to crouch inside. The bottom half of the pod is ringed in Druidic glyphs and layered with ever-fertile soil, while the top is crafted from stained glass that magically cycles between depictions of rainy, starry, and sunny skies. A <Link to="/race/ghoran">ghoran</Link> can expel its seed into a propagation pod and seal the pod as a full-round action; this does not cause the ghoran to gain a negative level. Over the next 2d6 days, the ghoran's seed sprouts into an exact replica of his current appearance. After maturing, this new ghoran remains in stasis indefinitely, acting in all ways as a fully grown clone of the ghoran as per the <em>clone</em> spell. If the ghoran dies and its soul transfers to the clone as a result, the propagation pod shatters into shards of powerless clay and glass.</p>
<p>While a ghoran's seed is expelled into a propagation pod, it cannot use its seed racial trait, nor can it use any feats or abilities dependent upon its seed. If the ghoran has the <Link to="/feat/sproutling">Sproutling</Link> feat, he can allow his clone to develop after 1d6 days instead of 2d6 days, though his size is adjusted and his ability scores modified as described by the Sproutling feat should he die and subsequently inhabit his clone.</p>
<h3 id="magic-wondrous-propagation_pod-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/clone">clone</Link>, <Link to="/spell/plant_growth">plant growth</Link>; <strong>Cost</strong> 15,660 gp</p>
</>};
const _prophetic_paraphernalia = {title: "Prophetic Paraphernalia", jsx: <><h2 id="magic-wondrous-prophetic_paraphernalia-prophetic-paraphernalia">Prophetic Paraphernalia</h2>
<p><strong>Sources</strong> <Link to="/source/faiths_and_philosophies">Faiths and Philosophies pg. 30</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 9th<br/><strong>Slot</strong> none; <strong>Price</strong> 2,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This roll of tanned horsehide contains pockets that hold ceremonial gear such as incense, candles, and tiny bells as well as a small, carved stone idol in the shape of a totem spirit such as a dragon or other creature known for its wisdom. Anyone who unrolls the kit and spends 10 minutes performing a special ritual either increases her caster level by 1 for any divination spell she begins casting immediately after concluding the ritual, or gains a +3 insight bonus to any one skill check she makes in the next hour. Alternatively, she may spend all remaining uses of the kit in an hour-long ritual to cast <em>commune,</em> asking one question for every two remaining uses in the kit.</p>
<p>A newly created set of prophetic paraphernalia has 10 uses. When all of the uses are expended, the stone idol crumbles into powder.</p>
<h3 id="magic-wondrous-prophetic_paraphernalia-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/commune">commune</Link>; <strong>Cost</strong> 1,250 gp</p>
</>};
const _psychic_aurascope = {title: "Psychic Aurascope", jsx: <><h2 id="magic-wondrous-psychic_aurascope-psychic-aurascope">Psychic Aurascope</h2>
<p><strong>Sources</strong> <Link to="/source/haunted_heroes_handbook">Haunted Heroes Handbook pg. 31</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 7th<br/><strong>Slot</strong> none; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> 4 lbs.</p>
<p>A magical version of a <Link to="/eq-misc/haunt_detector">haunt detector</Link>, a psychic aurascope is filled with a strange, swirling white vapor. A psychic aurascope acts in all ways as a haunt detector, but in addition, while the aurascope's bulb is touching a creature or object, the user can utter a command word to activate the aurascope, causing the vapor contained within it to rapidly shift between multiple hues for as long as it continues to touch that creature or object. The hues displayed within the aurascope relate to the touched creature or object's alignment aura, emotion aura, health aura, and magic aura, allowing the user to use the <Link to="/skill/read_aura">read aura</Link> occult skill unlock once per day, even if she has no levels in an occult class or doesn't have the <Link to="/feat/psychic_sensitivity">Psychic Sensitivity</Link> feat. If the user has levels in an occult class or the Psychic Sensitivity feat, she can attempt a <Link to="/skill/perception">Perception</Link> check with a DC equal to 25 + the creature's Hit Dice or the item's caster level and apply the result to all of the target's auras instead of just one single aura. The user can use this version of the read aura occult skill unlock at will; it doesn't count as her one daily use of the read aura skill unlock.</p>
<p>In addition, if the user attempts to read the auras of an object that is associated with a haunt, the object's auras twist and writhe in the shape of skulls, anguished faces, and flashes of scenes relating to the haunt's formation, allowing her to use <Link to="/skill/knowledge_religion">Knowledge (religion)</Link> to attempt to identify the haunt's elements, such as its area, notice DC, weakness, trigger, destruction requirements, and so on. The DC to identify a haunt's elements with a psychic aurascope is equal to 20 + the haunt's CR, which allows the user to determine one of the haunt's elements, chosen randomly. For every 5 by which the check's result exceeds this DC, the user randomly determines another one of the haunt's elements.</p>
<h3 id="magic-wondrous-psychic_aurascope-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/analyze_aura">analyze aura</Link>, <Link to="/spell/speak_with_haunt">speak with haunt</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _pugwampi_braid = {title: "Pugwampi Braid", jsx: <><h2 id="magic-wondrous-pugwampi_braid-pugwampi-braid">Pugwampi Braid</h2>
<p><strong>Sources</strong> <Link to="/source/monster_codex">Monster Codex pg. 93</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 8th<br/><strong>Slot</strong> none; <strong>Price</strong> 9,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This braid, crafted from strips of <Link to="/monster/pugwampi">pugwampi</Link> pelts, is 1 inch in diameter and 12 inches long. It can be carried in the hand like a riding crop or worn as an adornment.</p>
<p>Once per day with a command word, the owner of the braid can create a 5-foot-radius aura around the braid for 1 minute. Creatures other than the owner within the aura must roll twice and use the lower result whenever a situation calls for a d20 roll. This is a mind-affecting effect that does not work on humanoids with the <Link to="/monster/gnoll">gnoll</Link> subtype, animals, or <Link to="/family/gremlin">gremlins</Link>. A creature under the effect of a luck bonus is immune to the aura.</p>
<h3 id="magic-wondrous-pugwampi_braid-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bestow_curse">bestow curse</Link>; <strong>Cost</strong> 4,500 gp</p>
</>};
const _purifying_ointment = {title: "Purifying Ointment", jsx: <><h2 id="magic-wondrous-purifying_ointment-purifying-ointment">Purifying Ointment</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 223</Link><br/><strong>Aura</strong> faint abjuration and conjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 4,000 gp; <strong>Weight</strong> 1/2 lb.</p>
<p>Usually stored in a jar shaped like a scarab beetle, this unguent is pale green and smells like thistle with a hint of the scent of embalming fluids. A jar contains five applications, each of which can be applied as a full-round action.</p>
<p>When applied to an afflicted area or swallowed, the ointment removes a single curse or restores ability damage caused by an undead's special attack (such as a shadow's touch). This ointment otherwise acts as per <em>lesser restoration</em> or <em>remove curse</em> with a +5 bonus on the check. Unlike normal applications of <em>remove curse,</em> purifying ointment can potentially remove an affliction that is both a curse and disease (such as <Link to="/curse/mummy_rot">mummy rot</Link>), though that requires two successful caster level checks.</p>
<h3 id="magic-wondrous-purifying_ointment-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/lesser_restoration">lesser restoration</Link>, <Link to="/spell/remove_curse">remove curse</Link>, <Link to="/spell/remove_disease">remove disease</Link>; <strong>Cost</strong> 2,000 gp</p>
</>};
const _purifying_pearl = {title: "Purifying Pearl", jsx: <><h2 id="magic-wondrous-purifying_pearl-purifying-pearl">Purifying Pearl</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 48</Link><br/><strong>Aura</strong> moderate conjuration and transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> none; <strong>Price</strong> 19,000 gp; <strong>Weight</strong> -</p>
<p>A favored tool of diplomats and those tasked with protecting the lives of regents and other important people, this small luminescent white pearl purifies putridity and poison in two ways. First, up to 10 cubic feet of food or drink that it touches per day is affected as if a <em>purify food and drink</em> spell had been cast upon the food or drink. Second, once per day, if placed in the mouth of a creature (as a standard action that provokes attacks of opportunity), the pearl acts as a <em>neutralize poison</em> spell cast on that creature (caster level 10th).</p>
<h3 id="magic-wondrous-purifying_pearl-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/neutralize_poison">neutralize poison</Link>, <Link to="/spell/purify_food_and_drink">purify food and drink</Link>; <strong>Cost</strong> 8,000 gp</p>
</>};
const _pyre_bead = {title: "Pyre Bead", jsx: <><h2 id="magic-wondrous-pyre_bead-pyre-bead">Pyre Bead</h2>
<p><strong>Sources</strong> <Link to="/source/path_of_the_hellknight">Path of the Hellknight pg. 39</Link><br/><strong>Aura</strong> faint evocation; <strong>CL</strong> 2nd<br/><strong>Slot</strong> none; <strong>Price</strong> 1,440 gp; <strong>Weight</strong> -</p>
<p>This tiny glass bead transforms itself into a 10-foot-by-10-foot pile of logs and kindling whenever its command word is spoken. A sturdy, 8-foot-tall post juts out of the center of the log heap. This heap does not light upon coming into being, but anyone who touches the heap and says a second command word causes it to burst into flame (this also automatically activates any <Link to="/magic-wondrous/pyre_salt">pyre salt</Link> in the flame's area). The fire burns for 4 hours or until extinguished, at which point it turns back into a bead. The owner of the item must wait twice as long as the fire burned before she can order the bead to become a pile of logs again.</p>
<h3 id="magic-wondrous-pyre_bead-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/produce_flame">produce flame</Link>; <strong>Cost</strong> 720 gp</p>
</>};
const _pyre_salt = {title: "Pyre Salt", jsx: <><h2 id="magic-wondrous-pyre_salt-pyre-salt">Pyre Salt</h2>
<p><strong>Sources</strong> <Link to="/source/path_of_the_hellknight">Path of the Hellknight pg. 39</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> none; <strong>Price</strong> 700 gp; <strong>Weight</strong> -</p>
<p>Said to be crafted from witches' tears and the ashes of burned heretics, pyre salt is composed of glistening black-and-white granules and smells of smoke. It typically comes in a narrow glass vial containing one use. When pyre salt is cast into any magical or mundane flame whose area is at least 10 feet by 10 feet, the fire in that area deals double the normal amount of damage to any objects or creatures in that space for 1 round. Pyre salt cannot be activated by fire spells or effects cast onto it.</p>
<p>Additionally, any objects or creatures destroyed by the affected fire prove exceptionally difficult to restore. Anyone who casts <Link to="/spell/mending">mending</Link>, <Link to="/spell/make_whole">make whole</Link>, or a similar spell on an object destroyed by the fire must first succeed at a DC 20 caster level check or the spell fails. By the same token, anyone who casts <Link to="/spell/raise_dead">raise dead</Link>, <Link to="/spell/resurrection">resurrection</Link>, or a similar spell on a creature killed by the fire must also succeed at a DC 20 caster level check or the spell fails.</p>
<h3 id="magic-wondrous-pyre_salt-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/death_knell">death knell</Link>, <Link to="/spell/pyrotechnics">pyrotechnics</Link>; <strong>Cost</strong> 350 gp</p>
</>};
const _pyxes_of_redirected_focus = {title: "Pyxes of Redirected Focus", jsx: <><h2 id="magic-wondrous-pyxes_of_redirected_focus-pyxes-of-redirected-focus">Pyxes of Redirected Focus</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 317</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> none; <strong>Price</strong> 1,000 gp; <strong>Weight</strong> -</p>
<p>This round metal container is just large enough to contain the wooden, coin-sized token inside. Each side of the token is inscribed with a different prayer. Once per day, a <Link to="/class/cleric">cleric</Link> (or other class with cleric <Link to="/ability/domains">domains</Link>) may activate the pyxes and may select any one of her prepared domain spells and replace it with the domain spell of that level from her other domain. For example, a cleric with the <Link to="/domain/fire">Fire</Link> and <Link to="/domain/luck">Luck</Link> domains could switch her 1st-level prepared <Link to="/spell/burning_hands">burning hands</Link> domain spell to <Link to="/spell/true_strike">true strike</Link>. The pyxes has no effect on creatures with no domain spells or only one domain.</p>
<h3 id="magic-wondrous-pyxes_of_redirected_focus-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/prayer">prayer</Link>; <strong>Cost</strong> 500 gp</p>
</>};
const _quasit_key = {title: "Quasit Key", jsx: <><h2 id="magic-wondrous-quasit_key-quasit-key">Quasit Key</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_78_city_of_locusts">Pathfinder #78: City of Locusts pg. 63</Link><br/><strong>Aura</strong> strong conjuration (teleportation); <strong>CL</strong> 13th<br/><strong>Slot</strong> none; <strong>Price</strong> 70,000 gp; <strong>Weight</strong> 12 lbs.</p>
<p>A quasit key appears as a glass jar filled with preserving fluids in which a pickled <Link to="/monster/quasit">quasit</Link> floats. Each quasit key is attuned to a specific location in <Link to="/rule/the_abyss">the Abyss</Link> when created, and as long as it is carried (even if it's carried in an extradimensional space), the carrier can use <em>plane shift</em> to transport himself and up to eight other creatures that are joining hands to that location (the quasit key found in this adventure is keyed to area C1 of Aponavicius's lair). If used in the Abyss, the quasit key instead uses plane shift to transport its user back to wherever the key was last used to travel to its linked location. Until a quasit key is used to travel to its linked Abyssal location, it has nowhere to go from the Abyss itself and does not function while in the Abyss. A quasit key functions only twice per day.</p>
<h3 id="magic-wondrous-quasit_key-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/plane_shift">plane shift</Link>; <strong>Cost</strong> 35,000 gp</p>
</>};
const _quill_of_passage = {title: "Quill of Passage", jsx: <><h2 id="magic-wondrous-quill_of_passage-quill-of-passage">Quill of Passage</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 15</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> -</p>
<p>This black-feathered quill has a glowing nib with a small amount of glowing ink inside it. Three times per day, the bearer can place the quill's nib against a wall and say a command word to cause the ink to flow from the pen and draw a doorway onto the wall. The doorway persists for 10 minutes, during which any number of creatures can spend a move action to walk through the door as if it were real. Doorways can be created in this way only on walls that are no more than 6 inches thick. Additionally, a doorway cannot be created if the space on the other side of the targeted wall is blocked (such as by solid stone or dirt, furniture, or another impediment). If the bearer attempts to create a doorway in such an impossible place, the quill's ink simply doesn't flow and a daily use of this item is not expended.</p>
<h3 id="magic-wondrous-quill_of_passage-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/knock">knock</Link>, <Link to="/spell/open_and_shut">open and shut</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _quill_of_verification = {title: "Quill of Verification", jsx: <><h2 id="magic-wondrous-quill_of_verification-quill-of-verification">Quill of Verification</h2>
<p><strong>Sources</strong> <Link to="/source/villain_codex">Villain Codex pg. 45</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 1st<br/><strong>Slot</strong> none; <strong>Price</strong> 1,000 gp; <strong>Weight</strong> -</p>
<p>This swan-feather quill helps its wielder verify signatures. The wielder can store a signature in the quill by pressing the quill into the signature and speaking a command word. She can then tap the quill's tip on another signature to check if it was written by the same individual. The quill verifies the authenticity of the signature as if it had attained a total result of 20 on a <Link to="/skill/linguistics">Linguistics</Link> check. If the signature detects as legitimate (including skilled forgeries whose DC to detect them is greater than 20), the quill glows blue. A quill of verification can validate a signature up to 3 times per day. The wielder can switch the stored signature any number of times between uses of the verification ability.</p>
<h3 id="magic-wondrous-quill_of_verification-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/identify">identify</Link>; <strong>Cost</strong> 500 gp</p>
</>};
const _racing_broom_of_flying = {title: "Racing Broom of Flying", jsx: <><h2 id="magic-wondrous-racing_broom_of_flying-racing-broom-of-flying">Racing Broom of Flying</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 317</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 30,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>A racing broom of flying functions like a <Link to="/magic-wondrous/broom_of_flying">broom of flying</Link>, except for 9 minutes per day it can fly faster than its standard counterpart. Activating this increased speed is a swift action. The broom's increased fly speed is 60 feet with a load up to 200 pounds, or at a speed of 40 feet carrying up to 400 pounds. Each minute at this faster speed uses 1 hour of the broom's daily flight time. As a swift action, the rider may expend 5 hours of flight time to increase the broom's speed to 120 feet with a load up to 200 pounds, or at a speed of 80 feet carrying up to 400 pounds. This speed boost lasts for 1 round, but when it ends there is a 50% chance that the broom gains the <Link to="/misc/broken">broken</Link> condition and is powerless until repaired.</p>
<h3 id="magic-wondrous-racing_broom_of_flying-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/haste">haste</Link>, <Link to="/spell/overland_flight">overland flight</Link>, <Link to="/spell/permanency">permanency</Link>; <strong>Cost</strong> 15,000 gp</p>
</>};
const _radiant_panel = {title: "Radiant Panel", jsx: <><h2 id="magic-wondrous-radiant_panel-radiant-panel">Radiant Panel</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_shadows">Blood of Shadows pg. 21</Link><br/><strong>Aura</strong> faint evocation; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 12,000 gp; <strong>Weight</strong> -</p>
<p>This small glass cube bears shallow indents carved into each side. Pressing an indentation as a standard action creates a thin sheet of hard light that is 5 feet wide. The sheet covers one edge of a 5-foot square, chosen at activation. While active, the sheet blocks attacks as if it is a solid wall, granting total <Link to="/rule/cover">cover</Link> against attacks and spells that pass through this edge. The sheet has hardness 10 and 30 hp. Force effects bypass this sheet, acting normally. The edge chosen can even be a horizontal one, creating a platform that can hold 500 pounds of weight.</p>
<p>Once active, the cube anchors itself in place, preventing the sheet from moving. Moving the cube while it is active requires a successful DC 22 Strength check. If the cube moves or if more than 500 pounds of weight is added to the sheet, the sheet shatters, requiring another activation to create a new sheet.</p>
<p>Light sheets created by the cube remain for 1 minute and a cube can create up to 5 sheets per day. A sheet can be dismissed as a standard action, expending the full use of that sheet.</p>
<h3 id="magic-wondrous-radiant_panel-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/floating_disk">floating disk</Link>; <strong>Cost</strong> 6,000 gp</p>
</>};
const _ranged_piton = {title: "Ranged Piton", jsx: <><h2 id="magic-wondrous-ranged_piton-ranged-piton">Ranged Piton</h2>
<p><strong>Sources</strong> <Link to="/source/ranged_tactics_toolbox">Ranged Tactics Toolbox pg. 28</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 800 gp; <strong>Weight</strong> 1 lb.</p>
<p>This pointed metallic <Link to="/eq-misc/piton">piton</Link> bears a ring the size of a gold piece. A ranged piton is sized and designed so that it can be launched as easily as an arrow. When fired from a bow as a standard action at an object or empty square, the wielder makes a ranged attack against AC 5 to determine whether the piton hits the intended target. Range penalties apply as normal. On a hit, the piton attaches to the point struck, cleaving to vertical and horizontal surfaces alike. An attached ranged piton can be recovered only by speaking a command word while pulling on the piton's ring. Light rope, such as <Link to="/eq-misc/silk_rope">silk rope</Link>, can be threaded through the piton's ring before it is fired to rapidly place rope lines.</p>
<h3 id="magic-wondrous-ranged_piton-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/spider_climb">spider climb</Link>; <strong>Cost</strong> 400 gp</p>
</>};
const _raucous_canard = {title: "Raucous Canard", jsx: <><h2 id="magic-wondrous-raucous_canard-raucous-canard">Raucous Canard</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 251</Link>, <Link to="/source/taldor_echoes_of_glory">Taldor, Echoes of Glory pg. 27</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 1st<br/><strong>Slot</strong> none; <strong>Price</strong> 100 gp; <strong>Weight</strong> -</p>
<p>Scheming nobles like to use raucous canards to spread gossip about their enemies. An inactive raucous canard appears to be a small, nondescript piece of rolled-up parchment. Unrolling the parchment allows you to record a messages up to 25 words long. Once you record a message, you can throw the parchment into the air, causing it to animate, sprout small feathery wings, and circle overhead for 10 minutes while loudly repeating the message over and over in a booming voice. Alternatively, you can close the scroll, causing the animation to be triggered the next time someone opens the scroll. After 10 minutes, the raucous canard disappears in a small shower of sparks and is destroyed.</p>
<h3 id="magic-wondrous-raucous_canard-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/animate_objects">animate objects</Link>, <Link to="/spell/magic_mouth">magic mouth</Link>; <strong>Cost</strong> 50 gp</p>
</>};
const _razored_ropes = {title: "Razored Ropes", jsx: <><h2 id="magic-wondrous-razored_ropes-razored-ropes">Razored Ropes</h2>
<p><strong>Sources</strong> <Link to="/source/faiths_of_balance">Faiths of Balance pg. 27</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> none; <strong>Price</strong> 8,301 gp; <strong>Weight</strong> 3 lbs.</p>
<p>A razored rope is a +1 <Link to="/eq-weapon/lasso">lasso</Link> made out of tightly braided lengths of fine chain, used to help restrain cowards attempting to flee a battle. It can be used to entangle an opponent as normal, but deals 1d4 points of damage to a creature that attempts to slip free and fails. The razored rope is also more difficult to escape from, requiring a DC 18 <Link to="/skill/escape_artist">Escape Artist</Link> check to slip free from and a DC 28 Strength check to break.</p>
<p>If <Link to="/faith/gorum">Gorum</Link> is your patron, as a standard action you can cause the lasso to constrict around a creature already entangled by the rope, dealing 1d4 points of damage. If Gorum is not your patron and you attempt to make the lasso constrict, it lashes up and strikes you for 1d4 points of damage.</p>
<h3 id="magic-wondrous-razored_ropes-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/animate_rope">animate rope</Link>; <strong>Cost</strong> 4,150 gp</p>
</>};
const _recondite_holy_symbol = {title: "Recondite Holy Symbol", jsx: <><h2 id="magic-wondrous-recondite_holy_symbol-recondite-holy-symbol">Recondite Holy Symbol</h2>
<p><strong>Sources</strong> <Link to="/source/black_markets">Black Markets pg. 23</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 3rd<br/><strong>Slot</strong> none; <strong>Price</strong> 500 gp; <strong>Weight</strong> 1 lb.</p>
<p>A recondite holy symbol is a silver amulet depicting an old or obscure religious symbol that has long fallen out of common use within the religion in question. Each religion has its own unique obsolete emblems, but older religions are likely to have a greater variety of emblems than newer religions. For example, a recondite holy symbol of <Link to="/faith/desna">Desna</Link> might depict a single shining star (as she was sometimes depicted in ancient Azlant) or a silhouetted woman astride an elk (as she is depicted by ancient Kellid tradition), rather than her common butterfly symbol. A successful DC 15 <Link to="/skill/knowledge_religion">Knowledge (religion)</Link> check is required to identify the deity or religion associated with a recondite holy symbol, allowing the wielder to utilize the holy symbol without identifying her faith to the uninformed. When the wielder uses an appropriate recondite holy symbol to <Link to="/ability/channel_energy">channel energy</Link>, she gains a +3 competence bonus on Knowledge (religion) checks related to her deity or religion for 1 minute.</p>
<h3 id="magic-wondrous-recondite_holy_symbol-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/guidance">guidance</Link>, creator must have at least 5 ranks in Knowledge (religion); <strong>Cost</strong> 250 gp</p>
</>};
const _red_feather_fan = {title: "Red Feather Fan", jsx: <><h2 id="magic-wondrous-red_feather_fan-red-feather-fan">Red Feather Fan</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 167</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 6th<br/><strong>Slot</strong> none; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This fan is made of copper fashioned into a dozen small feathers mounted on a ring-shaped bone handle. Once per day, the bearer can hold it and speak a command word to <Link to="/rule/counterspells">counterspell</Link> a darkness effect (as if using <em>daylight</em>) or counterspell a light effect (as if using <em>deeper darkness</em>). If activated in an area of overlapping light and darkness effects, the fan randomly counterspells one of them, leaving the other intact.</p>
<h3 id="magic-wondrous-red_feather_fan-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/daylight">daylight</Link>, <Link to="/spell/deeper_darkness">deeper darkness</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _redemptors_blessing = {title: "Redemptor's Blessing", jsx: <><h2 id="magic-wondrous-redemptors_blessing-redemptors-blessing">Redemptor's Blessing</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 223</Link><br/><strong>Aura</strong> faint necromancy; <strong>CL</strong> 3rd<br/><strong>Slot</strong> none; <strong>Price</strong> 9,000 gp; <strong>Weight</strong> 1/2 lb.</p>
<p>This soothing holy symbol is carved from a single chunk of soapstone, and its graceful curves draw the eye. When used to <Link to="/ability/channel_positive_energy">channel positive energy</Link> to heal living creatures, it also calms nearby creatures.</p>
<p>Any creature healed by the positive energy channeled by a user of a redemptor's blessing must attempt a DC 13 Will save or become affected by a <em>calm emotions</em> spell. This effect lasts as long as the user continues to brandish the holy symbol and maintain concentration or until anyone takes an aggressive action against a calmed creature.</p>
<h3 id="magic-wondrous-redemptors_blessing-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/calm_emotions">calm emotions</Link>, ability to channel positive energy; <strong>Cost</strong> 4,500 gp</p>
</>};
const _regression_mine = {title: "Regression Mine", jsx: <><h2 id="magic-wondrous-regression_mine-regression-mine">Regression Mine</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_122_into_the_shattered_continent">Pathfinder #122: Into the Shattered Continent pg. 75</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 10th<br/><strong>Slot</strong> none; <strong>Price</strong> 1,500 gp; <strong>Weight</strong> 2 lbs.</p>
<p>A regression mine is a nondescript plate of metal that can be armed to deliver a terrible, mind-affecting curse. Arming the mine requires a move action, and deploying it in an adjacent square requires a standard action. An armed regression mine must be deployed within 3 rounds; otherwise, it must be rearmed before it can be deployed.</p>
<p>Once it has been deployed, a regression mine triggers when any creature enters its space. The triggered mine emits an invisible magical field in a 20-foot-radius <Link to="/misc/burst">burst</Link> centered on itself, which lasts for 1 minute before dissipating. Creatures in this field when the mine activates or that enter it while it remains active are <Link to="/misc/confused">confused</Link> and take a -4 penalty to their Intelligence scores as long as they remain in the field and for 1 minute thereafter. When a creature with the confused condition from this effect determines its action, it must reroll any result that isn't "attack nearest creature" and take the second result.</p>
<p>A creature in the field of a regression mine can avoid its effects with a successful DC 15 saving throw, but it must continue attempting saving throws at the same DC each round it remains within the regression mine's field.</p>
<p>A regression mine is a single-use item; once triggered, the mine is inert and nonmagical. An armed regression mine in the area of another regression mine's active field automatically triggers; therefore, a string of carefully placed mines can be activated in quick succession when only one of them is triggered. An armed or active regression mine can be disabled with a successful DC 30 Disable Device check. Failing the check to disable an armed regression mine by more than 5 immediately triggers it. If an active mine is disabled, its magical field immediately collapses. A regression mine is inherently unstable; a creature that takes damage while carrying an armed regression mine must succeed at a DC 15 Reflex saving throw, or the mine immediately activates.</p>
<h3 id="magic-wondrous-regression_mine-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/confusion">confusion</Link>; <strong>Cost</strong> 750 gp</p>
</>};
const _relic_of_a_virtuous_emperor = {title: "Relic of a Virtuous Emperor", jsx: <><h2 id="magic-wondrous-relic_of_a_virtuous_emperor-relic-of-a-virtuous-emperor">Relic of a Virtuous Emperor</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_ancients">Blood of the Ancients pg. 23</Link><br/><strong>Aura</strong> strong divination; <strong>CL</strong> 17th<br/><strong>Slot</strong> none; <strong>Price</strong> 87,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>While most objects - such as ancient trinkets and jewelry - sold as purported belongings of a Lung Wa emperor have no actual magical value, some do have magical properties. Such items all function much the same way, despite taking a variety of shapes and being attributed to different emperors. Whatever its origin and form, a relic of a virtuous emperor can be used to cast <em>augury</em> three times per day. It can also be used to summon one <Link to="/monster/kodama">kodama</Link> or 1d4+1 <Link to="/monster/shikigami">shikigami</Link> as if they had been summoned by <em>summon nature's ally V,</em> once per day. Additionally, anyone in possession of a relic of a virtuous emperor gains a +1 insight bonus to AC.</p>
<h3 id="magic-wondrous-relic_of_a_virtuous_emperor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/augury">augury</Link>, <Link to="/spell/foresight">foresight</Link>, <Link to="/spell/summon_natures_ally_v">summon nature's ally V</Link>; <strong>Cost</strong> 43,500 gp</p>
</>};
const _replenishing_aquarium_ball_lesser = {title: "Replenishing Aquarium Ball (Lesser)", jsx: <><h2 id="magic-wondrous-replenishing_aquarium_ball_lesser-replenishing-aquarium-ball">Replenishing Aquarium Ball</h2>
<p><strong>Sources</strong> <Link to="/source/familiar_folio">Familiar Folio pg. 21</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> none; <strong>Price</strong> 500 gp (Lesser), 2,000 gp (Standard), 4,000 gp (Greater); <strong>Weight</strong> 20 lbs.</p>
<p>Replenishing aquarium balls act as standard <Link to="/eq-misc/aquarium_ball">aquarium balls</Link>, but are endowed with magical effects beneficial to the creature held within. The power of the magic depends on the kind of replenishing aquarium ball.</p>
<p><strong className="hl">Lesser:</strong> The ball continually refreshes itself with clean water, allowing a creature within to live as long as it has food.</p>
<p><strong className="hl">Standard:</strong> The ball continually refreshes itself with clean water and fresh food.</p>
<p><strong className="hl">Greater:</strong> The ball continually refreshes itself with clean water and fresh food. In addition, a greater replenishing aquarium ball is magically enhanced so that the glass is as hard as stone (hardness 8, 15 hp) without increasing its weight.</p>
<h3 id="magic-wondrous-replenishing_aquarium_ball_lesser-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/create_water">create water</Link> (lesser only), <Link to="/spell/create_food_and_water">create food and water</Link> (standard and greater only), <Link to="/spell/stoneskin">stoneskin</Link> (greater only); <strong>Cost</strong> 250 gp (lesser), 1,000 gp (standard), 2,000 gp (greater)</p>
</>};
const _resplendent_diplomats_palette = {title: "Resplendent Diplomat's Palette", jsx: <><h2 id="magic-wondrous-resplendent_diplomats_palette-resplendent-diplomats-palette">Resplendent Diplomat's Palette</h2>
<p><strong>Sources</strong> <Link to="/source/down_the_blighted_path">Down the Blighted Path pg. 42</Link><br/><strong>Aura</strong> minor enchantment and illusion; <strong>CL</strong> 3rd<br/><strong>Slot</strong> none; <strong>Price</strong> 5,500 gp; <strong>Weight</strong> 2 lbs.</p>
<p>This shallow box contains an assortment of beeswax, oils, pigments, brushes, and quills, and allows a user to blend seemlessly into new cultures and fashion scenes. By spending 5 minutes applying these contents, a user may adopt the hairstyle, fashion, and social cues of any culture with which he is familiar, granting a +2 circumstance bonus on <Link to="/skill/bluff">Bluff</Link> or <Link to="/skill/diplomacy">Diplomacy</Link> checks with members of that culture, but leaving him otherwise recognizable. Alternatively, the palette may be used to conceal the user's identity entirely; it cannot make the user appear shorter or taller or otherwise alter their body, but otherwise allows him to adopt the appearance of another creature of the same type with the same body type and build. Either application lasts for 5 hours or until removed with soap and water. A resplendent diplomat's palette has 50 charges when created, and each use consumes 1 charge.</p>
<p>The palette qualifies as a <Link to="/eq-misc/disguise_kit">disguise kit</Link>, granting a +2 circumstance bonus on <Link to="/skill/disguise">Disguise</Link> checks. Using it as such does not consume a charge.</p>
<h3 id="magic-wondrous-resplendent_diplomats_palette-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/disguise_self">disguise self</Link>, <Link to="/spell/eagles_splendor">eagle's splendor</Link>; <strong>Cost</strong> 2,750 gp</p>
</>};
const _restless_lockpicks = {title: "Restless Lockpicks", jsx: <><h2 id="magic-wondrous-restless_lockpicks-restless-lockpicks">Restless Lockpicks</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 317</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> none; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This set of <Link to="/eq-material/mithral">mithral</Link> <Link to="/eq-misc/masterwork_thieves_tools">masterwork thieves' tools</Link> springs to life in the hands of a skilled user. If the user attempts to use the tools to disarm a trap or other device, he may spend a standard action beginning the disarm attempt, after which the tools continue on their own without being held. Thereafter, the bearer may perform other actions or even move away while the tools work. The tools make a <Link to="/skill/disable_device">Disable Device</Link> using the bearer's skill bonus plus the +2 for being masterwork thieves' tools, taking the normal amount of time to disable the device. When the skill check is completed, the tools remain in place until removed from the device. The tools can animate for up to 10 rounds per day. They can take 10 but cannot take 20. If there aren't enough rounds left in the tools to finish a particular check, the bearer can continue where the animated tools left off as long as she is in the square with the tools when the animation duration runs out.</p>
<h3 id="magic-wondrous-restless_lockpicks-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/knock">knock</Link>, <Link to="/spell/mage_hand">mage hand</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _restoration_dust = {title: "Restoration Dust", jsx: <><h2 id="magic-wondrous-restoration_dust-restoration-dust">Restoration Dust</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 234</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 2,000 gp; <strong>Weight</strong> -</p>
<p>This silky red dust is pleasantly warm to the touch. When sprinkled on a partially decomposed corpse or skeleton, it causes the dead flesh and bones to mend and reform, allowing the corpse to be identified or raised as if it were killed recently (effectively restarting the day count that limits <Link to="/spell/raise_dead">raise dead</Link>). If more than half of the bones are missing or the subject has been dead for more than 100 years, the dust has no effect. One vial contains enough restoration dust to restore a single Medium or smaller corpse. Larger corpses can be restored by using multiple vials (two for Large creatures, four for Huge, eight for Gargantuan, and 16 for Colossal).</p>
<h3 id="magic-wondrous-restoration_dust-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/make_whole">make whole</Link>; <strong>Cost</strong> 1,000 gp</p>
</>};
const _restorative_ointment = {title: "Restorative Ointment", jsx: <><h2 id="magic-wondrous-restorative_ointment-restorative-ointment">Restorative Ointment</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 317</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 526</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 4,000 gp; <strong>Weight</strong> 1/2 lb.</p>
<p>A jar of this unguent is 3 inches in diameter and 1 inch deep, and contains 5 applications. Placed upon a poisoned wound or swallowed, the ointment detoxifies any poison (as <em>neutralize poison</em> with a +5 bonus on the check). Applied to a diseased area, it removes the disease (as <em>remove disease</em> with a +5 bonus on the check). Rubbed on a wound, the ointment cures 1d8+5 points of damage (as <em>cure light wounds</em>).</p>
<h3 id="magic-wondrous-restorative_ointment-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cure_light_wounds">cure light wounds</Link>, <Link to="/spell/neutralize_poison">neutralize poison</Link>, <Link to="/spell/remove_disease">remove disease</Link>; <strong>Cost</strong> 2,000 gp</p>
</>};
const _retort_of_control = {title: "Retort of Control", jsx: <><h2 id="magic-wondrous-retort_of_control-retort-of-control">Retort of Control</h2>
<p><strong>Sources</strong> <Link to="/source/alchemy_manual">Alchemy Manual pg. 16</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> none; <strong>Price</strong> 13,000 gp; <strong>Weight</strong> -</p>
<p>This crystal retort was meticulously crafted from the hides of a dozen shattered crysmals. When light is shone through the retort, the concoction within glows like a golden torch. A retort of control can be used to perform <Link to="/rule/spontaneous_alchemy">spontaneous alchemy</Link> with speed and precision. Distillation and sublimation can be carried out in merely 10 minutes when using this tool. In addition, if the user speaks a command word while using spontaneous alchemy to create an alchemical item with the retort as an additional crafting tool, she can designate one creature type or creature subtype. The created alchemical item does not affect creatures of the designated creature type or subtype - alchemical weapons do not harm such creatures on a direct hit or with splash damage, alchemical remedies do not work on such creatures, and so on.</p>
<h3 id="magic-wondrous-retort_of_control-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/haste">haste</Link>, <Link to="/spell/mark_of_justice">mark of justice</Link>; <strong>Cost</strong> 7,500 gp</p>
</>};
const _retriever_drone = {title: "Retriever Drone", jsx: <><h2 id="magic-wondrous-retriever_drone-retriever-drone">Retriever Drone</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_75_demons_heresy">Pathfinder #75: Demon's Heresy pg. 62</Link><br/><strong>Aura</strong> strong conjuration; <strong>CL</strong> 15th<br/><strong>Slot</strong> none; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>A retriever drone appears as a masterfully preserved spider the size of a house cat, whose eyes have been replaced by four glittering gemstones. These devices are created by spellcasters who wish to control their own <Link to="/monster/retriever">retrievers</Link>, since the secret of creating those monsters is beyond mortal capacity to understand.</p>
<p>A retriever drone can be used to usurp control of a retriever that is within 30 feet. To take control of a retriever, the user of a retriever drone must have line of sight to the target and concentrate on it while holding the retriever drone in both hands. The target retriever can resist the attempt to take control by succeeding at a DC 16 Will save. If the retriever is currently on a mission to retrieve a target, it gains a +8 bonus on this save. If the retriever's saving throw is successful, the drone thrashes and scurries, making a single +15 bite attack (1d6+4 damage) against its carrier before becoming inert for 24 hours.</p>
<p>If the retriever fails to resist, it falls under the control of the person who carried the drone - this control is permanent as long as the retriever drone exists and the person who activated the drone is chaotic evil. If the controller isn't chaotic evil, control granted lasts for only 24 hours. If the retriever controlled by a drone is destroyed, the drone itself crumbles to dust.</p>
<p>As a full-round action while touching an active retriever drone, the user can look through the eyes of a controlled retriever and direct its actions. If the drone is destroyed while the user is linked in this manner, the user takes 1d4 points of <Link to="/rule/constitution_damage">Constitution damage</Link> (Fortitude DC 16 negates).</p>
<h3 id="magic-wondrous-retriever_drone-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_construct">Craft Construct</Link>, <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/greater_planar_binding">greater planar binding</Link>, <Link to="/spell/scrying">scrying</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _rhombocrystal = {title: "Rhombocrystal", jsx: <><h2 id="magic-wondrous-rhombocrystal-rhombocrystal">Rhombocrystal</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 268</Link>, <Link to="/source/gods_and_magic">Gods and Magic pg. 59</Link><br/><strong>Aura</strong> faint evocation; <strong>CL</strong> 1st<br/><strong>Slot</strong> none; <strong>Price</strong> 2,250 gp; <strong>Weight</strong> -</p>
<p>This jewel-like lens slowly changes colors over time, with no discernible pattern. It may appear as a ruby one morning and a sapphire that night, only to become opaline for the entire next day. Most owners set their rhombocrystal in a metal festoon on a chain and carry it as a pendant, monocle, or loupe. A rhombocrystal can be used as a magnifying glass, and grants its bearer a +5 competence bonus on <Link to="/skill/appraise">Appraise</Link> checks involving gems and crystals.</p>
<p>If <Link to="/faith/nivi_rhombodazzle">Nivi Rhombodazzle</Link> is the bearer's patron, the bearer gains a +1 luck bonus on Reflex saving throws.</p>
<h3 id="magic-wondrous-rhombocrystal-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/divine_favor">divine favor</Link>, creator must have 5 ranks in Appraise; <strong>Cost</strong> 1,125 gp</p>
</>};
const _ribbon_of_the_three = {title: "Ribbon of the Three", jsx: <><h2 id="magic-wondrous-ribbon_of_the_three-ribbon-of-the-three">Ribbon of the Three</h2>
<p><strong>Sources</strong> <Link to="/source/legacy_of_the_first_world">Legacy of the First World pg. 25</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> none; <strong>Price</strong> 60,000 gp; <strong>Weight</strong> -</p>
<p>This green ribbon is fashioned in the shape of <Link to="/faith/magdh">Magdh's</Link> three-pointed knot. The wearer gains three faces that each represent a different aspect of her personality, as if constantly under the effect of <em>threefold face.</em></p>
<h3 id="magic-wondrous-ribbon_of_the_three-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/threefold_face">threefold face</Link>; <strong>Cost</strong> 30,000 gp</p>
</>};
const _riffle_scroll_cantrip = {title: "Riffle Scroll (Cantrip)", jsx: <><h2 id="magic-wondrous-riffle_scroll_cantrip-riffle-scroll">Riffle Scroll</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_magic">Inner Sea Magic pg. 14</Link><br/><strong>Aura</strong> varies; <strong>CL</strong> varies<br/><strong>Slot</strong> none; <strong>Price</strong> 25 gp (Cantrip), 150 gp (1st-level Spell), 375 gp (2nd-Level Spell), 700 gp (3rd-Level Spell), 1,125 gp (4th-Level Spell), 1,650 gp (5th-Level Spell), 2,275 gp (6th-Level Spell), 3,000 gp (7th-Level Spell), 3,825 gp (8th-Level Spell); <strong>Weight</strong> 1 lb.</p>
<p>Although details of this antiquated method of crafting scrolls were once long buried in an obscure library in Ustalav, the secrets of crafting riffle scrolls were recently rediscovered by Chelish Pathfinder Varian Jeggare. Happily, he found the crafting and use of these scroll-like devices a handy remedy for the crippling nausea he normally suffered whenever he cast a spell. The secrets of this magic's rediscovery and details of its use are fully detailed in the Pathfinder Tales novel Prince of Wolves.</p>
<p>A riffle scroll is similar to a <Link to="/rule/scrolls">standard scroll</Link>, but its methods of activation and shape are quite different. A riffle scroll is a wondrous item that holds the power of a single spell. Each riffle scroll is a thin booklet, similar in shape to a chapbook (but somewhat smaller), containing 25 to 50 pages of eldritch symbols. When held between thumb and forefinger and riffled through in a quick manner, the motion of the pages turning activates the magic within, simultaneously completing casting of the spell and erasing the booklet.</p>
<p>A riffle scroll uses <Link to="/misc/spell_completion">spell completion</Link> as its activation type, just as do normal scrolls. Characters who cannot cast the spell contained in a riffle scroll must rely on <Link to="/skill/use_magic_device">Use Magic Device</Link> to activate the magic held within. Riffle scrolls are treated exactly as scrolls for the purposes of deciphering the writing, activating the spell, and determining its effects (including the chances for mishaps), save for the fact that riffle scrolls do not require verbal components - they automatically function as if they were cast using the <Link to="/feat/silent_spell">Silent Spell</Link> metamagic feat. Activating a riffle scroll provokes attacks of opportunity just like casting a spell. Magical silence does not interfere with using a riffle scroll. Activating a riffle scroll requires one free hand. A riffle scroll uses the normal casting time for the inscribed spell, even if the user or creator is of a class that has increased casting times when using metamagic effects.</p>
<p>Riffle scrolls are somewhat heavier than normal scrolls; a single riffle scroll weighs 1 pound. Each riffle scroll has an AC of 9, 5 hit points, hardness 0, and a break DC of 10. Riffle scrolls cannot be kept in standard scroll tubes; they are normally transported in flat leather cases or boxes similar to containers used to transport books.</p>
<p>Riffle scrolls can be created by any spellcaster who has the <Link to="/feat/scribe_scroll">Scribe Scroll</Link> and Silent Spell feats. Scribing a riffle scroll is more time-consuming and expensive than scribing normal scrolls because of the greater number of pages and more complex magic involved. A riffle scroll's market price is equal to the spell level &times; the caster's level &times; 25 gp - but note that only spells that have been modified by the Silent Spell metamagic feat can be crafted into riffle scrolls. This affects the spell's effective spell level for the purposes of determining the riffle scroll's price. Effectively, a riffle scroll costs about the same as a normal scroll of one spell level higher. This also means that 9th-level spells cannot be made into riffle scrolls, because there are no 10th-level spell slots. Abilities that reduce the level adjustment of the Silent Spell feat do not affect riffle scrolls.</p>
<p>To scribe a riffle scroll, you must use up raw materials costing half of its market price. Scribing a riffle scroll takes 1 day for each 1,000 gp in its base price, with a minimum of 1 day of work. Although an individual riffle scroll might contain more than one spell, each spell must be scribed as a separate effort, meaning that no more than 1 spell can be scribed in a day.</p>
<h3 id="magic-wondrous-riffle_scroll_cantrip-construction">Construction</h3>
<p><strong>Requirements</strong> Scibe Scroll, Silent Spell, the spell to be scribed; <strong>Cost</strong> 12.5 gp (Cantrip), 75 gp (1st-level spell), 187.5 gp (2nd-level spell), 350 gp (3rd-level spell), 562.5 gp (4th-level spell), 825 gp (5th-level spell), 1137.5 gp (6th-level spell), 1500 gp (7th-level spell), 1912.5 gp (8th-level spell)</p>
</>};
const _righteous_medal = {title: "Righteous Medal", jsx: <><h2 id="magic-wondrous-righteous_medal-righteous-medal">Righteous Medal</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_74_sword_of_valor">Pathfinder #74: Sword of Valor pg. 62</Link><br/><strong>Aura</strong> moderate abjuration and transmutation; <strong>CL</strong> 11th<br/><strong>Slot</strong> none; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> -</p>
<p>These ornate military medals are awarded to crusaders and adventurers who excel and deserve commendation in the war against the Worldwound. A medal must be affixed to a worn article of clothing to function, but doesn't have to be worn visibly. Any number of righteous medals can be worn, but the effects of multiple medals of a single type don't stack. A righteous medal functions only if the wearer has legitimately achieved the feat for which she received the medal. As a swift action, the wearer can gain a +2 sacred bonus to the medal's associated ability score for 1 minute. In addition, each righteous medal grants a constant sacred bonus on one type of roll, as detailed below.</p>
<blockquote>
<p><strong className="hl">Righteous Medal of Agility:</strong> This triangular iron medal shows a demonic face surrounded by three swords. It is awarded to a hero who delivers a death blow to a <Link to="/family/demon">demon</Link> in combat before that demon gets a chance to act in the combat. This medal is associated with Dexterity and grants a +1 sacred bonus on Initiative checks.</p>
<p><strong className="hl">Righteous Medal of Clarity:</strong> This circular blue medal depicts a pair of feminine gray eyes surrounded by a circular silver lightning bolt. It is awarded to a hero who recovers vital information of great use against the Worldwound and delivers this intelligence to the crusaders. This medal is associated with Intelligence and grants a +2 sacred bonus on saves against insanity or confusion effects.</p>
<p><strong className="hl">Righteous Medal of Command:</strong> This circular medal depicts a leering demon head before two crossed swords. It is awarded to a hero who redeems one of the enemy and convinces the redeemed character to join the crusade. This medal is associated with Charisma and grants a +2 sacred bonus on saves against emotion-based effects (including fear effects).</p>
<p><strong className="hl">Righteous Medal of Spirit:</strong> This rectangular medal depicts the symbol of <Link to="/faith/iomedae">Iomedae</Link> on a field of red. It is awarded to a hero who becomes possessed or mentally controlled by a demon but escapes from that control before he is forced to do evil. This medal is associated with Wisdom and grants a +2 sacred bonus on saves against charm and possession effects (including dominate effects).</p>
<p><strong className="hl">Righteous Medal of Valor:</strong> This medal looks like a demonic skull, the top of which has been pierced by four red-hilted swords. It is awarded to a hero who delivers a death blow to a demon whose CR is at least 1 higher than the hero's character level. This medal is associated with Strength and grants a +2 sacred bonus to CMD.</p>
<p><strong className="hl">Righteous Medal of Vigor:</strong> This hexagonal medal depicts a white castle on a field of red with gold trim. It is awarded to a hero who is reduced to negative hit points by a demon but survives (or alternately, is restored to life) and rejoins the battle before that demon is defeated. This medal is associated with Constitution and grants a +2 sacred bonus on saves against death effects.</p>
</blockquote>
<p>A mythic character who wears all six righteous medals gains one additional use of mythic power per day.</p>
<h3 id="magic-wondrous-righteous_medal-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>; <Link to="/spell/bless">bless</Link>; <Link to="/spell/bears_endurance">bear's endurance</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>, <Link to="/spell/cats_grace">cat's grace</Link>, <Link to="/spell/eagles_splendor">eagle's splendor</Link>, <Link to="/spell/foxs_cunning">fox's cunning</Link>, or <Link to="/spell/owls_wisdom">owl's wisdom</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _ring_gates = {title: "Ring Gates", jsx: <><h2 id="magic-wondrous-ring_gates-ring-gates">Ring Gates</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 317</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 526</Link><br/><strong>Aura</strong> strong conjuration; <strong>CL</strong> 17th<br/><strong>Slot</strong> none; <strong>Price</strong> 40,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These always come in pairs - two iron rings, each about 18 inches in diameter. The rings must be on the same plane of existence and within 100 miles of each other to function. Whatever is put through one ring comes out the other, and up to 100 pounds of material can be transferred each day. (Objects only partially pushed through and then retracted do not count.) This useful device allows for instantaneous transport of items or messages, or even attacks. A character can reach through to grab things near the other ring, or even stab a weapon through if so desired. Alternatively, a character could stick his head through to look around. A spellcaster could even cast a spell through a ring gate. A Small character can make a DC 13 <Link to="/skill/escape_artist">Escape Artist</Link> check to slip through. Creatures of Tiny, Diminutive, or Fine size can pass through easily. Each ring has an "entry side" and an "exit side," both marked with appropriate symbols.</p>
<p>The weight listed is per ring.</p>
<h3 id="magic-wondrous-ring_gates-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/gate">gate</Link>; <strong>Cost</strong> 20,000 gp</p>
</>};
const _riot_pipes = {title: "Riot Pipes", jsx: <><h2 id="magic-wondrous-riot_pipes-riot-pipes">Riot Pipes</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 350</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 310</Link></p>
<p><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 10th<br/><strong>Slot</strong> none; <strong>Weight</strong> 3 lbs.</p>
<p>This simple musical instrument seems and behaves in all ways like any other kind of magical pipes until its owner plays it in an urban setting. Once he does, it requires all people within hearing range to make a DC 15 Will saving throw to avoid falling into a murderous fury. Those who fail their saves gain the effects of a <Link to="/spell/rage">rage</Link> spell for the next 1d6 hours and experience a strong compulsion (DC 15 Will save negates) to attack any stranger or disliked person whom they encounter during this time. If the owner spends more than 3 consecutive days in an urban setting, he must make a DC 15 Will saving throw each day to avoid playing the riot pipes at some point during each subsequent day. The pipes remain with the player until the curse is broken.</p>
<h3 id="magic-wondrous-riot_pipes-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/magic-wondrous/pipes_of_haunting">pipes of haunting</Link>, <Link to="/magic-wondrous/pipes_of_the_sewers">pipes of the sewers</Link>, <Link to="/magic-wondrous/pipes_of_sounding">pipes of sounding</Link>; <strong>Cost</strong> -</p>
</>};
const _riverseer_plate = {title: "Riverseer Plate", jsx: <><h2 id="magic-wondrous-riverseer_plate-riverseer-plate">Riverseer Plate</h2>
<p><strong>Sources</strong> <Link to="/source/people_of_the_river">People of the River pg. 29</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> 1/2 lb.</p>
<p>This disc of thick green glass is 12 inches in diameter and has a small, stylized image of a boat acid - etched into its center. When set against the deck of a waterborne vessel, the plate warns of nearby obstacles on or under the water, presenting them as glowing green silhouettes on the glass in relation to the boat etched on the plate's center. A riverseer plate warns of inanimate dangers within a 300-foot radius beyond the vessel in which it is set, providing a +6 competence bonus on <Link to="/rule/sailing_check">sailing checks</Link> to navigate the vessel around potential dangers.</p>
<p>Once per day, a creature can apply a drop of blood to a riverseer plate's surface. For 5 minutes thereafter, the plate marks the location of Small or larger animate creatures in the water around the vessel, presenting them on the plate's surface as glowing red dots.</p>
<h3 id="magic-wondrous-riverseer_plate-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/detect_animals_or_plants">detect animals or plants</Link>, <Link to="/spell/riversight">riversight</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _root_of_the_world_tree_lesser = {title: "Root of the World Tree (Lesser)", jsx: <><h2 id="magic-wondrous-root_of_the_world_tree_lesser-root-of-the-world-tree">Root of the World Tree</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 156</Link><br/><strong>Aura</strong> strong conjuration; <strong>CL</strong> 17th<br/><strong>Slot</strong> none; <strong>Price</strong> 300 gp (Lesser), 1,000 gp (Normal), 2,500 gp (Greater); <strong>Weight</strong> -</p>
<p>This fibrous powder is ground from bark harvested from the roots of trees growing across planar boundaries. When thrown in the air as part of casting a conjuration (summoning) spell, it grants the creatures summoned the <Link to="/template/advanced">advanced</Link> simple template. If the caster also expends one use of mythic power, the summoned creatures gain DR 5/epic, or DR 10/epic if they have at least 11 HD. Lesser root affects conjuration (summoning) spells up to 3rd level, normal root conjuration (summoning) spells up to 6th level, and greater root any conjuration (summoning) spell.</p>
<h3 id="magic-wondrous-root_of_the_world_tree_lesser-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/mythic_crafter">Mythic Crafter</Link>, <Link to="/feat/augment_summoning">Augment Summoning</Link>, <Link to="/spell/heroism">heroism</Link>; <strong>Cost</strong> 150 gp (Lesser), 500 gp (Normal), 1,250 gp (Greater)</p>
</>};
const _rope_of_climbing = {title: "Rope of Climbing", jsx: <><h2 id="magic-wondrous-rope_of_climbing-rope-of-climbing">Rope of Climbing</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 317</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 529</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> none; <strong>Price</strong> 3,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>A 60-foot-long rope of climbing is no thicker than a wand, but it is strong enough to support 3,000 pounds. Upon command, the rope snakes forward, upward, downward, or in any other direction at 10 feet per round, attaching itself securely wherever its owner desires. It can unfasten itself and return in the same manner.</p>
<p>A rope of climbing can be commanded to knot or unknot itself. This causes large knots to appear at 1-foot intervals along the rope. Knotting shortens the rope to a 50-foot length until the knots are untied, but lowers the DC of <Link to="/skill/climb">Climb</Link> checks while using it by 10. A creature must hold one end of the rope when its magic is invoked.</p>
<h3 id="magic-wondrous-rope_of_climbing-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/animate_rope">animate rope</Link>; <strong>Cost</strong> 1,500 gp</p>
</>};
const _rope_of_entanglement = {title: "Rope of Entanglement", jsx: <><h2 id="magic-wondrous-rope_of_entanglement-rope-of-entanglement">Rope of Entanglement</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 318</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 529</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 12th<br/><strong>Slot</strong> none; <strong>Price</strong> 21,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>A rope of entanglement looks just like any other hempen rope about 30 feet long. Upon command, the rope lashes forward 20 feet or upward 10 feet to entangle a victim. An <Link to="/rule/entangled">entangled</Link> creature can break free with a DC 20 Strength check or a DC 20 <Link to="/skill/escape_artist">Escape Artist</Link> check.</p>
<p>A rope of entanglement has AC 22, 12 hit points, hardness 10, and damage reduction 5/slashing. The rope repairs damage to itself at a rate of 1 point per 5 minutes, but if a rope of entanglement is severed (all 12 hit points lost to damage), it is destroyed.</p>
<h3 id="magic-wondrous-rope_of_entanglement-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/animate_objects">animate objects</Link>, <Link to="/spell/animate_rope">animate rope</Link> or <Link to="/spell/entangle">entangle</Link>; <strong>Cost</strong> 10,500 gp</p>
</>};
const _rope_of_knots = {title: "Rope of Knots", jsx: <><h2 id="magic-wondrous-rope_of_knots-rope-of-knots">Rope of Knots</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 318</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> none; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> -</p>
<p>This rope is 100 feet long and can perform all the functions of a <Link to="/magic-wondrous/rope_of_climbing">rope of climbing</Link>. Furthermore, upon command the rope of knots snakes out and knots itself into a rope structure. The rope can tie itself into any structure which can be created out of 100 feet of rope. Possible structures include (but are not limited to) a sturdy rope bridge up to 25 feet long, a 10-foot-square net or hammock, or a 40-foot-tall rope ladder. The rope takes up to 10 rounds to create a complex structure or half that time to return itself to a simple coil. The rope has hardness 1 and 20 hit points. It repairs damage to itself at a rate of 2 hit points every 10 minutes.</p>
<h3 id="magic-wondrous-rope_of_knots-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/animate_rope">animate rope</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _ruby_sapphire_of_osh_maru = {title: "Ruby Sapphire of Osh-Maru", jsx: <><h2 id="magic-wondrous-ruby_sapphire_of_osh_maru-ruby-sapphire-of-osh-maru">Ruby Sapphire of Osh-Maru</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_95_anvil_of_fire">Pathfinder #95: Anvil of Fire pg. 39</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> none; <strong>Price</strong> 96,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This fist-sized uncut gem looks like a human heart. One half is ruby-red with blue flecks; the other is sapphire-blue with red flecks. Five times per day when the gem is held in one hand, a spellcaster can use this item as an additional focus component when casting a spell that deals electricity or fire damage, converting up to half the spell's electricity damage to fire damage or vice versa, as if using the Elemental Spell metamagic feat. Unlike the feat, this does not alter the casting time or spell level of the spell.</p>
<p>In addition, when held, the gem provides the bearer resistance 20 against electricity and fire. At will as a free action, the bearer can command the Ruby Sapphire of Osh-Maru to glow as brightly as a <Link to="/eq-misc/torch">torch</Link> with either blue or red flame, manipulate this light as if it were <Link to="/spell/dancing_lights">dancing lights</Link>, or snuff this light.</p>
<h3 id="magic-wondrous-ruby_sapphire_of_osh_maru-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/elemental_spell">Elemental Spell</Link>, <Link to="/spell/resist_energy">resist energy</Link>; <strong>Cost</strong> 48,000 gp</p>
</>};
const _ruby_skull_of_chast = {title: "Ruby Skull of Chast", jsx: <><h2 id="magic-wondrous-ruby_skull_of_chast-ruby-skull-of-chast">Ruby Skull of Chast</h2>
<p><strong>Sources</strong> <Link to="/source/lost_treasures">Lost Treasures pg. 50</Link><br/><strong>Aura</strong> moderate evocation [good]; <strong>CL</strong> 9th<br/><strong>Slot</strong> none; <strong>Price</strong> 65,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This human skull covered in red lacquer bears a holy symbol of <Link to="/faith/pharasma">Pharasma</Link>. The area around the Ruby Skull of Chast is treated as though a <em>hallow</em> spell had been cast upon it, with the skull as the point of origin. Creatures that are lawful neutral or worship Pharasma gain the benefit of <Link to="/spell/death_ward">death ward</Link> while in the area of this effect. Despite its powerful effect, the Ruby Skull of Chast does not register to <Link to="/spell/detect_good">detect good</Link>, <Link to="/spell/detect_magic">detect magic</Link>, or similar divination spells unless the caster of the divination succeeds at a DC 20 caster level check.</p>
<h3 id="magic-wondrous-ruby_skull_of_chast-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/hallow">hallow</Link>, <Link to="/spell/nondetection">nondetection</Link>; <strong>Cost</strong> 32,500 gp</p>
</>};
const _runes_of_the_crones_coven = {title: "Runes of the Crone's Coven", jsx: <><h2 id="magic-wondrous-runes_of_the_crones_coven-runes-of-the-crones-coven">Runes of the Crone's Coven</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 234</Link><br/><strong>Aura</strong> strong universal; <strong>CL</strong> 12th<br/><strong>Slot</strong> none; <strong>Price</strong> 16,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This leather pouch contains a set of black stones, each engraved with a different rune of ill fortune. When used as part of <Link to="/class/skald">spell kenning</Link>, they allow the user to cast spells from the <Link to="/main/spells_witch">witch spell list</Link>. To cast a witch spell, the possessor must spend twice as long casting as for normal spell kenning, and must use a spell slot 1 level higher than normal. If the possessor has the master skald class feature, determine casting time as though he lacked that class feature instead of doubling casting time. The tiles can be used once per day.</p>
<h3 id="magic-wondrous-runes_of_the_crones_coven-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/imbue_with_spell_ability">imbue with spell ability</Link>, creator must be able to cast 6th-level witch spells; <strong>Cost</strong> 8,000 gp</p>
</>};
const _runes_of_the_old_faith = {title: "Runes of the Old Faith", jsx: <><h2 id="magic-wondrous-runes_of_the_old_faith-runes-of-the-old-faith">Runes of the Old Faith</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 234</Link><br/><strong>Aura</strong> strong universal; <strong>CL</strong> 12th<br/><strong>Slot</strong> none; <strong>Price</strong> 16,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This velvet pouch contains a number of stones gathered from the creator's local area that bear runes with a single druidic symbol each. Runes of the old faith work as <Link to="/magic-wondrous/runes_of_the_crones_coven">runes of the crone's coven</Link>, except they allow casting of <Link to="/main/spells_druid">druid spells</Link> as part of <Link to="/class/skald">spell kenning</Link>. The stones can be used once per day.</p>
<h3 id="magic-wondrous-runes_of_the_old_faith-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/imbue_with_spell_ability">imbue with spell ability</Link>, creator must be able to cast 6th-level druid spells; <strong>Cost</strong> 8,000 gp</p>
</>};
const _runestone_of_power = {title: "Runestone of Power", jsx: <><h2 id="magic-wondrous-runestone_of_power-runestone-of-power">Runestone of Power</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 234</Link>, <Link to="/source/pathfinder_society_field_guide">Pathfinder Society Field Guide pg. 53</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 17th<br/><strong>Slot</strong> none; <strong>Price</strong> 2,000 gp (1st), 8,000 gp (2nd), 18,000 gp (3rd), 32,000 gp (4th), 50,000 gp (5th), 72,000 gp (6th), 98,000 gp (7th), 128,000 gp (8th), 162,000 gp (9th); <strong>Weight</strong> -</p>
<p>A runestone of power is a small chip of polished stone etched with a rune. These objects are potent aids to all spellcasters who cast spontaneously (but not to spellcasters like clerics who have the option to spontaneously cast certain spells). Once per day, a spontaneous caster can draw upon a runestone of power to cast a spell - doing so is part of the spellcasting action, and expends that runestone's power for the day rather than one of the spellcaster's actual spell slots for the day. An expended runestone of power recharges its capacity after 24 hours. The spell must be of a particular level, depending on the runestone.</p>
<h3 id="magic-wondrous-runestone_of_power-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, creator must be able to spontaneously cast spells of the appropriate spell level; <strong>Cost</strong> 1,000 gp (1st), 4,000 gp (2nd), 9,000 gp (3rd), 16,000 gp (4th), 25,000 gp (5th), 36,000 gp (6th), 49,000 gp (7th), 64,000 gp (8th), 81,000 gp (9th)</p>
</>};
const _sable_company_elite_saddle = {title: "Sable Company Elite Saddle", jsx: <><h2 id="magic-wondrous-sable_company_elite_saddle-sable-company-elite-saddle">Sable Company Elite Saddle</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 62</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 14,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>Several alterations along the edges of this well-maintained leather <Link to="/eq-misc/saddle">saddle</Link> allow for the movement of a mount's wings. A Sable Company elite saddle grants a mount wearing it a +5 competence bonus on <Link to="/skill/fly">Fly</Link> checks, and grants the rider a +5 competence bonus on <Link to="/skill/ride">Ride</Link> checks. If the rider is unsaddled during flight, he is immediately subject to a <Link to="/spell/feather_fall">feather fall</Link> effect.</p>
<p>The mount additionally gains the benefits of any <Link to="/main/teamwork_feat">teamwork feats</Link> the rider possesses.</p>
<h3 id="magic-wondrous-sable_company_elite_saddle-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/fly">fly</Link>, <Link to="/spell/mount">mount</Link>, creator must have 5 ranks in Ride; <strong>Cost</strong> 7,000 gp</p>
</>};
const _saccadic_focusing_prism = {title: "Saccadic Focusing Prism", jsx: <><h2 id="magic-wondrous-saccadic_focusing_prism-saccadic-focusing-prism">Saccadic Focusing Prism</h2>
<p><strong>Sources</strong> <Link to="/source/magic_tactics_toolbox">Magic Tactics Toolbox pg. 18</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 3rd<br/><strong>Slot</strong> none; <strong>Price</strong> 2,400 gp; <strong>Weight</strong> 1 lb.</p>
<p>When this large, clear prism is held between the user and a text, it allows the user to read that text quickly and still obtain a complete understanding. The time needed to read any nonmagical text with a saccadic focusing prism is reduced to one-tenth the time the user would normally require. The time required to gain a benefit from any magical text (such as a <Link to="/magic-wondrous/tome_of_clear_thought">tome of clear thought</Link> or a <Link to="/magic-wondrous/manual_of_war">manual of war</Link>) is halved. This has no impact on the time required to learn spells or extracts from written sources.</p>
<h3 id="magic-wondrous-saccadic_focusing_prism-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/comprehend_languages">comprehend languages</Link>, <Link to="/spell/haste">haste</Link>; <strong>Cost</strong> 1,200 gp</p>
</>};
const _sacrificial_dagger_of_the_blood_mother = {title: "Sacrificial Dagger of the Blood Mother", jsx: <><h2 id="magic-wondrous-sacrificial_dagger_of_the_blood_mother-sacrificial-dagger-of-the-blood-mother">Sacrificial Dagger of the Blood Mother</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 268</Link>, <Link to="/source/gods_and_magic">Gods and Magic pg. 59</Link><br/><strong>Aura</strong> faint necromancy [evil]; <strong>CL</strong> 3rd<br/><strong>Slot</strong> none; <strong>Price</strong> 2,700 gp; <strong>Weight</strong> 1 lb.</p>
<p>This dagger is usually made of chiseled stone, though some varieties are made of sharpened mammoth bone. Its hilt is especially long, as if created for a Large creature, and the blade is carved with a symbol of a woman holding meat in one hand and a stone tablet in the other. The dagger is symbolic, and cannot be used as an actual weapon. Once per day, the wielder can use <em>detect animals or plants.</em></p>
<p>If the giant goddess <Link to="/faith/fandarra">Fandarra</Link> is the wielder's patron, once per day the wielder can use <em>death knell</em> if he offers the target's blood to the goddess.</p>
<h3 id="magic-wondrous-sacrificial_dagger_of_the_blood_mother-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/death_knell">death knell</Link>, <Link to="/spell/detect_animals_or_plants">detect animals or plants</Link>; <strong>Cost</strong> 1,350 gp</p>
</>};
const _safecamp_wagon = {title: "Safecamp Wagon", jsx: <><h2 id="magic-wondrous-safecamp_wagon-safecamp-wagon">Safecamp Wagon</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 268</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 6th<br/><strong>Slot</strong> none; <strong>Price</strong> 3,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p><Link to="/faith/abadar">Abadar's</Link> church created the first safecamp wagons to protect valuable cargo as it traveled between cities. When inactive, a safecamp wagon looks like an elaborately carved wooden toy wagon, 12 inches long, 6 inches wide, and 6 inches tall. On command, the toy transforms in a single round into an open-topped wagon. A second command word creates a canvas top supported with a sturdy wooden frame over the wagon.</p>
<p>A third command word causes wooden panels to extend down and outward from the wagon, forming a stable wooden platform extending 5 feet in all directions from the wagon's base, suitable for walking, sitting, standing, or sleeping upon. A sliding wooden door in the back panel allows access to the space under the wagon. Speaking the command word again causes these panels to retract into the wagon. A fourth command word returns the wagon to its toy shape; any items on or in the wagon are carefully placed on the ground around the toy.</p>
<p>A safecamp wagon cannot transform if there isn't enough open space for it to occupy at full size. In any form, the wooden parts of this item have hardness 8, the canvas parts have hardness 2, and the entire object has fire resistance 5.</p>
<h3 id="magic-wondrous-safecamp_wagon-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/fabricate">fabricate</Link>, creator must have 2 ranks in the <Link to="/skill/craft">Craft (carpentry)</Link> skill; <strong>Cost</strong> 1,500 gp</p>
</>};
const _saga_of_the_linnorm_kings = {title: "Saga of the Linnorm Kings", jsx: <><h2 id="magic-wondrous-saga_of_the_linnorm_kings-saga-of-the-linnorm-kings">Saga of the Linnorm Kings</h2>
<p><strong>Sources</strong> <Link to="/source/people_of_the_north">People of the North pg. 29</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> none; <strong>Price</strong> 26,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This heavy book contains a collection of epic tales of mighty Ulfen heroes and the wondrous deeds they performed, but entwined within the words is a powerful magical effect. If anyone reads this book, which takes a total of 48 hours over a minimum of 6 days, she gains a +5 competence bonus on <Link to="/skill/diplomacy">Diplomacy</Link> and <Link to="/skill/intimidate">Intimidate</Link> checks and a +4 morale bonus on saves against fear. This is a permanent magical effect that can be dispelled as normal. Once the book is read, the magic disappears from the pages and it becomes a normal book.</p>
<h3 id="magic-wondrous-saga_of_the_linnorm_kings-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/eagles_splendor">eagle's splendor</Link>, <Link to="/spell/remove_fear">remove fear</Link>, creator must be a <Link to="/class/bard">bard</Link>; <strong>Cost</strong> 13,000 gp</p>
</>};
const _saliharion = {title: "Saliharion", jsx: <><h2 id="magic-wondrous-saliharion-saliharion">Saliharion</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_temples">Inner Sea Temples pg. 52</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 3,000 gp; <strong>Weight</strong> 15 lbs.</p>
<p>Named for Nashina aj-Salihar, the Sarenite monk who penned the original work, this hefty tome contains inspiring parables, simple folk remedies for widespread illnesses and injuries, and helpful hints for dealing with common monsters. Its pages are expertly illuminated with brilliant inks and metallic foil, depicting scenes of angels battling various monstrosities. While in possession of this book, the owner gains a +2 sacred bonus on <Link to="/skill/heal">Heal</Link> checks and <Link to="/skill/knowledge">Knowledge</Link> skill checks to identify the abilities and weaknesses of monsters.</p>
<p>If <Link to="/faith/sarenrae">Sarenrae</Link> is the owner's patron, the owner may instead choose to gain a sacred bonus equal to her Wisdom or Charisma modifier on these skill checks instead of the normal +2 bonus.</p>
<h3 id="magic-wondrous-saliharion-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/know_the_enemy">know the enemy</Link>, <Link to="/spell/owls_wisdom">owl's wisdom</Link>; <strong>Cost</strong> 1,500 gp</p>
</>};
const _saline_purge = {title: "Saline Purge", jsx: <><h2 id="magic-wondrous-saline_purge-saline-purge">Saline Purge</h2>
<p><strong>Sources</strong> <Link to="/source/magical_marketplace">Magical Marketplace pg. 9</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 900 gp; <strong>Weight</strong> 1/2 lb.</p>
<p>The putrid concoction in this glass bottle smells foul and tastes worse. Anyone who drinks a dose of saline purge must succeed at a DC 14 Fortitude save or become <Link to="/misc/nauseated">nauseated</Link> for 1d4+1 rounds. Whether or not this save is successful, the imbiber is cured of any curses or poisons affecting him as his body purges the ill effects.</p>
<h3 id="magic-wondrous-saline_purge-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/neutralize_poison">neutralize poison</Link>, <Link to="/spell/remove_curse">remove curse</Link>; <strong>Cost</strong> 450 gp</p>
</>};
const _salve_of_slipperiness = {title: "Salve of Slipperiness", jsx: <><h2 id="magic-wondrous-salve_of_slipperiness-salve-of-slipperiness">Salve of Slipperiness</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 318</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 529</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 6th<br/><strong>Slot</strong> none; <strong>Price</strong> 1,000 gp; <strong>Weight</strong> -</p>
<p>This substance provides a +20 competence bonus on all <Link to="/skill/escape_artist">Escape Artist</Link> checks and combat maneuver checks made to escape from a <Link to="/rule/grapple">grapple</Link>. The salve also grants a +10 competence bonus to the wearer's CMD for the purpose of avoiding grapple attempts. In addition, such obstructions as webs (magical or otherwise) do not affect an anointed individual. Magic ropes and the like do not avail against this salve. If it is smeared on a floor or on steps, the area should be treated as a long-lasting <em>grease</em> spell. The salve requires 8 hours to wear off normally, or it can be wiped off with an alcohol solution (even wine).</p>
<p>Salve of slipperiness is needed to coat the inside of a container meant to hold <Link to="/magic-wondrous/sovereign_glue">sovereign glue</Link>.</p>
<h3 id="magic-wondrous-salve_of_slipperiness-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/grease">grease</Link>; <strong>Cost</strong> 500 gp</p>
</>};
const _salve_of_the_second_chance = {title: "Salve of the Second Chance", jsx: <><h2 id="magic-wondrous-salve_of_the_second_chance-salve-of-the-second-chance">Salve of the Second Chance</h2>
<p><strong>Sources</strong> <Link to="/source/guide_to_the_river_kingdoms">Guide to the River Kingdoms pg. 62</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> none; <strong>Price</strong> 1,600 gp; <strong>Weight</strong> -</p>
<p>Under tutelage from Embeth Forest sprites, Mother Nightmoss developed this potent salve from the distillation of nightmoss. When smeared on a body or body part from a recently deceased creature, the salve mimics the effects of a <em>reincarnate</em> spell. If this salve is used on a creature during the night of a new moon, roll twice on the reincarnate table and have the recipient player or NPC choose his preferred result.</p>
<h3 id="magic-wondrous-salve_of_the_second_chance-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/reincarnate">reincarnate</Link>; <strong>Cost</strong> 800 gp</p>
</>};
const _samisen_of_oracular_vision = {title: "Samisen of Oracular Vision", jsx: <><h2 id="magic-wondrous-samisen_of_oracular_vision-samisen-of-oracular-vision">Samisen of Oracular Vision</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_53_tide_of_honor">Pathfinder #53: Tide of Honor pg. 60</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 10th<br/><strong>Slot</strong> none; <strong>Price</strong> 46,575 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This elegant, long-necked samisen is crafted of cat skin stretched over a wooden frame. The samisen's three silken strings are magically keyed to the past, present, and future. A user must succeed at a DC 20 <Link to="/skill/perform">Perform (string)</Link> check to play the correct tune and cast one of the following spell effects: <em>legend lore</em> (using the string of the past), <em>scrying</em> (using the string of the present), or <em>divination</em> (using the string of the future). Each tune can be performed once per day, and the user must play the samisen for the required casting time of the spell effect. In the case of <em>legend lore,</em> if the required casting time is 1 or more days, the user needs to play for just 1 hour. As a <Link to="/eq-misc/masterwork_samisen">masterwork samisen</Link>, the samisen of oracular vision provides a +2 circumstance bonus on all Perform checks using the instrument (including Perform checks to use its abilities).</p>
<h3 id="magic-wondrous-samisen_of_oracular_vision-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/divination">divination</Link>, <Link to="/spell/legend_lore">legend lore</Link>, <Link to="/spell/scrying">scrying</Link>, creator must have 10 ranks in the Perform (string) skill; <strong>Cost</strong> 24,075 gp</p>
</>};
const _sandstorm_dust = {title: "Sandstorm Dust", jsx: <><h2 id="magic-wondrous-sandstorm_dust-sandstorm-dust">Sandstorm Dust</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_elements">Blood of the Elements pg. 30</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 11th<br/><strong>Slot</strong> none; <strong>Price</strong> 9,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This ornate sack made of dyed leather contains a mixture of swirling atmospheric energies from the Plane of Air and gritty elemental dust from the Plane of Earth. As a standard action, the owner can blow a handful of sandstorm dust at a single creature of size Large or smaller within 10 feet. If the target fails at a DC 19 Reflex save, the sandstorm dust catches on the creature and grows to the size of a small sandstorm. At the beginning of the target's turn for the next 1d6+1 rounds, the creature is swept violently upward, thrown back to the ground, and then dropped in a random adjacent empty square, taking 1d6 points of damage from the impact. While the target lands on its feet each time, this does not prevent it from being dropped off a cliff or onto a dangerous patch of terrain. The affected creature can attempt to arrest itself as a move action with a successful DC 25 <Link to="/skill/acrobatics">Acrobatics</Link> check or DC 19 Reflex save; success means that the creature is not flung into the air that round. If the creature succeeds at two consecutive Acrobatics checks or Reflex saves in this way, the sandstorm dissipates and the effect ends.</p>
<p>A newly created bag of sandstorm dust contains enough dust for three uses.</p>
<h3 id="magic-wondrous-sandstorm_dust-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/sirocco">sirocco</Link>; <strong>Cost</strong> 4,500 gp</p>
</>};
const _sashimono_of_comfort = {title: "Sashimono of Comfort", jsx: <><h2 id="magic-wondrous-sashimono_of_comfort-sashimono-of-comfort">Sashimono of Comfort</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_51_the_hungry_storm">Pathfinder #51: The Hungry Storm pg. 62</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 1st<br/><strong>Slot</strong> none; <strong>Price</strong> 2,400 gp; <strong>Weight</strong> 3 lbs.</p>
<p>A sashimono of comfort is a purple Tian silk banner, typically 3 feet tall and 1 foot wide, decorated with three stylized orchid flowers. The banner is attached to a lance, polearm, staff, or frame, which can be worn on the back of a creature, carried by a mounted creature, flown from a wagon, or planted in the ground. A sashimono of comfort keeps creatures comfortable in extreme weather conditions. It has no effect when not mounted properly or when lying on the ground. When worn or carried by a creature, the banner grants the effects of <em>endure elements</em> to the bearer. When carried by a mounted creature, it grants both mount and rider this benefit. If it is flown from a wagon, the wagon's driver, passengers, and draft team all gain this benefit. If planted firmly in the ground, the banner grants this benefit to all creatures within 30 feet. In addition, a <Link to="/rule/caravan_statistics">caravan</Link> equipped with a sashimono of comfort gains a +2 bonus on Security checks to resist the effects of severe weather. These effects function at temperatures between -50&deg; and 140&deg; F. If conditions are beyond these extremes, creatures using a sashimono of comfort treat the ambient temperature as if it were 50&deg; F warmer or cooler respectively, thereby possibly allowing additional castings of <em>endure elements</em> to work normally.</p>
<h3 id="magic-wondrous-sashimono_of_comfort-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/endure_elements">endure elements</Link>; <strong>Cost</strong> 1,200 gp</p>
</>};
const _sasquatch_skull = {title: "Sasquatch Skull", jsx: <><h2 id="magic-wondrous-sasquatch_skull-sasquatch-skull">Sasquatch Skull</h2>
<p><strong>Sources</strong> <Link to="/source/mystery_monsters_revisited">Mystery Monsters Revisited pg. 43</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> none; <strong>Price</strong> -; <strong>Weight</strong> 5 lbs.</p>
<p>Divination reveals this large humanoid skull to be that of a gorilla or giant, although it is actually an accursed <Link to="/monster/sasquatch">sasquatch</Link> skull. The item seems to grant its bearer a +5 bonus on <Link to="/skill/stealth">Stealth</Link> checks in wooded areas. If an individual takes possession of the sasquatch skull for more than 24 hours, it quickly begins to stink. The smell is undetectable by the skull's bearer, but companions and creatures within 30 feet find the pungent smell extremely noticeable. The smell imposes a -2 penalty on Charisma checks and Charisma-based skill checks made by the skull's owner. In addition, aggressive wild animals always target the skull's owner first during combat. The skull need not be on the owner's person for the curse to manifest, so long as ownership has not been transferred through sale, gift, or theft.</p>
<h3 id="magic-wondrous-sasquatch_skull-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/magic-wondrous/darkskull">darkskull</Link>; <strong>Cost</strong> -</p>
</>};
const _satchel_of_plentiful_feed = {title: "Satchel of Plentiful Feed", jsx: <><h2 id="magic-wondrous-satchel_of_plentiful_feed-satchel-of-plentiful-feed">Satchel of Plentiful Feed</h2>
<p><strong>Sources</strong> <Link to="/source/villain_codex">Villain Codex pg. 165</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 2,000 gp (Type I), 4,000 gp (Type II), 7,500 gp (Type III), 15,000 gp (Type IV); <strong>Weight</strong> varies</p>
<p>This item appears to be an unremarkable mesh bag with many small openings, but it is stuffed to overflowing with hay. It can be hung from a line, post, or tree limb and used to feed horses and ponies. It produces enough fresh feed for a number of horses or other similar mounts each day, as shown in the table below.</p>
<ScrollContainer id="magic-wondrous-satchel_of_plentiful_feed--table-0"><table>
<thead>
<tr>
<th>Satchel Type</th>
<th>Satchel Weight</th>
<th>Mounts Fed/Day</th>
<th>Market Price</th>
</tr>
</thead>
<tbody><tr>
<td>I</td>
<td>15 lbs.</td>
<td>4</td>
<td>2,000 gp</td>
</tr>
<tr>
<td>II</td>
<td>20 lbs.</td>
<td>10</td>
<td>4,000 gp</td>
</tr>
<tr>
<td>III</td>
<td>25 lbs.</td>
<td>25</td>
<td>7,500 gp</td>
</tr>
<tr>
<td>IV</td>
<td>30 lbs.</td>
<td>50</td>
<td>15,000 gp</td>
</tr>
</tbody></table></ScrollContainer>
<h3 id="magic-wondrous-satchel_of_plentiful_feed-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/create_food_and_water">create food and water</Link>; <strong>Cost</strong> 1,000 gp (Type I), 2,000 gp (Type II), 3,750 gp (Type III), 7,500 gp (Type IV)</p>
</>};
const _scabbard_of_honing = {title: "Scabbard of Honing", jsx: <><h2 id="magic-wondrous-scabbard_of_honing-scabbard-of-honing">Scabbard of Honing</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 318</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> none; <strong>Price</strong> 500 gp; <strong>Weight</strong> 1 lb.</p>
<p>This leather scabbard resizes itself to fit any axe, sword, dagger, or similar item normally stored in a scabbard. Sheathing a nonmagical weapon in the scabbard for 1 minute hones its edge as if it had been sharpened with a <Link to="/eq-misc/whetstone">whetstone</Link>.</p>
<h3 id="magic-wondrous-scabbard_of_honing-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/mending">mending</Link>; <strong>Cost</strong> 250 gp</p>
</>};
const _scabbard_of_keen_edges = {title: "Scabbard of Keen Edges", jsx: <><h2 id="magic-wondrous-scabbard_of_keen_edges-scabbard-of-keen-edges">Scabbard of Keen Edges</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 318</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 529</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 16,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This black scabbard is engraved with intricate silver runes that depict all manner of bladed weapons. A scabbard of keen edges can shrink or enlarge to accommodate any knife, dagger, sword, or similar weapon up to and including a <Link to="/eq-weapon/greatsword">greatsword</Link>. Up to three times per day on command, the scabbard casts <em>keen edge</em> on any blade placed within it. Runes similar to those on the outside of the scabbard appear on a blade while it is under this <em>keen edge</em> effect.</p>
<h3 id="magic-wondrous-scabbard_of_keen_edges-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/keen_edge">keen edge</Link>; <strong>Cost</strong> 8,000 gp</p>
</>};
const _scabbard_of_many_blades = {title: "Scabbard of Many Blades", jsx: <><h2 id="magic-wondrous-scabbard_of_many_blades-scabbard-of-many-blades">Scabbard of Many Blades</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 235</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> none; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This scabbard can hold multiple melee weapons in an extradimensional space, including weapons that would not normally fit in any kind of scabbard or sheath. It can hold up to four two-handed weapons. Two one-handed or light melee weapons can fit in each two-handed weapon slot, for a maximum capacity of eight one-handed or light melee weapons. Only weapons designed to be used by creatures the same size as the wearer or smaller can be kept in a scabbard of many blades. The scabbard can't be used to store shields (even if they can be used to make melee attacks), gauntlets, improvised weapons, or wands, but can store rods (which are treated as one-handed weapons) and magic staves (which are treated as two-handed weapons).</p>
<p>When the wearer draws a weapon from the scabbard, if she does not lose her grip on it (keeping it in her hands at all times), as a move action she can have it switch places with another weapon in the scabbard. If the wearer has the <Link to="/feat/quick_draw">Quick Draw</Link> feat, she can do this as a swift action. If the wearer loses her grip on a weapon drawn from the scabbard, that weapon can't switch places with another weapon until it has been, sheathed in the scabbard of many blades and drawn again.</p>
<h3 id="magic-wondrous-scabbard_of_many_blades-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/secret_chest">secret chest</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _scabbard_of_pain = {title: "Scabbard of Pain", jsx: <><h2 id="magic-wondrous-scabbard_of_pain-scabbard-of-pain">Scabbard of Pain</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 269</Link><br/><strong>Aura</strong> faint necromancy; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 2,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>This rugged black leather scabbard is wrapped in jet black chains that allow it to easily be hung from one's belt. A scabbard of pain grants it bearer knowledge of advanced torturing techniques used by depraved cultists of the Midnight Lord. It grows or shrinks to fit any bladed weapon sized for a Medium or Small creature. Three times per day, the bearer can declare that he is attempting to deliver a painful strike with a melee attack. If the attack hits, the opponent must succeed at a DC 11 Fortitude save or be affected by <em>ray of sickening.</em> The bearer can expend one use of the scabbard's painful strike as an immediate action to affect himself with the <em>ray of sickening</em> effect and voluntarily fail the saving throw. Doing so allows the bearer to reroll a failed saving throw against a mind-affecting effect.</p>
<h3 id="magic-wondrous-scabbard_of_pain-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/ray_of_sickening">ray of sickening</Link>; <strong>Cost</strong> 1,250 gp</p>
</>};
const _scabbard_of_stanching = {title: "Scabbard of Stanching", jsx: <><h2 id="magic-wondrous-scabbard_of_stanching-scabbard-of-stanching">Scabbard of Stanching</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 318</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 309</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>This fine, red leather sheath is decorated with gold filigree. It fits any bladed slashing weapon. While worn, a scabbard of stanching protects against <Link to="/rule/bleed">bleed</Link> damage. Anytime the wearer suffers a bleed effect, the scabbard automatically stanches it. It has no effect on bleed damage from effects that require a DC 16 or higher caster level or <Link to="/skill/heal">Heal</Link> check.</p>
<h3 id="magic-wondrous-scabbard_of_stanching-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cure_light_wounds">cure light wounds</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _scabbard_of_the_efreet = {title: "Scabbard of the Efreet", jsx: <><h2 id="magic-wondrous-scabbard_of_the_efreet-scabbard-of-the-efreet">Scabbard of the Efreet</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 63</Link><br/><strong>Aura</strong> strong evocation; <strong>CL</strong> 12th<br/><strong>Slot</strong> none; <strong>Price</strong> 41,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>These black-and-red leather scabbards are produced in the distant Padishah Empire of Kelesh; in the Inner Sea region, they are predominantly found in Qadira. Each scabbard fits any bladed weapon, and has the bound essence of an <Link to="/monster/efreeti">efreeti</Link> within. Any weapon drawn from the scabbard gains the <Link to="/magic-enh/flaming">flaming</Link> weapon special ability for 5 rounds. Three times per day on command, the scabbard can impart the <Link to="/magic-enh/flaming_burst">flaming burst</Link> weapon special ability to a weapon drawn from it for 10 rounds.</p>
<p>Once per day, the wielder can summon a pyroclastic storm when drawing a weapon from the scabbard. Treat this as an <Link to="/spell/ice_storm">ice storm</Link> spell that deals fire damage instead of cold damage. The storm is centered on the location of the wielder, but doesn't harm or otherwise affect her.</p>
<h3 id="magic-wondrous-scabbard_of_the_efreet-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/fireball">fireball</Link>, <Link to="/spell/giant_form_i">giant form I</Link>, <Link to="/spell/scorching_ray">scorching ray</Link>; <strong>Cost</strong> 20,500 gp</p>
</>};
const _scabbard_of_the_lost_kiss = {title: "Scabbard of the Lost Kiss", jsx: <><h2 id="magic-wondrous-scabbard_of_the_lost_kiss-scabbard-of-the-lost-kiss">Scabbard of the Lost Kiss</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_temples">Inner Sea Temples pg. 52</Link><br/><strong>Aura</strong> faint evocation; <strong>CL</strong> 4th<br/><strong>Slot</strong> none; <strong>Price</strong> 8,600 gp; <strong>Weight</strong> 1 lb.</p>
<p>This aged and worn scabbard is believed to have once held one of a dozen legendary scimitar relics named <Link to="/magic-artifact/dawnflowers_kiss">Dawnflower's Kiss</Link>. From its prolonged proximity to such a divine blade, the scabbard has acquired its own unique magical abilities. Twice per day on command, the wearer can draw forth a blazing beam of red-hot fire from the scabbard that can be wielded as if it were a <Link to="/eq-weapon/scimitar">scimitar</Link>, as per <em>flame blade.</em></p>
<p>If <Link to="/faith/sarenrae">Sarenrae</Link> is the wearer's patron, half of the flame blade's damage is fire damage, but the other half results directly from divine power and is therefore not subject to being reduced by resistance to fire.</p>
<h3 id="magic-wondrous-scabbard_of_the_lost_kiss-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/flame_blade">flame blade</Link>, <Link to="/spell/flame_strike">flame strike</Link>; <strong>Cost</strong> 4,300 gp</p>
</>};
const _scabbard_of_true_death = {title: "Scabbard of True Death", jsx: <><h2 id="magic-wondrous-scabbard_of_true_death-scabbard-of-true-death">Scabbard of True Death</h2>
<p><strong>Sources</strong> <Link to="/source/magical_marketplace">Magical Marketplace pg. 25</Link><br/><strong>Aura</strong> faint necromancy; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 32,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>Whenever an <Link to="/pclass/assassin">assassin</Link> draws a weapon from the scabbard of true death and makes a successful death attack against her target, the DC of her true death ability increases by 4. In addition, regardless of whether the wielder has levels in the assassin class, the wielder gains the <Link to="/talent/bleeding_attack">bleeding attack</Link> rogue talent as though she had a sneak attack that dealt 1d6 points of damage (thus, attacks that qualify as sneak attacks deal 1 point of <Link to="/rule/bleed">bleed</Link> damage); if the wielder already has the bleeding attack rogue talent, the bleed damage caused by that talent is increased by 1.</p>
<h3 id="magic-wondrous-scabbard_of_true_death-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bestow_curse">bestow curse</Link>, creator must have the bleeding attack rogue talent; <strong>Cost</strong> 16,000 gp</p>
</>};
const _scabbard_of_vigor = {title: "Scabbard of Vigor", jsx: <><h2 id="magic-wondrous-scabbard_of_vigor-scabbard-of-vigor">Scabbard of Vigor</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 318</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 309</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 1,800 gp; <strong>Weight</strong> 3 lbs.</p>
<p>Once per day, as part of the action of drawing forth the weapon held by a scabbard of vigor, the wearer can order it to endow the weapon with an enhancement bonus on attack and damage rolls. The duration of the effect depends on the desired enhancement bonus for the weapon.</p>
<ScrollContainer id="magic-wondrous-scabbard_of_vigor--table-0"><table>
<thead>
<tr>
<th>Bonus</th>
<th>Duration</th>
</tr>
</thead>
<tbody><tr>
<td>+4</td>
<td>1 round</td>
</tr>
<tr>
<td>+3</td>
<td>3 rounds</td>
</tr>
<tr>
<td>+2</td>
<td>5 rounds</td>
</tr>
<tr>
<td>+1</td>
<td>10 rounds</td>
</tr>
</tbody></table></ScrollContainer>
<h3 id="magic-wondrous-scabbard_of_vigor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/greater_magic_weapon">greater magic weapon</Link>; <strong>Cost</strong> 900 gp</p>
</>};
const _scarab_of_khepri = {title: "Scarab of Khepri", jsx: <><h2 id="magic-wondrous-scarab_of_khepri-scarab-of-khepri">Scarab of Khepri</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_84_pyramid_of_the_sky_pharaoh">Pathfinder #84: Pyramid of the Sky Pharaoh pg. 61</Link>, <Link to="/source/osirion_land_of_the_pharaohs">Osirion, Land of the Pharaohs pg. 25</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 7,800 gp; <strong>Weight</strong> -</p>
<p>This small, blue figurine is fashioned in the likeness of a <Link to="/monster/scarab_beetle">scarab beetle</Link>, the sacred animal of <Link to="/faith/khepri">Khepri</Link>, the Ancient Osirian god of freedom, the rising sun, and work. Once per day, the bearer of the scarab can speak with vermin as if using <em>speak with animals,</em> though the information obtained is very limited. If the bearer has the <Link to="/ability/wild_empathy">wild empathy</Link> class feature, she may use it to influence vermin as easily as she influences animals. Once per day, the bearer can cast <em>summon swarm</em> to summon a swarm of scarab beetles (treat as a <Link to="/monster/spider_swarm">spider swarm</Link>, but instead of poison, the swarm causes <Link to="/disease/filth_fever">filth fever</Link>).</p>
<h3 id="magic-wondrous-scarab_of_khepri-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/vermin_heart">Vermin Heart</Link>, <Link to="/spell/speak_with_animals">speak with animals</Link>, <Link to="/spell/summon_swarm">summon swarm</Link>; <strong>Cost</strong> 3,900 gp</p>
</>};
const _scarecrow_lure = {title: "Scarecrow Lure", jsx: <><h2 id="magic-wondrous-scarecrow_lure-scarecrow-lure">Scarecrow Lure</h2>
<p><strong>Sources</strong> <Link to="/source/kobolds_of_golarion">Kobolds of Golarion pg. 31</Link><br/><strong>Aura</strong> faint illusion and transmutation; <strong>CL</strong> 1st<br/><strong>Slot</strong> none; <strong>Price</strong> 850 gp; <strong>Weight</strong> 40 lbs.</p>
<p>This life-sized scarecrow is garbed in old clothing and armor. At its center is the real skeleton of a former adventurer. A scarecrow lure is enchanted to writhe and cry out for help as if wounded. The lure's voice is usually that of the adventurer whose remains are inside, though the creator may choose any voice when creating the item. Anyone who hears or sees a scarecrow lure can attempt a DC 11 Will save to disbelieve the effect. Activating a scarecrow lure is a standard action that doesn't provoke attacks of opportunity.</p>
<h3 id="magic-wondrous-scarecrow_lure-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/mage_hand">mage hand</Link>, <Link to="/spell/ventriloquism">ventriloquism</Link>; <strong>Cost</strong> 450 gp</p>
</>};
const _scavengers_stone = {title: "Scavenger's Stone", jsx: <><h2 id="magic-wondrous-scavengers_stone-scavengers-stone">Scavenger's Stone</h2>
<p><strong>Sources</strong> <Link to="/source/goblins_of_golarion">Goblins of Golarion pg. 29</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 1st<br/><strong>Slot</strong> none; <strong>Price</strong> 2,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This jagged, egg-shaped stone emits a faint red glow when not in direct sunlight. By rubbing a scavenger's stone against a damaged (but not destroyed) construct or object as a full-round action, you repair 1d6 points of damage to the object or construct. If this brings a broken object's hit points above half its maximum hit points, it loses the <Link to="/misc/broken">broken</Link> condition. As a standard action, you can smash a scavenger's stone against a destroyed object or damaged construct. Doing so immediately repairs the object to full functionality or heals a damaged construct of 10d6 points of damage. Destroyed magic items can be repaired in this manner if their caster level is no higher than 3rd - more powerful destroyed magical items cannot be repaired by a scavenger's stone. A newly-created scavenger's stone has 50 charges - smashing a stone against an object uses up 10 charges.</p>
<h3 id="magic-wondrous-scavengers_stone-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/make_whole">make whole</Link>; <strong>Cost</strong> 1,000 gp</p>
</>};
const _school_of_eyes = {title: "School of Eyes", jsx: <><h2 id="magic-wondrous-school_of_eyes-school-of-eyes">School of Eyes</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 319</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 10th<br/><strong>Slot</strong> none; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> -</p>
<p>This item is a flask of syrupy fluid with an eyeball floating in it. When a creature drinks the entire flask, 1d4 rounds later he is <Link to="/misc/stunned">stunned</Link> for 1 round as 1d4+1 floating fish with large eyes for heads crawl out of his flesh. Once these eye-fish free themselves, they hover near the drinker, always staying in the drinker's square, and otherwise function as the eyes from a <em>prying eyes</em> spell, except they are Tiny rather than Fine. As long as the drinker has at least three of the fish in his square, he gains a +10 competence bonus on sight-based <Link to="/skill/perception">Perception</Link> checks. Every 1d6 &times; 10 minutes, 1d4+1 more eye-fish crawl out of his flesh, stunning him for 1 round each time. Each flask can produce up to 1d4+10 fish total; once this many have appeared, no more are created. The fish remain until they are destroyed or until 10 hours pass from the time the flask was used.</p>
<h3 id="magic-wondrous-school_of_eyes-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/prying_eyes">prying eyes</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _scope_of_stormsight = {title: "Scope of Stormsight", jsx: <><h2 id="magic-wondrous-scope_of_stormsight-scope-of-stormsight">Scope of Stormsight</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_96_shadow_of_the_storm_tyrant">Pathfinder #96: Shadow of the Storm Tyrant pg. 18</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 7th<br/><strong>Slot</strong> none; <strong>Price</strong> 18,000 gp; <strong>Weight</strong> 12 lbs.</p>
<p>This sight can be attached to a single direct-fire <Link to="/main/equipment_siege_engines">siege engine</Link>. When this is done, the sight becomes part of the siege engine, but can be removed from that siege engine with a full-round action. A character firing a siege engine that has this sight attached can look through the scope to see through magical and normal fog, mist, smoke, and similar obscurement, ignoring the miss chance for these obstructions. In addition, a character using this scope can choose to take a full-round action to either locate an invisible creature within line of sight or make a single shot that ignores the invisibility of a creature that she knows is in the area.</p>
<h3 id="magic-wondrous-scope_of_stormsight-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/hunters_eye">hunter's eye</Link>; <strong>Cost</strong> 9,000 gp</p>
</>};
const _scourge_vial = {title: "Scourge Vial", jsx: <><h2 id="magic-wondrous-scourge_vial-scourge-vial">Scourge Vial</h2>
<p><strong>Sources</strong> <Link to="/source/daughters_of_fury">Daughters of Fury pg. 62</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 1,200 gp; <strong>Weight</strong> -</p>
<p>Hurling this crystalline, ember-filled vial at an enemy causes the vessel to erupt in a burst of green smoke and burning ash that coalesces into a fire-blackened skull with burning eyes. Wreathed in oily, acrid smoke and trailing hot embers, the skull corkscrews around its target uttering biting insults and dire curses. The black smoke left in its wake causes watering eyes and wracking coughs.</p>
<p>When a scourge vial is thrown as a ranged touch attack, the skull torments any single struck creature of size Large or smaller. The skull moves with the target, distracting it in combat with its chaotic orbit. Any combatant in melee with the target is considered to be <Link to="/rule/flanking">flanking</Link> with the skull.</p>
<p>The skull's trailing smoke and embers cause the target (and any creature occupying the same square as the target) to become <Link to="/misc/dazzled">dazzled</Link>. Furthermore, each round, the target must succeed at a DC 14 Fortitude save or become <Link to="/misc/sickened">sickened</Link> by the smoke. Targets with the <Link to="/umr/scent">scent</Link> ability take a -4 penalty on their Fortitude saves. Creatures with the fire subtype are immune to the sickening effect. The skull and smoke dissipate in 5 rounds.</p>
<p>If an attack roll made to throw a scourge vial fails, the vial is treated as a <Link to="/rule/splash_weapon">splash weapon</Link> to determine where it lands instead. If there is creature of size Large or smaller in the resulting square, make a touch attack against that target. If that attack misses, or there is no valid target in that square, the skull shrieks harmlessly before dissipating.</p>
<h3 id="magic-wondrous-scourge_vial-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/pyrotechnics">pyrotechnics</Link>; <strong>Cost</strong> 600 gp</p>
</>};
const _scrap_collectors_strap = {title: "Scrap Collector's Strap", jsx: <><h2 id="magic-wondrous-scrap_collectors_strap-scrap-collectors-strap">Scrap Collector's Strap</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_armory_2">Adventurer's Armory 2 pg. 23</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> none; <strong>Price</strong> 500 gp; <strong>Weight</strong> -</p>
<p>When this leather strap is tied around the grip of a broken weapon, the user can ignore the effects of the <Link to="/misc/broken">broken</Link> condition on that weapon. If the weapon loses its remaining hit points, it is destroyed as normal. Tying or untying the strap is a full-round action.</p>
<h3 id="magic-wondrous-scrap_collectors_strap-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/mending">mending</Link>; <strong>Cost</strong> 250 gp</p>
</>};
const _scroll_of_blood_ink = {title: "Scroll of Blood Ink", jsx: <><h2 id="magic-wondrous-scroll_of_blood_ink-scroll-of-blood-ink">Scroll of Blood Ink</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 143</Link><br/><strong>Aura</strong> varies; <strong>CL</strong> varies<br/><strong>Slot</strong> none; <strong>Weight</strong> -</p>
<p>This scroll can seem to contain any spell. When the wielder attempts to cast the spell, the ink turns to blood and runs off the page, ruining the spell automatically. The scroll's edges turn sharp and cut the wielder's hands and wrists, dealing 4 points of <Link to="/rule/constitution_damage">Constitution</Link> <Link to="/rule/bleed">bleed</Link>. A successful DC 15 Reflex save halves the bleed. The bleed can be stopped with any magical healing or a successful DC 20 <Link to="/skill/heal">Heal</Link> check.</p>
<h3 id="magic-wondrous-scroll_of_blood_ink-construction">Construction</h3>
<p><strong>Requirements</strong> any scroll; <strong>Cost</strong> -</p>
</>};
const _sea_silk_shell = {title: "Sea Silk Shell", jsx: <><h2 id="magic-wondrous-sea_silk_shell-sea-silk-shell">Sea Silk Shell</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 26</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> none; <strong>Price</strong> 4,500 gp; <strong>Weight</strong> 1/2 lb.</p>
<p>This small clamshell magically contains a 300-square-foot sheet of sea silk, which is an extremely fine, valuable, and strong fabric woven from the filaments of pen shells. The sea silk has hardness 10 and 15 hit points, and it cannot be ruined by exposure to water or other mundane means (though spells that target it still work as normal).</p>
<p>As a standard action the shell's user can speak a command word and pull the silk sheet from the shell in one of three different forms chosen at that time. The silk can emerge as 60 squares of sails ready to be installed (enough to propel most Colossal or smaller water vehicles), which can be magically treated as normal. Alternatively, the silk can emerge as up to 15 total <Link to="/eq-misc/nobles_outfit">noble's outfits</Link> or <Link to="/eq-misc/royal_outfit">royal outfits</Link> in any style and color the user wishes. As a third option, the silk can emerge as an unaltered sheet that can be cut and sewn as normal into any objects that could be made from cloth, except that the silk cannot be used to create weapons or functional armor. Once the silk has been pulled from the shell, the shell remains empty until the silk is returned to it or destroyed.</p>
<p>Once adjacent to the shell, the outfits, sheet of silk, or sails can be placed back into the shell with a second command word. (If the sheet was cut into pieces, all pieces must be adjacent to the shell before the silk can be returned.) Any damage to the silk or items made from it are undone by returning the cloth to the shell. If the silk or any items made from it are destroyed, the sea silk shell remains inert for a week as it regenerates the cloth from scratch, after which the shell can be used again as normal.</p>
<h3 id="magic-wondrous-sea_silk_shell-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/minor_creation">minor creation</Link>; <strong>Cost</strong> 2,250 gp</p>
</>};
const _secure_paypack = {title: "Secure Paypack", jsx: <><h2 id="magic-wondrous-secure_paypack-secure-paypack">Secure Paypack</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_temples">Inner Sea Temples pg. 32</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> none; <strong>Price</strong> 4,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This rugged backpack is identical to a <Link to="/magic-wondrous/handy_haversack">handy haversack</Link> in most regards, with numerous compartments for storing items. Any effort to identify it with a <Link to="/skill/spellcraft">Spellcraft</Link> check result ranging from 24 to 33 by someone unfamiliar with its special properties reveals it to be a handy haversack. A result below 24 does not identify any magic properties, while a result of 34 or higher reveals its additional secret properties. It has two hidden compartments (<Link to="/skill/perception">Perception</Link> DC 35), each able to store up to 1 cubic foot of material or 10 pounds in weight. In addition, the entire item is reinforced with thin <Link to="/eq-material/mithral">mithral</Link> fibers, giving it a hardness of 15 and 5 hit points. Each compartment has a concealed <Link to="/eq-misc/superior_lock">superior lock</Link> (Perception DC 35, <Link to="/skill/disable_device">Disable Device</Link> DC 40) built in to prevent unauthorized access. When a compartment is locked, an item can still be removed from it as a move action by a character who has a key to the lock, like a normal handy haversack. The keys are not magical and can be crafted (<Link to="/skill/craft">Craft</Link> DC 25) by a character able to disable the existing locks and who has at least 5 ranks in Craft (locks). Each secure paypack is normally created with two keys.</p>
<h3 id="magic-wondrous-secure_paypack-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/arcane_lock">arcane lock</Link>, <Link to="/spell/knock">knock</Link>, <Link to="/spell/secret_chest">secret chest</Link>; <strong>Cost</strong> 2,000 gp</p>
</>};
const _see_invisibility_sight = {title: "See Invisibility Sight", jsx: <><h2 id="magic-wondrous-see_invisibility_sight-see-invisibility-sight">See Invisibility Sight</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 143</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 8th<br/><strong>Slot</strong> none (see below); <strong>Price</strong> 12,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This sight can be attached to a single two-handed firearm. When this is done, the sight becomes part of the weapon, but can be removed from that weapon with a full-round action. A firearm wielder using a firearm that has this sight can choose to spend a full-round action to either locate an invisible creature within line of sight or make a single shot that ignores the invisibility of a creature that she knows is in the area.</p>
<h3 id="magic-wondrous-see_invisibility_sight-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/true_seeing">true seeing</Link>; <strong>Cost</strong> 6,000 gp</p>
</>};
const _seekers_sight = {title: "Seeker's Sight", jsx: <><h2 id="magic-wondrous-seekers_sight-seekers-sight">Seeker's Sight</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 319</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 8th<br/><strong>Slot</strong> none; <strong>Price</strong> 12,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This sight can be attached to a single two-handed firearm. When this is done, the sight becomes part of the weapon, but can be removed from that weapon with a full-round action. A firearm wielder using a firearm that has this sight can choose to spend a full-round action to either locate an invisible creature within line of sight or make a single shot that ignores the invisibility of a creature that she knows is in the area.</p>
<h3 id="magic-wondrous-seekers_sight-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/true_seeing">true seeing</Link>; <strong>Cost</strong> 6,000 gp</p>
</>};
const _seeking_lens = {title: "Seeking Lens", jsx: <><h2 id="magic-wondrous-seeking_lens-seeking-lens">Seeking Lens</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_131_the_reapers_right_hand">Pathfinder #131: The Reaper's Right Hand pg. 33</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 11th<br/><strong>Slot</strong> none; <strong>Price</strong> 20,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This telescope is adjustable as a full-round action, allowing magnifications anywhere from &times;2 to &times;250. The user gains a +5 competence bonus on <Link to="/skill/knowledge_geography">Knowledge (geography)</Link> and <Link to="/skill/perception">Perception</Link> checks when using the device to study planets, stars, and other celestial bodies.</p>
<p>As a full-round action, the user can press the two lenses together, compressing the device to a small assayer's lens small enough to occupy the eyes slot. In this form, the lens grants a +5 competence bonus on <Link to="/skill/appraise">Appraise</Link> checks, <Link to="/skill/perception">Perception</Link> checks, and <Link to="/skill/survival">Survival</Link> checks to follow tracks. Once per week, after studying the possessions or tracks of a creature, the wearer may designate that creature as his quarry. This functions as the <Link to="/class/ranger">ranger's</Link> quarry ability. If the wearer already has the quarry ability, the lens instead allows him to designate a creature as his quarry even if it is not one of his <Link to="/ability/favored_enemies">favored enemies</Link>.</p>
<h3 id="magic-wondrous-seeking_lens-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/clairaudience_clairvoyance">clairaudience/clairvoyance</Link>, <Link to="/spell/true_seeing">true seeing</Link>; <strong>Cost</strong> 10,000 gp</p>
</>};
const _seers_tea = {title: "Seer's Tea", jsx: <><h2 id="magic-wondrous-seers_tea-seers-tea">Seer's Tea</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 319</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 3rd<br/><strong>Slot</strong> none; <strong>Price</strong> 550 gp; <strong>Weight</strong> -</p>
<p>This rich tea can be made from any number of herbs. When the tea is brewed without a filter and imbibed, the drinker can read the patterns in the leaves remaining at the bottom of her cup, gaining the benefits of an <em>augury</em> spell.</p>
<p>Additionally, the unbrewed tea can be used as an extra material component when casting <em>augury,</em> removing the need for a focus. In this case, the caster instead reveals information as if she had cast <em>divination</em> instead.</p>
<h3 id="magic-wondrous-seers_tea-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/augury">augury</Link> or <Link to="/spell/divination">divination</Link>; <strong>Cost</strong> 275 gp</p>
</>};
const _seishinru_spirit_elixir = {title: "Seishinru, Spirit Elixir", jsx: <><h2 id="magic-wondrous-seishinru_spirit_elixir-seishinru-spirit-elixir">Seishinru, Spirit Elixir</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_54_the_empty_throne">Pathfinder #54: The Empty Throne pg. 61</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 10th<br/><strong>Slot</strong> none; <strong>Price</strong> 5,500 gp; <strong>Weight</strong> -</p>
<p>This potent elixir has the consistency and color of pomegranate juice, and a tart taste with a faint aroma of fresh fruit. Usually found in bamboo containers decorated with images of carp, the sacred animal of the goddess <Link to="/faith/shizuru">Shizuru</Link>, the elixir within contains the distilled spiritual essence of the most honorable guardians who died in service to Minkai's emperors. Each time the character drinking the elixir makes an attack roll, ability check, or skill check, it rolls two d20s and takes the better result, as these spiritual guardians offer their advice and encouragement. This effect lasts for 10 rounds, but it immediately ends if any roll is a natural 20. If the character drinking the elixir is a scion of one of Minkai's five imperial families (including anyone invested as such by an Imperial Seal) and is reduced to fewer than 0 hit points during the duration of the elixir's effects, the elixir also immediately cures the drinker of 5d8+10 points of damage, which can bring a recently slain character back to life. This healing immediately ends any of the elixir's other effects.</p>
<h3 id="magic-wondrous-seishinru_spirit_elixir-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/breath_of_life">breath of life</Link>, <Link to="/spell/brilliant_inspiration">brilliant inspiration</Link>; <strong>Cost</strong> 2,750 gp</p>
</>};
const _senate_aid_badge = {title: "Senate Aid Badge", jsx: <><h2 id="magic-wondrous-senate_aid_badge-senate-aid-badge">Senate Aid Badge</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_127_crownfall">Pathfinder #127: Crownfall pg. 11</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 9th<br/><strong>Slot</strong> none; <strong>Price</strong> 1,500 gp; <strong>Weight</strong> -</p>
<p>This brooch features the heraldry of a Taldan noble family, marking the wearer as an aide to the associated senator. All senate aide badges are part of a set, attuned to a single master senator badge during their creation. A creature wearing the pinned brooch can receive telepathic communications sent from the wearer of the master senator badge. Once the wearer of the senate aide badge receives a message, she has 1 minute to send a telepathic reply of up to 25 words. Sending a reply requires a full-round action of concentration. The wearer of the master senator badge can send up to 10 telepathic messages per day, targeting either a specific badge or broadcasting to all badge wearers, and knows the approximate direction and distance to all wearers of senate aid badges attuned to the master badge.</p>
<p>Senate aide badges are often further enchanted with emergency effects that mimic the <Link to="/spell/contingency">contingency</Link> spell, whisking endangered staff to safety or casting protective magic. The exact conditions and effects vary, and their cost is added the badge's construction cost.</p>
<h3 id="magic-wondrous-senate_aid_badge-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/sending">sending</Link>, <Link to="/spell/status">status</Link>; <strong>Cost</strong> 750 gp</p>
</>};
const _seven_sided_coin = {title: "Seven-Sided Coin", jsx: <><h2 id="magic-wondrous-seven_sided_coin-seven-sided-coin">Seven-Sided Coin</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_runescars_4">Pathfinder Runescars #4 pg. 27</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 9th<br/><strong>Slot</strong> none; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> -</p>
<p>This brass coin is smooth on both faces. Once per week when touched to a creature, it affects that creature with a <em>mark of justice</em> (CL 9th). The user chooses the behavior that activates the mark, but it must be one of the seven deadly sins (greed, lust, pride, gluttony, envy, wrath, or sloth).</p>
<h3 id="magic-wondrous-seven_sided_coin-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/mark_of_justice">mark of justice</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _shackles_ensign = {title: "Shackles Ensign", jsx: <><h2 id="magic-wondrous-shackles_ensign-shackles-ensign">Shackles Ensign</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_57_tempest_rising">Pathfinder #57: Tempest Rising pg. 58</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 10th<br/><strong>Slot</strong> none; <strong>Price</strong> 10,800 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This red-and-black naval ensign displays the grinning skull and crossed manacles of the Shackles. While the flag feels as sleek as silk, the material is stronger than the toughest sail canvas. Openly flying a Shackles ensign improves the initial attitude of most hostile or unfriendly pirates by one step, and worsens the starting attitude of those opposed to piracy by one step. The ensign has no effect when not properly mounted on a ship.</p>
<p>Once per day, a Shackles ensign can be hoisted and unfurled on a ship to impose a sinister sense of doom upon an opposing ship's crew. It takes two full-round actions to raise the flag. All non-pirate creatures (defined at the GM's discretion) within 300 feet who are able to see the flag take a -1 penalty on attack rolls, weapon damage rolls, saving throws, and skill checks for 1 minute. This is a visual mind-affecting effect. In addition, all allied creatures aboard the ship flying the Shackles ensign gain a +1 luck bonus on attack rolls, weapon damage rolls, saving throws, and skill checks for 1 minute.</p>
<h3 id="magic-wondrous-shackles_ensign-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/prayer">prayer</Link>; <strong>Cost</strong> 5,400 gp</p>
</>};
const _shadow_hand_smoke_pellet = {title: "Shadow Hand Smoke Pellet", jsx: <><h2 id="magic-wondrous-shadow_hand_smoke_pellet-shadow-hand-smoke-pellet">Shadow Hand Smoke Pellet</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 251</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> none; <strong>Price</strong> 800 gp; <strong>Weight</strong> -</p>
<p>This delicate metallic shell contains two sets of volatile alchemical substances, similar to those used in <Link to="/eq-misc/smoke_pellet">smoke pellets</Link>. When the sphere is broken, the substances mingle and fill a 10-foot cube with a cloud of dark gray smoke that lasts for 1 minute. The user can throw the pellet as a ranged touch attack with an increment of 10 feet. Partially tangible hands of smoke accost creatures in the cloud. These hands attempt to <Link to="/rule/grapple">grapple</Link> anyone moving through the smoke (CMB +7). Upon successfully grappling an opponent, the hands attempt to maintain the grapple every round until the smoke dissipates.</p>
<h3 id="magic-wondrous-shadow_hand_smoke_pellet-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/black_tentacles">black tentacles</Link>, <Link to="/spell/obscuring_mist">obscuring mist</Link>; <strong>Cost</strong> 400 gp</p>
</>};
const _shadow_stylus = {title: "Shadow Stylus", jsx: <><h2 id="magic-wondrous-shadow_stylus-shadow-stylus">Shadow Stylus</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_136_temple_of_the_peacock_spirit">Pathfinder #136: Temple of the Peacock Spirit pg. 54</Link><br/><strong>Aura</strong> strong illusion; <strong>CL</strong> 12th<br/><strong>Slot</strong> none; <strong>Price</strong> 48,000 gp; <strong>Weight</strong> -</p>
<p>A shadow stylus can create a doorway between the Material Plane and the <Link to="/rule/shadow_plane">Shadow Plane</Link>. To do so, the user must prick a bit of skin with the stylus's pointed end, anointing it with a drop of blood from a living creature. The user must then use the shadowy chalk held in the stylus's other end to inscribe a doorway on a solid surface in an area of dim light. Doing so requires 1d4 rounds of work and, once completed, fashions a portal like that created by a <Link to="/spell/gate">gate</Link> spell, linking the Material Plane and the Shadow Plane. The destinations on both planes must overlap - to create a portal to Shadow Absalom, for example, the user would have to create the doorway from the Material Plane in Absalom. The portal created closes 1 minute after it is created.</p>
<p>As long as a creature carries a shadow stylus on her person, she gains a +2 bonus on saving throws against spells of the shadow subschool and against all special attacks created by <Link to="/family/kyton">kytons</Link>, <Link to="/monster/shadow">shadows</Link>, and other creatures native to the Shadow Plane. In addition, the character can see on the Shadow Plane as if that realm were <Link to="/rule/vision_and_light">brightly lit</Link>. A shadow stylus has 6 uses when it is created. Once it is used to create a sixth portal, the stylus loses its ability to craft new portals but retains its protective qualities.</p>
<h3 id="magic-wondrous-shadow_stylus-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/shadow_walk">shadow walk</Link>; <strong>Cost</strong> 24,000 gp</p>
</>};
const _shadow_well = {title: "Shadow Well", jsx: <><h2 id="magic-wondrous-shadow_well-shadow-well">Shadow Well</h2>
<p><strong>Sources</strong> <Link to="/source/classic_treasures_revisited">Classic Treasures Revisited pg. 61</Link><br/><strong>Aura</strong> strong conjuration; <strong>CL</strong> 17th<br/><strong>Slot</strong> none; <strong>Price</strong> 82,000 gp; <strong>Weight</strong> -</p>
<p>Rather than opening to random locations across the planes, this version of the <Link to="/magic-wondrous/well_of_many_worlds">well of many worlds</Link> opens only to random locations on the Shadow Plane (or random locations on the Material Plane when on the Shadow Plane). Regardless of which plane the user opens the well from, there is a 15% chance it randomly diverts the user into the Ethereal Plane, given its nature as a natural buffer between the two realities.</p>
<h3 id="magic-wondrous-shadow_well-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/gate">gate</Link>, <Link to="/spell/shadow_walk">shadow walk</Link>; <strong>Cost</strong> 41,000 gp</p>
</>};
const _shadowblood = {title: "Shadowblood", jsx: <><h2 id="magic-wondrous-shadowblood-shadowblood">Shadowblood</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_74_sword_of_valor">Pathfinder #74: Sword of Valor pg. 63</Link><br/><strong>Aura</strong> moderate evocation [evil]; <strong>CL</strong> 9th<br/><strong>Slot</strong> none; <strong>Price</strong> 1,500 gp; <strong>Weight</strong> -</p>
<p>Shadowblood is among the most notorious of drugs - a fluid infused with a <Link to="/monster/shadow_demon">shadow demon's</Link> essence. Anyone who drinks this substance must succeed at a DC 20 Fortitude save or take 1d6 points of cold damage and 1d4 points of <Link to="/rule/wisdom_damage">Wisdom damage</Link>, and become <Link to="/misc/nauseated">nauseated</Link> for 1d6 rounds. Thereafter, the target gains 1d10+5 temporary hit points, cold resistance 5, and darkvision 60 feet. These effects persist for 1 hour, during which demons take a -4 penalty on saving throws against the drinker's spells and spell-like abilities of the shadow subschool.</p>
<p>Shadowblood is exceedingly addictive and carries some significant disadvantages. Each time a creature takes a dose of shadowblood, it must succeed at a DC 20 Fortitude save or become addicted - shadowblood addiction is a <Link to="/rule/addiction">severe addiction</Link>. A creature under the influence of shadowblood or suffering from shadowblood addiction takes a -4 penalty on all saving throws against possession type effects made by demons, and can never gain the benefits of <Link to="/spell/protection_from_evil">protection from evil</Link> or similar spells against such effects.</p>
<h3 id="magic-wondrous-shadowblood-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/desecrate">desecrate</Link>, <Link to="/spell/shadow_evocation">shadow evocation</Link>, creator must be a shadow demon or must have the cooperation of a shadow demon; <strong>Cost</strong> 750 gp</p>
</>};
const _shard_of_psychic_power_1st_level = {title: "Shard of Psychic Power (1st-level)", jsx: <><h2 id="magic-wondrous-shard_of_psychic_power_1st_level-shard-of-psychic-power">Shard of Psychic Power</h2>
<p><strong>Sources</strong> <Link to="/source/psychic_anthology">Psychic Anthology pg. 9</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 17th<br/><strong>Slot</strong> none; <strong>Price</strong> 1,000 gp (1st-level), 4,000 gp (2nd-level), 9,000 gp (3rd-level), 16,000 gp (4th-level), 25,000 gp (5th-level), 36,000 gp (6th-level), 49,000 gp (7th-level), 64,000 gp (8th-level), 81,000 gp (9th-level); <strong>Weight</strong> -</p>
<p>This shard of quartz is roughly the size of a human finger and covered in flowing sigils. It contains the knowledge of a psychic spell (chosen by the creator when the item is crafted). If the bearer is a psychic spellcaster and has that spell on her class spell list, she can use her spell slots to cast that spell as if it were one of her spells known. A shard of psychic power is priced based on the spell's psychic spell level. If the spell does not appear on the <Link to="/main/spells_psychic">psychic's spell list</Link>, it is based on the highest spell level it has on any other spell list. For example, a spell that is on the 1st-level medium list and the 2nd-level spiritualist list is priced as a 2nd-level spell.</p>
<h3 id="magic-wondrous-shard_of_psychic_power_1st_level-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, creator must be able to cast the spell contained in the shard; <strong>Cost</strong> 500 gp (1st-level), 2,000 gp (2nd-level), 4,500 gp (3rd-level), 8,000 gp (4th-level), 12,500 gp (5th-level), 18,000 gp (6th-level), 24,500 gp (7th-level), 32,000 gp (8th-level), 40,500 gp (9th-level)</p>
</>};
const _sheath_of_bladestealth = {title: "Sheath of Bladestealth", jsx: <><h2 id="magic-wondrous-sheath_of_bladestealth-sheath-of-bladestealth">Sheath of Bladestealth</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 319</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 309</Link><br/><strong>Aura</strong> faint illusion; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>This mundane-looking but serviceable sheath fits any bladed slashing weapon, from a dagger to a greatsword. When a weapon is placed into the sheath of bladestealth, both it and the weapon become invisible (as the <em>invisibility</em> spell) until the weapon is drawn, at which point it and the sheath become visible again. The invisible sheathed weapon can still be detected by touch, but the bearer gains a +5 bonus on <Link to="/skill/sleight_of_hand">Sleight of Hand</Link> checks to conceal the weapon, and casual inspection does not reveal it at all. Other effects that detect or reveal invisible things work normally on the sheathed weapon.</p>
<h3 id="magic-wondrous-sheath_of_bladestealth-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/invisibility">invisibility</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _shell_of_sending = {title: "Shell of Sending", jsx: <><h2 id="magic-wondrous-shell_of_sending-shell-of-sending">Shell of Sending</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_124_city_in_the_deep">Pathfinder #124: City in the Deep pg. 56</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 7th<br/><strong>Slot</strong> none; <strong>Price</strong> 12,200 gp; <strong>Weight</strong> -</p>
<p>This conch shell measures only a few inches long and shimmers with a delicate pink color. Shells of sending always come in pairs, with each shell attuned to the other. If pairs are mixed up or lost, a shell of sending can be attuned to a new shell of sending in a process that takes 24 hours.</p>
<p>Once per day, anyone holding a shell of sending can whisper up to 25 words into the shell. The sender's words emerge from the second shell, audible to anyone holding the attuned shell, as long as the receiver is on the same plane of existence. If the receiver wishes, she can send a return message of up to 25 words.</p>
<p>Anyone eavesdropping on either sender or receiver must attempt a DC 14 Will saving throw. On a success, an eavesdropper can hear the speakers normally. On a failure, the speakers seem to be relaying gibberish and nonsense words to each other. Creatures who fail this saving throw by 5 or more are <Link to="/misc/deafened">deafened</Link> for 1d4 minutes.</p>
<h3 id="magic-wondrous-shell_of_sending-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/sending">sending</Link>; <strong>Cost</strong> 6,100 gp</p>
</>};
const _shield_of_countless_causes = {title: "Shield of Countless Causes", jsx: <><h2 id="magic-wondrous-shield_of_countless_causes-shield-of-countless-causes">Shield of Countless Causes</h2>
<p><strong>Sources</strong> <Link to="/source/faiths_and_philosophies">Faiths and Philosophies pg. 31</Link><br/><strong>Aura</strong> faint enchantment; <strong>CL</strong> 5th<br/><strong>Slot</strong> shield; <strong>Price</strong> 11,157 gp; <strong>Weight</strong> 10 lbs.</p>
<p>Dozens of pages of scripture cover the face of this +2 <Link to="/eq-armor/heavy_wooden_shield">heavy wooden shield</Link>, each detailing in word or illustration the tenets of a knightly order. While worn or carried, the shield acts like a <Link to="/magic-wondrous/phylactery_of_faithfulness">phylactery of faithfulness</Link>, except that it only functions for actions that would violate the edicts of the wearer's <Link to="/ability/orders">cavalier order</Link>. A newly created shield of countless causes has 5 charges. By expending 1 charge and studying the shield's texts for 10 minutes, the wielder can regain the use of his order abilities as if 24 hours had passed. By expending 3 charges and studying the shield's texts for 8 hours, the wielder can change his order. When the last charge is used, the shield remains a +2 heavy wooden shield.</p>
<h3 id="magic-wondrous-shield_of_countless_causes-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/atonement">atonement</Link>; <strong>Cost</strong> 5,657 gp</p>
</>};
const _shoanti_war_paint_blue = {title: "Shoanti War Paint (Blue)", jsx: <><h2 id="magic-wondrous-shoanti_war_paint_blue-shoanti-war-paint">Shoanti War Paint</h2>
<p><strong>Sources</strong> <Link to="/source/curse_of_the_crimson_throne">Curse of the Crimson Throne pg. 436</Link>, <Link to="/source/pathfinder_10_a_history_of_ashes">Pathfinder #10: A History of Ashes pg. 14</Link><br/><strong>Aura</strong> moderate (school varies<sup><InnerLink showBacklink="backlink-magic-wondrous-shoanti_war_paint_blue-ref-S-1" id="magic-wondrous-shoanti_war_paint_blue-ref-S-1" data-hash-target to="magic-wondrous-shoanti_war_paint_blue-S">1</InnerLink></sup>); <strong>CL</strong> 7th<br/><strong>Slot</strong> none; <strong>Price</strong> 900 gp (Blue, Green, Orange, Red, Silver, and Yellow), 1,800 gp (Black and White); <strong>Weight</strong> -</p>
<p>The Shoanti have developed numerous types of magical war paint, each providing a specific benefit to aid their hunters, warriors, and heroes in a variety of tasks. Shoanti war paint can be applied to any visible part of the body - typically the face, shoulders, legs, or arms. Applying a dose of war paint is a full-round action that provokes an attack of opportunity. Shoanti war paint does not take up a magic item slot, but you can benefit from only one color of Shoanti war paint at a time and applying a dose of a different color replaces the effects of the previous application. Once Shoanti war paint is applied, its effects last for 24 hours. Below are the eight most common colors and their effects.</p>
<ul>
<li><strong>Black (1,800 gp):</strong> The wearer becomes cloaked in shadows and smoke, gaining the effects of a <Link to="/spell/blur">blur</Link> spell.</li>
<li><strong>Blue (900 gp):</strong> The wearer gains a 30-foot enhancement bonus to her base move speed.</li>
<li><strong>Green (900 gp):</strong> When the wearer uses <Link to="/ability/bardic_performance">bardic performance</Link> to <Link to="/performance/inspire_courage">inspire courage</Link>, the morale bonus she grants increases by 1.</li>
<li><strong>Orange (900 gp):</strong> The wearer gains damage reduction 1/-. This effect stacks with damage reduction gained via a character class, such as <Link to="/class/barbarian">barbarian</Link>.</li>
<li><strong>Red (900 gp):</strong> The wearer gains fire resistance 10.</li>
<li><strong>Silver (900 gp):</strong> The wearer gains a +3 deflection bonus to her AC.</li>
<li><strong>White (1,800 gp):</strong> The wearer gains a +4 resistance bonus on all saving throws against <Link to="/umr/energy_drain">energy drain</Link> and negative energy. As soon as the wearer takes a <Link to="/rule/negative_level">negative level</Link> from an energy drain attack, the white war paint absorbs the negative level and then fades away, ending the ongoing duration of the paint's effect immediately.</li>
<li><strong>Yellow (900 gp):</strong> The wearer gains a +5 competence bonus on <Link to="/skill/perception">Perception</Link> checks.</li>
</ul>
<h3 id="magic-wondrous-shoanti_war_paint_blue-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>; <Link to="/spell/blur">blur</Link> (black), <Link to="/spell/clairaudience_clairvoyance">clairaudience/clairvoyance</Link> (yellow), <Link to="/spell/death_ward">death ward</Link> (white), <Link to="/spell/expeditious_retreat">expeditious retreat</Link> (blue), <Link to="/spell/heroism">heroism</Link> (green), <Link to="/spell/resist_energy">resist energy</Link> (red), <Link to="/spell/shield_of_faith">shield of faith</Link> (silver), <Link to="/spell/stoneskin">stoneskin</Link> (orange); <strong>Cost</strong> 900 gp (black and white paint), 450 gp (all other paints)</p>
<section data-footnotes>
<h3 id="magic-wondrous-shoanti_war_paint_blue-label">Footnotes</h3>
<ol>
<li id="magic-wondrous-shoanti_war_paint_blue-S">
<p>There are no official sources as to which school auras each color has. As a non-official suggestion based on the spells required: black is illusion; yellow is divination; white is necromancy; blue is transmutation; green is enchantment; and red, orange, and silver are abjuration. <InnerLink id="backlink-magic-wondrous-shoanti_war_paint_blue-ref-S-1" data-hash-target to="magic-wondrous-shoanti_war_paint_blue-ref-S-1" aria-label="Back to reference S-1">↩</InnerLink></p>
</li>
</ol>
</section>
</>};
const _shrinking_berries = {title: "Shrinking Berries", jsx: <><h2 id="magic-wondrous-shrinking_berries-shrinking-berries">Shrinking Berries</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 25</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 300 gp; <strong>Weight</strong> -</p>
<p>These berries cause animals that eat them to transform into smaller and far less dangerous versions of themselves, as per the spell <em>pup shape</em> (Fortitude DC 14 negates), except other creatures do not need to attempt Will saves to attack the transformed animal and the effect lasts for 24 hours. These berries can be concealed in meat or other typical foods of an animal's diet.</p>
<h3 id="magic-wondrous-shrinking_berries-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/pup_shape">pup shape</Link>; <strong>Cost</strong> 150 gp</p>
</>};
const _shroud_of_disintegration = {title: "Shroud of Disintegration", jsx: <><h2 id="magic-wondrous-shroud_of_disintegration-shroud-of-disintegration">Shroud of Disintegration</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 319</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 11th<br/><strong>Slot</strong> none; <strong>Price</strong> 3,300 gp; <strong>Weight</strong> 10 lbs.</p>
<p>These burial wrappings are made of fine, embroidered materials. When a body is placed inside, speaking a command word turns the body to dust. The magic of the shroud is usable only once, after which the wrappings become ordinary, fine cloth.</p>
<h3 id="magic-wondrous-shroud_of_disintegration-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/disintegrate">disintegrate</Link>; <strong>Cost</strong> 1,650 gp</p>
</>};
const _shrouded_demise = {title: "Shrouded Demise", jsx: <><h2 id="magic-wondrous-shrouded_demise-shrouded-demise">Shrouded Demise</h2>
<p><strong>Sources</strong> <Link to="/source/heaven_unleashed">Heaven Unleashed pg. 55</Link><br/><strong>Aura</strong> faint necromancy, strong evil; <strong>CL</strong> 3rd<br/><strong>Slot</strong> none; <strong>Price</strong> 4,410 gp; <strong>Weight</strong> -</p>
<p>This wand of <em>death knell</em> (49 charges) is made of wood but carved to appear as though it were tightly wrapped in several veils.</p>
<h3 id="magic-wondrous-shrouded_demise-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wand">Craft Wand</Link>, <Link to="/spell/death_knell">death knell</Link>; <strong>Cost</strong> 2,250 gp</p>
</>};
const _sigil_chalk = {title: "Sigil Chalk", jsx: <><h2 id="magic-wondrous-sigil_chalk-sigil-chalk">Sigil Chalk</h2>
<p><strong>Sources</strong> <Link to="/source/magic_tactics_toolbox">Magic Tactics Toolbox pg. 18</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 7th<br/><strong>Slot</strong> none; <strong>Price</strong> 2,000 gp; <strong>Weight</strong> -</p>
<p>This short stick of grayish chalk is flecked with <Link to="/eq-material/mithral">mithral</Link>. When the chalk's bearer succeeds at a Knowledge check to identify a monster's special powers or vulnerabilities, he can take a standard action to draw a 1-foot-wide runic shape in the air that represents the monster's type. This rune floats around the user's head for 1 hour, moving with the user. The hovering rune provides the user a +1 insight bonus on attack rolls and skill checks against creatures of the type represented by the rune. It doesn't impair the user's vision or movement in any way. The rune cannot be harmed by physical attacks, but <Link to="/spell/dispel_magic">dispel magic</Link>, <Link to="/spell/disintegrate">disintegrate</Link>, a <Link to="/magic-artifact/sphere_of_annihilation">sphere of annihilation</Link>, or a <Link to="/magic-rod/rod_of_cancellation">rod of cancellation</Link> affects it. A rune's Armor Class against touch attacks is equal to 10 + the user's Dexterity modifier.</p>
<p>If the user fails an attack roll or skill check against a creature of the type represented by his hovering rune, he can dismiss the rune as an immediate action to gain a +2d4 competence bonus on the attack roll or skill check retroactively, which may turn the failure into a success. Each stick of sigil chalk may be used to draw five runes. A single user can have a number of hovering runes equal to his Intelligence modifier (minimum 1) simultaneously, but each must represent a different creature type.</p>
<h3 id="magic-wondrous-sigil_chalk-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/gallant_inspiration">gallant inspiration</Link>, <Link to="/spell/true_strike">true strike</Link>; <strong>Cost</strong> 1,000 gp</p>
</>};
const _silent_aviary = {title: "Silent Aviary", jsx: <><h2 id="magic-wondrous-silent_aviary-silent-aviary">Silent Aviary</h2>
<p><strong>Sources</strong> <Link to="/source/lost_treasures">Lost Treasures pg. 53</Link><br/><strong>Aura</strong> strong (all schools); <strong>CL</strong> 20th<br/><strong>Slot</strong> none; <strong>Price</strong> 195,000 gp; <strong>Weight</strong> -</p>
<p>The Silent Aviary is a unique <Link to="/eq-misc/harrow_deck">harrow deck</Link> that features beautiful artwork of songbirds on each card. Anyone who counts the cards while looking at the illustrated fronts sees that the deck has 54 cards. Counting the cards while looking at their backs, however, always produces a card count of 55. The mysterious 55th card is the accursed Cage.</p>
<p>The Silent Aviary functions identically to a standard <Link to="/magic-artifact/harrow_deck_of_many_things">Harrow Deck of Many Things</Link>, except only a single character can draw from it each day, and only a single card can be drawn (although cards that allow or require redraws still function normally). The <em>deck of many things</em> can be used to model it instead if preferred (though its total card count is 22 rather than 54). However, unlike most harrow decks, the Silent Aviary offers its user a unique advantage: at any time during the drawing process, the user of the Silent Aviary may choose to immediately replace a drawn card. To do so, the user must simply utter a command phrase, put the rejected card back in the deck, and draw a new card to replace it. Only the effects of the replacement card are realized. However, every time a user rejects a card, he risks replacing it with the Cage card.</p>
<p>Every time a user utters the command phrase, he must attempt a DC 20 Will saving throw. If successful, the user replaces the rejected card as detailed above. However, if he fails the Will saving throw, the replacement card automatically comes up as the Cage. In this instance, the user is sucked into the card, as if she had fallen into a <Link to="/magic-wondrous/bag_of_holding">bag of holding</Link>. The user is then trapped in an extradimensional space that contains 250 cubic feet of space, 24 hours worth of breathable air, and over a dozen corpses.</p>
<p>A creature trapped in the Cage can escape by using either <em>plane shift</em> or <Link to="/spell/freedom">freedom</Link>. If the Silent Aviary is destroyed or disenchanted while a creature is trapped in the Cage, the extradimensional space is immediately and permanently sealed, and becomes impossible to escape except with a <Link to="/spell/miracle">miracle</Link> or <em>wish.</em></p>
<h3 id="magic-wondrous-silent_aviary-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/plane_shift">plane shift</Link>, <Link to="/spell/wish">wish</Link>; <strong>Cost</strong> 97,500 gp</p>
</>};
const _silver_nail = {title: "Silver Nail", jsx: <><h2 id="magic-wondrous-silver_nail-silver-nail">Silver Nail</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 223</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> none; <strong>Price</strong> 2,100 gp; <strong>Weight</strong> -</p>
<p>This silver nail is finely engraved with hundreds of tiny runes that flash faintly blue under the light of the moon. The nail can be used to trap evil outsiders and incorporeal undead creatures to prevent their escape. To use a silver nail, the bearer must take a full-round action and succeed at a touch attack against a creature.</p>
<p>When used against a <Link to="/misc/helpless">helpless</Link> or <Link to="/rule/pinned">pinned</Link> evil outsider, the bearer can prevent that creature from escaping as per <em>dimensional anchor.</em></p>
<p>The bearer can instead trap an incorporeal undead creature. If he succeeds at a touch attack, the nail prevents the incorporeal undead creature from moving into walls or other solid objects.</p>
<p>The effects of the silver nail last 1 minute, during which the nail remains inside the creature. When this duration ends, the nail falls out and is forever rendered powerless. If used against a creature that is neither an outsider nor an incorporeal undead creature, the silver nail has no effect, but is still expended.</p>
<h3 id="magic-wondrous-silver_nail-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/dimensional_anchor">dimensional anchor</Link>, <Link to="/spell/plane_shift">plane shift</Link>; <strong>Cost</strong> 1,050 gp</p>
</>};
const _silver_nocking_point = {title: "Silver Nocking Point", jsx: <><h2 id="magic-wondrous-silver_nocking_point-silver-nocking-point">Silver Nocking Point</h2>
<p><strong>Sources</strong> <Link to="/source/ranged_tactics_toolbox">Ranged Tactics Toolbox pg. 29</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 1st<br/><strong>Slot</strong> none; <strong>Price</strong> 3,150 gp; <strong>Weight</strong> -</p>
<p>This small silver cylinder is no bigger than a pinhead and is engraved with an Elven aphorism that roughly translates to "unhindered flight." A silver nocking point can be attached to the string of any bow or crossbow. When using a weapon equipped with a silver nocking point, a character can treat penalties for <Link to="/rule/wind">wind conditions</Link> as though they were one step less severe. For example, a character firing a ranged projectile in severe wind conditions would fire at a ranged penalty of -2 instead of -4. Magical wind effects that would normally deflect the projectile (such as <Link to="/spell/fickle_winds">fickle winds</Link>) instead impose only a -8 penalty on the attack roll.</p>
<h3 id="magic-wondrous-silver_nocking_point-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/true_strike">true strike</Link>; <strong>Cost</strong> 1,575 gp</p>
</>};
const _silversheen = {title: "Silversheen", jsx: <><h2 id="magic-wondrous-silversheen-silversheen">Silversheen</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 319</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 529</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 250 gp; <strong>Weight</strong> -</p>
<p>This shimmering paste-like substance can be applied to a weapon as a standard action. It gives the weapon the properties of <Link to="/eq-material/alchemical_silver">alchemical silver</Link> for 1 hour, replacing the properties of any other special material it might have. One vial coats a single melee weapon or 20 units of ammunition.</p>
<h3 id="magic-wondrous-silversheen-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>; <strong>Cost</strong> 125 gp</p>
</>};
const _singing_bell_of_striking = {title: "Singing Bell of Striking", jsx: <><h2 id="magic-wondrous-singing_bell_of_striking-singing-bell-of-striking">Singing Bell of Striking</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 319</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This simple bowl-shaped bell made of either <Link to="/eq-material/cold_iron">cold iron</Link> or silver is played by rubbing a leather mallet along its rim, creating a ringing sound. By playing the bell while meditating or resting to regain ki, the bearer may attune his ki points to the instrument. Once attuned, the bearer's ki strikes count as cold iron (if the bell is cold iron) or silver (if the bell is silver) instead of magic for the purpose of overcoming damage reduction. This lasts until the next time the bearer rests or meditates to regain ki points. A creature can only be attuned to one singing bell at a time, and a singing bell can only be attuned to one person at a time. Only creatures whose ki strikes normally act as magic weapons can use a singing bell of striking.</p>
<h3 id="magic-wondrous-singing_bell_of_striking-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/versatile_weapon">versatile weapon</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _sinners_wage = {title: "Sinner's Wage", jsx: <><h2 id="magic-wondrous-sinners_wage-sinners-wage">Sinner's Wage</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_corruption">Champions of Corruption pg. 31</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 7th<br/><strong>Slot</strong> none; <strong>Price</strong> 500 gp; <strong>Weight</strong> -</p>
<p>A sinner's wage is a round golden coin with two blank faces. When placed among nonmagical currency, it adopts the size, shape, and any embellishments (such as an engraving or stamp) of the majority of the other coins.</p>
<p>When included as payment for any service that compromises the recipient's morals (such as a bribe for a lawful city guard to look the other way, or a contribution to a good politician to pass dubious legislation), a sinner's wage makes the offered payment more tempting. The giver of the sinner's wage gains a +2 profane bonus on Charisma checks and <Link to="/skill/bluff">Bluff</Link>, <Link to="/skill/diplomacy">Diplomacy</Link>, and <Link to="/skill/intimidate">Intimidate</Link> checks to convince the recipient to perform the service in question. Thus, the item can be used to pay off a guard as well as convince an outsider to perform a service with a <Link to="/spell/planar_binding">planar binding</Link> spell (in the latter case, the +2 profane bonus stacks with the bonus normally granted for offering a reward to the outsider).</p>
<p>In addition, a sinner's wage can be used as an optional focus component when the owner casts any charm or compulsion spell of 5th level or lower. When a creature is subject to a spell incorporating this focus, it takes a -2 penalty on all rolls to resist acting against its nature (whether a Will saving throw or a Charisma check). Using the sinner's wage in this fashion temporarily drains the magic from the coin, rendering it unusable for any purpose for a period of 1 week.</p>
<h3 id="magic-wondrous-sinners_wage-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/charm_monster">charm monster</Link>; <strong>Cost</strong> 250 gp</p>
</>};
const _skeleton_anchor = {title: "Skeleton Anchor", jsx: <><h2 id="magic-wondrous-skeleton_anchor-skeleton-anchor">Skeleton Anchor</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_58_island_of_empty_eyes">Pathfinder #58: Island of Empty Eyes pg. 61</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 7th<br/><strong>Slot</strong> none; <strong>Price</strong> 14,450 gp; <strong>Weight</strong> 100 lbs.</p>
<p>This ship's anchor is crafted of fused bones and skulls, but it has the strength and hardness of iron. When attached to a ship by a rope or chain and dropped into the water, the anchor increases its weight to properly anchor the ship it is attached to. Once per day, the skeleton anchor can hold the ship it is attached to immobile for up to 1 day, or until commanded to release.</p>
<p>The greatest property of a skeleton anchor, however, is to summon undead <Link to="/template/skeleton">skeletons</Link> from the corpses of drowned mariners, who rise from the depths of the sea and clamber up the sides of the ship to serve as its crew. The undead created by the anchor are 1 Hit Die skeletons that possess <Link to="/skill/profession">Profession (sailor)</Link> scores of +7. Each skeleton can perform the duties of one crew member but has no other abilities. The skeletons cannot speak, attack, or even defend themselves. They are not proficient with any weapons or armor. The skeletons obey the commands of the ship's captain or pilot, but they only obey orders pertaining to the operation of a ship.</p>
<p>A skeleton anchor can be used just once every 7 days to create up to 28 skeletal crew members. The skeletons do not count against the maximum total Hit Dice worth of undead creatures that the user can control. The skeletons act as crew for 1 week or until dismissed by the ship's captain or pilot. At the end of the week, the skeletons abandon the ship.</p>
<h3 id="magic-wondrous-skeleton_anchor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/desecrate">desecrate</Link>, <Link to="/spell/levitate">levitate</Link>, <Link to="/spell/skeleton_crew">skeleton crew</Link>; <strong>Cost</strong> 7,250 gp</p>
</>};
const _skill_slug = {title: "Skill Slug", jsx: <><h2 id="magic-wondrous-skill_slug-skill-slug">Skill Slug</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_goblins_1">Pathfinder Goblins #1 pg. 29</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 750 gp; <strong>Weight</strong> -</p>
<p>Skill slugs are tiny, segmented parasites incubated primarily in the exposed brains of imprisoned <Link to="/monster/caulborn">caulborn</Link>. Long as a baby's finger and twice as plump, these quivering gastropods draw sustenance from the memory fragments extracted from the caulborn. A measure of those memories lives on within the slug. When consumed, the skill slug grants a +10 competence bonus on a single Intelligence-based skill for 1 hour. Each slug's associated skill is determined at the time of its creation, and cannot be changed. The swallower counts as trained in the skill even if he does not have ranks in it.</p>
<h3 id="magic-wondrous-skill_slug-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/share_memory">share memory</Link>; <strong>Cost</strong> 375 gp</p>
</>};
const _skin_harp = {title: "Skin Harp", jsx: <><h2 id="magic-wondrous-skin_harp-skin-harp">Skin Harp</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_63_the_asylum_stone">Pathfinder #63: The Asylum Stone pg. 58</Link><br/><strong>Aura</strong> moderate enchantment and necromancy; <strong>CL</strong> 9th<br/><strong>Slot</strong> none; <strong>Price</strong> 16,500 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This small harp is made from a <Link to="/monster/sprite">sprite's</Link> twisted, leathery corpse, its arms and legs arching up to hold the crossbar along the instrument's top. The strings are made from thin strips of twisted flesh flayed from the fey's torso and strung between their anchor points on the corpse and the crossbar. Though the corpse's chest cavity is clearly visible, all viscera have been removed.</p>
<p>A skin harp functions as a <Link to="/eq-misc/masterwork_harp">masterwork harp</Link>. In addition, once per day, it can be activated to cast either <em>command undead</em> or <em>dominate person</em> (Will DC 19 negates). With a successful DC 20 <Link to="/skill/perform">Perform (string)</Link> check, the save DC for this effect increases by +2. When used in this manner, the harp animates and plays itself, the corpse freeing one hand from the crossbar in order to strum its flesh strings.</p>
<h3 id="magic-wondrous-skin_harp-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/command_undead">command undead</Link>, <Link to="/spell/dominate_person">dominate person</Link>; <strong>Cost</strong> 8,550 gp</p>
</>};
const _skyspirit_stone = {title: "Skyspirit Stone", jsx: <><h2 id="magic-wondrous-skyspirit_stone-skyspirit-stone">Skyspirit Stone</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 24</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 2,000 gp; <strong>Weight</strong> 1/2 lb.</p>
<p>This object was naturally struck by lightning and imbued with a spirit of the sky. Despite the name, this object does not have to be a stone, though small objects made into skyspirit stones are the most common, convenient, and prized. Once per day, the stone can be placed in liquor or milk for 1 minute to infuse the liquid with the spirit's power. A <Link to="/class/kineticist">kineticist</Link> with the air <Link to="/ability/elements">elemental focus</Link> (aerokineticist) can drink this liquid as a move action to gain assistance from the spirit's power. For 1 hour after drinking the liquid, the kineticist can negate a single point of burn gained from using her kineticist abilities (this does not heal the associated nonlethal damage from the point of burn). This effect does not stack with itself.</p>
<h3 id="magic-wondrous-skyspirit_stone-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/lesser_restoration">lesser restoration</Link>; <strong>Cost</strong> 1,000 gp</p>
</>};
const _smear_of_seeing = {title: "Smear of Seeing", jsx: <><h2 id="magic-wondrous-smear_of_seeing-smear-of-seeing">Smear of Seeing</h2>
<p><strong>Sources</strong> <Link to="/source/dungeoneers_handbook">Dungeoneer's Handbook pg. 29</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 10th<br/><strong>Slot</strong> none; <strong>Price</strong> 4,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This oily black paste is kept in a glass jar about the size of a human's fist. When rubbed onto an opaque surface as a standard action, an application of smear of seeing allows others to see through it for 10 minutes or until it is thoroughly diluted with <Link to="/magic-wondrous/universal_solvent">universal solvent</Link>, after which the smear loses its potency. Anyone on the side of the surface on which the smear was applied can see through that surface as though it were a clear glass window. This does not enable creatures to hear through the surface. Creatures on the other side of a surface affected with smear of seeing cannot see the effect, but may detect it via <Link to="/spell/detect_magic">detect magic</Link> or other effects as normal.</p>
<p>Smear of seeing can be used on plaster, stone, wooden, or similar surfaces up to 10 feet thick. Smear of seeing has no effect on metal or harder materials, regardless of thickness.</p>
<p>One application of smear of seeing is enough to cover a 1-foot-radius area; multiple applications can be used to increase the affected surface area. One jar of smear of seeing contains enough paste for five applications.</p>
<h3 id="magic-wondrous-smear_of_seeing-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/arcane_eye">arcane eye</Link>, <Link to="/spell/see_through_stone">see through stone</Link>; <strong>Cost</strong> 2,000 gp</p>
</>};
const _smoke_bomb_of_forgetfulness = {title: "Smoke bomb of Forgetfulness", jsx: <><h2 id="magic-wondrous-smoke_bomb_of_forgetfulness-smoke-bomb-of-forgetfulness">Smoke bomb of Forgetfulness</h2>
<p><strong>Sources</strong> <Link to="/source/villain_codex">Villain Codex pg. 225</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 10th<br/><strong>Slot</strong> none; <strong>Price</strong> 900 gp; <strong>Weight</strong> -</p>
<p>Killers use smoke bombs of forgetfulness to conceal their identities and cover their escapes in the event of failed assassination attempts. The smoke bomb can be thrown to the ground as a standard action, destroying the item and creating a cloud of smoke with a 15-foot radius. This acts like the smoke from a <Link to="/eq-misc/smokestick">smokestick</Link>, and can be thrown at the user's feet or as a ranged touch attack with a range of 20 feet.</p>
<p>Any creature in the smoke cloud that isn't aware of the smoke bomb's nature must succeed at a DC 16 Will save or have its memory altered as though its sight had been obscured during the previous 2 rounds. This can cause it to forget the appearance of any creatures with which it had interacted or battled with during that time. From the point the smoke bomb is thrown, it functions as normal smoke, giving the user time to escape but no longer protecting its identity from creatures that leave the smoke and can see the user.</p>
<p>A creature that is already aware of the abilities of a smoke bomb of forgetfulness and suspects this smoke bomb is one automatically succeeds at the save. The memory alteration is a mind-affecting effect.</p>
<h3 id="magic-wondrous-smoke_bomb_of_forgetfulness-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/modify_memory">modify memory</Link>; <strong>Cost</strong> 450 gp</p>
</>};
const _smugglers_wayfinder = {title: "Smuggler's Wayfinder", jsx: <><h2 id="magic-wondrous-smugglers_wayfinder-smugglers-wayfinder">Smuggler's Wayfinder</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_society_primer">Pathfinder Society Primer pg. 21</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> none; <strong>Price</strong> 2,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This time-weathered <Link to="/magic-wondrous/wayfinder">wayfinder</Link> lacks any notable features. Despite its routine appearance, a smuggler's wayfinder has an additional ability generally known only to the person using it. When a command word is spoken, the compass's interior is replaced with a small extradimensional space that can hold up to 10 pounds of material occupying no more than 1 cubic foot of space. This material must be able to fit through the 3-inch-diameter opening in the compass's face (such as a thin glass vial, coins, small jewelry, or a rolled-up piece of paper). While the extradimensional space is accessible, all other properties of the wayfinder cease to function, including any resonant ioun stone powers. While the extradimensional space is hidden, the smuggler's wayfinder emits an aura of faint evocation, as a standard wayfinder.</p>
<h3 id="magic-wondrous-smugglers_wayfinder-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/light">light</Link>, <Link to="/spell/magic_aura">magic aura</Link>, <Link to="/spell/secret_chest">secret chest</Link>; <strong>Cost</strong> 1,000 gp</p>
</>};
const _snake_charmers_flute = {title: "Snake Charmer's Flute", jsx: <><h2 id="magic-wondrous-snake_charmers_flute-snake-charmers-flute">Snake Charmer's Flute</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_120_vault_of_the_onyx_citadel">Pathfinder #120: Vault of the Onyx Citadel pg. 19</Link><br/><strong>Aura</strong> strong conjuration and enchantment; <strong>CL</strong> 17th<br/><strong>Slot</strong> none; <strong>Price</strong> 26,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>Two distinct songs are etched on the entwined pipes of this flute. Playing the first creates a soothing, rhythmic melody that lulls snakes and serpents into compliance. This tune grants a +5 competence bonus on <Link to="/skill/handle_animal">Handle Animal</Link> and <Link to="/ability/wild_empathy">wild empathy</Link> checks to influence snakes as well as snake-like animals and magical beasts. If the musician lacks the wild empathy class feature, she can still use this song to influence snakes and snake-like creatures as if she had wild empathy, applying only her Charisma modifier and the flute's +5 bonus to the roll.</p>
<p>The second song of the snake charmer's flute can be performed only once per day as a full-round action. When used, it summons an <Link to="/template/advanced">advanced</Link> <Link to="/monster/giant_anaconda">giant anaconda</Link>. This serpent obeys the musician's mental commands and remains as long as the user continues to spend a move action each round maintaining the tune, up to a maximum of 3 minutes.</p>
<h3 id="magic-wondrous-snake_charmers_flute-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/dominate_monster">dominate monster</Link>, <Link to="/spell/summon_natures_ally_viii">summon nature's ally VIII</Link>; <strong>Cost</strong> 13,000 gp</p>
</>};
const _snapleaf = {title: "Snapleaf", jsx: <><h2 id="magic-wondrous-snapleaf-snapleaf">Snapleaf</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 319</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 750 gp; <strong>Weight</strong> -</p>
<p>This crystalline carving looks like a hand-sized tree leaf. It is usually worn around the neck on a strap so it is within easy reach, but can be affixed to a belt or clothing just like a badge. While falling, the bearer can snap and destroy the snapleaf as an immediate action to gain the benefits of <em>feather fall</em> and <em>invisibility.</em> The duration of the two effects work independently; ending one early does not affect the other. The item cannot be activated to provide just one of these two effects; they are always activated simultaneously.</p>
<h3 id="magic-wondrous-snapleaf-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/feather_fall">feather fall</Link>, <Link to="/spell/invisibility">invisibility</Link>; <strong>Cost</strong> 375 gp</p>
</>};
const _snowfall_orb = {title: "Snowfall Orb", jsx: <><h2 id="magic-wondrous-snowfall_orb-snowfall-orb">Snowfall Orb</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_elements">Blood of the Elements pg. 30</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 13th<br/><strong>Slot</strong> none; <strong>Price</strong> 14,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>On the borderlands between the Plane of Air and the Plane of Water, vast sheets of glacial ice tip from one realm to the other, storms of boulder-sized hail pulverize extant structures, and entire nations of snow swirl amid the dense interplanar vapors. The snowfall orb is a relic of this harsh realm and is capable of channeling its awesome elemental power in a variety of ways.</p>
<p>First, anytime the owner's equipment is targeted by <Link to="/spell/heat_metal">heat metal</Link>, the effect is automatically countered as if the snowfall orb had cast <em>chill metal.</em></p>
<p>Second, once per day, the owner can concentrate on the orb for 10 minutes to alter the weather in a 1-mile radius. Doing so causes snow, heavy snow, sleet, or hail (user's choice) to fall within that radius for 1d4 hours, regardless of the environment's predominant climate or season. This ability otherwise functions as <em>control weather.</em></p>
<p>Finally, the user can throw a snowfall orb at an opponent as a ranged touch attack with a range increment of 20 feet. On a hit, the orb is destroyed and the target immediately takes 5d6 points of cold damage. At the beginning of each round thereafter for 4 rounds, the target takes an additional 1d6 points of cold damage and must succeed at a DC 15 Fortitude save or take 1d2 points of <Link to="/rule/dexterity_damage">Dexterity damage</Link> and become <Link to="/misc/staggered">staggered</Link> for 1 round. If the target takes 3 or more points of Dexterity damage in this way, the creature becomes <Link to="/misc/fatigued">fatigued</Link>; if the target takes 5 or more points of Dexterity damage, it becomes <Link to="/misc/exhausted">exhausted</Link> instead.</p>
<h3 id="magic-wondrous-snowfall_orb-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/chill_metal">chill metal</Link>, <Link to="/spell/control_weather">control weather</Link>, <Link to="/spell/snowball">snowball</Link>; <strong>Cost</strong> 7,000 gp</p>
</>};
const _solidsmoke_pipeweed = {title: "Solidsmoke Pipeweed", jsx: <><h2 id="magic-wondrous-solidsmoke_pipeweed-solidsmoke-pipeweed">Solidsmoke Pipeweed</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 67</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> none; <strong>Price</strong> 1,000 gp; <strong>Weight</strong> -</p>
<p>When smoked in any pipe, this pinch of magical tobacco produces a languid, milky-white smoke that the smoker can transform into useful objects. A <Link to="/race/halfling">halfling</Link> who puffs on the pipe as a full-round action can shape the smoke into an object weighing no more than 5 pounds and having a maximum volume of 1 cubic foot. The halfling can, on following rounds, spend additional full-round actions to increase the object's weight by 2 additional pounds and its volume by another cubic foot. The halfling must succeed at an appropriate <Link to="/skill/craft">Craft</Link> check to make a complex item. If the halfling stops puffing on her pipe for any reason before she finishes creating the object, the figure in the smoke collapses and her pipe is extinguished. Objects created by solidsmoke pipeweed last for 24 hours before fading away into vapor. Objects created by the pipeweed have the same hardness, hit points, and other qualities as manufactured objects of their type, but look smoky and indistinct. Each pinch of solidsmoke pipeweed is sufficient for 3 full rounds of smoking. A single larger item must be created with a single pinch of solidsmoke pipeweed, so any item created with this pipeweed can't be larger than 9 pounds and 3 cubic feet.</p>
<p>A halfling cannot create an object designed to exactly duplicate or replace another specific object. For instance, while she could create a smoky lock with its own key, she could not puff smoke into an existing keyhole and then create a key that would open that particular lock.</p>
<p>This smoke is caustic and chokes non-halflings. It grants non-halflings no benefits, and each time they spend a standard action to smoke the pipeweed, they are <Link to="/misc/sickened">sickened</Link> for 1 round.</p>
<h3 id="magic-wondrous-solidsmoke_pipeweed-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/minor_creation">minor creation</Link>, creator must be a halfling; <strong>Cost</strong> 500 gp</p>
</>};
const _soothing_lyre = {title: "Soothing Lyre", jsx: <><h2 id="magic-wondrous-soothing_lyre-soothing-lyre">Soothing Lyre</h2>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook pg. 31</Link><br/><strong>Aura</strong> strong conjuration and enchantment; <strong>CL</strong> 13th<br/><strong>Slot</strong> none; <strong>Price</strong> 45,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>This ornate string instrument looks as if it were crafted from gold and silver but is as light as hollow wood. It grants a +2 circumstance bonus on <Link to="/skill/perform">Perform (string)</Link> checks. When the proper chords are struck (a standard action), the bearer can target all creatures within a 30-foot-radius <Link to="/misc/burst">burst</Link> with a <em>lullaby</em> spell (DC 13) that lasts as long as the bearer concentrates plus up to 13 rounds.</p>
<p>Additionally, once per day as a standard action, she can strum the lyre to affect up to nine creatures with <em>mass cure light wounds,</em> as per the spell. If the character has the <Link to="/ability/bardic_performance">bardic performance</Link> class feature, instead of this effect, she can perform a <Link to="/performance/soothing_performance">soothing performance</Link> once per day, even if she is not of sufficient level to normally have access to that ability (this still requires 4 rounds of continuous performance and still uses her bard level as the caster level). A bard who can use soothing performance and who plays the lyre as part of her performance increases her effective caster level for that ability by 1.</p>
<h3 id="magic-wondrous-soothing_lyre-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/lullaby">lullaby</Link>, <Link to="/spell/mass_cure_light_wounds">mass cure light wounds</Link>, creator must be a bard of at least 12th level with the bardic performance class ability; <strong>Cost</strong> 22,500 gp</p>
</>};
const _soul_jar = {title: "Soul Jar", jsx: <><h2 id="magic-wondrous-soul_jar-soul-jar">Soul Jar</h2>
<p><strong>Sources</strong> <Link to="/source/curse_of_the_crimson_throne">Curse of the Crimson Throne pg. 436</Link>, <Link to="/source/pathfinder_33_the_varnhold_vanishing">Pathfinder #33: The Varnhold Vanishing pg. 53</Link>, <Link to="/source/pathfinder_64_beyond_the_doomsday_door">Pathfinder #64: Beyond the Doomsday Door pg. 61</Link>, <Link to="/source/lost_treasures">Lost Treasures pg. 55</Link><br/><strong>Aura</strong> strong necromancy; <strong>CL</strong> 15th<br/><strong>Slot</strong> none; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>An empty soul jar can be used to contain a soul that has been successfully trapped in a black sapphire via <em>soul bind.</em> Holding the gemstone against the soul jar's lid for 1 full round transfers the soul in the gem to the soul jar (which can hold the soul of a creature of up to 20 Hit Dice), leaving the black sapphire unharmed 50% of the time. The rest of the time, transferring the soul from gem to jar shatters the black sapphire. A creature that can use <em>soul bind</em> as a spell-like ability (and thus does not use a focus) can automatically place a captured soul in a held soul jar as the spell-like ability is used. A soul in a soul jar cannot travel to the Boneyard to be judged, but can be restored to life via <Link to="/spell/resurrection">resurrection</Link> or more powerful magic. A soul jar can contain only one soul at a time. Soul jars are fragile (hardness 1, hp 10); if a soul jar is broken, the soul held within immediately escapes to the Boneyard.</p>
<h3 id="magic-wondrous-soul_jar-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/soul_bind">soul bind</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _soul_scribe_quill = {title: "Soul Scribe Quill", jsx: <><h2 id="magic-wondrous-soul_scribe_quill-soul-scribe-quill">Soul Scribe Quill</h2>
<p><strong>Sources</strong> <Link to="/source/planar_adventures">Planar Adventures pg. 55</Link><br/><strong>Aura</strong> faint necromancy; <strong>CL</strong> 5th<br/><strong>Slot</strong> none; <strong>Price</strong> 4,500 gp; <strong>Weight</strong> -</p>
<p>This elaborate red and black quill contains an endless reservoir of red ink that resembles fresh blood. Once per day, when within 5 feet of a living creature with -1 or fewer hit points, the bearer can activate this quill as a standard action by scribing a short sentence in the air with it describing the dying creature's death. If the victim fails a DC 15 Will save, it dies, and the bearer gains a +5 profane bonus on <Link to="/skill/bluff">Bluff</Link>, <Link to="/skill/diplomacy">Diplomacy</Link>, and <Link to="/skill/sense_motive">Sense Motive</Link> checks, a +1 profane bonus to caster level for spell-like abilities, and a +2 enhancement bonus to Charisma for 10 minutes per Hit Die of the victim.</p>
<h3 id="magic-wondrous-soul_scribe_quill-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/death_knell">death knell</Link>, <Link to="/spell/honeyed_tongue">honeyed tongue</Link>; <strong>Cost</strong> 2,250 gp</p>
</>};
const _soul_soap = {title: "Soul Soap", jsx: <><h2 id="magic-wondrous-soul_soap-soul-soap">Soul Soap</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 320</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 309</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 1st<br/><strong>Slot</strong> none; <strong>Price</strong> 200 gp; <strong>Weight</strong> 2 lbs.</p>
<p>This small bar of coarse gray soap has tiny pieces of ash, coal, or hard earth embedded in it, leaving anyone washed with it as dirty as before. Washing a creature with the soap requires water and takes 1 minute, after which the creature can attempt a new Will saving throw against any hostile ongoing mind-affecting effect currently affecting it. Unwilling creatures must be <Link to="/rule/pin">pinned</Link> or otherwise made helpless before they can be washed. The soap is sufficient to wash one creature.</p>
<h3 id="magic-wondrous-soul_soap-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/resistance">resistance</Link>; <strong>Cost</strong> 100 gp</p>
</>};
const _soultheft_glass = {title: "Soultheft Glass", jsx: <><h2 id="magic-wondrous-soultheft_glass-soultheft-glass">Soultheft Glass</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 262</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 9th<br/><strong>Slot</strong> none; <strong>Price</strong> 33,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>The wielder of this hand-sized, fine glass mirror can view another's reflection in the mirror to capture a portion of that creature's soul. Doing so requires the wielder to avert his eyes as if defending against a <Link to="/umr/gaze">gaze</Link> attack so that he views the creature only by its reflection, and then take a standard action that provokes an attack of opportunity. This imposes 1 temporary <Link to="/rule/negative_level">negative level</Link> on the creature reflected (Fortitude DC 16 negates). A soultheft glass can hold no more than three portions of a creature's soul, and can't contain portions from more than one creature's soul at a time. When the glass is at full capacity, attempts to steal additional soul portions fail. While the mirror retains at least one soul portion, its possessor receives a +1 luck bonus on ability checks, saving throws, and skill checks.</p>
<p>The wielder can query the soul portions trapped within, in effect questioning echoed memories of the target creature. This works as <em>call spirit,</em> except the creature doesn't need to be dead. The wielder can ask a number of questions per day equal to the number of soul portions in the glass.</p>
<p>Temporary negative levels bestowed by a soultheft glass never become permanent. The victim can attempt a DC 16 Fortitude save to remove each negative level every 24 hours. Success removes that negative level and frees one soul portion held within the glass. Any other method of removing a negative level (such as <Link to="/spell/restoration">restoration</Link>) also frees a soul portion from the glass.</p>
<p>Once it imposes a temporary negative level on a creature, a soultheft glass shows a ghostly reflection of that creature (though not any information about its surroundings) until all soul portions have been returned. If the victim dies, its soul portions fade after 24 hours. As a standard action, the mirror's wielder can release all soul portions, which also removes the victim's negative levels.</p>
<h3 id="magic-wondrous-soultheft_glass-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/call_spirit">call spirit</Link>, <Link to="/spell/enervation">enervation</Link>; <strong>Cost</strong> 16,500 gp</p>
</>};
const _sovereign_glue = {title: "Sovereign Glue", jsx: <><h2 id="magic-wondrous-sovereign_glue-sovereign-glue">Sovereign Glue</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 320</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 530</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 20th<br/><strong>Slot</strong> none; <strong>Price</strong> 2,400 gp; <strong>Weight</strong> -</p>
<p>This pale amber substance is thick and viscous. Because of its particular powers, it can be contained only in a flask whose inside has been coated with 1 ounce of <Link to="/magic-wondrous/salve_of_slipperiness">salve of slipperiness</Link>, and each time any of the bonding agent is poured from the flask, a new application of the salve of slipperiness must be put in the flask within 1 round to prevent the remaining glue from adhering to the side of the container. A flask of sovereign glue, when found, holds anywhere from 1 to 7 ounces of the stuff (1d8-1, minimum 1), with the other ounce of the flask's capacity taken up by the salve of slipperiness. One ounce of this adhesive covers 1 square foot of surface, bonding virtually any two substances together in a permanent union. The glue takes 1 round to set. If the objects are pulled apart (a move action) before that time has elapsed, that application of the glue loses its stickiness and is worthless. If the glue is allowed to set, then attempting to separate the two bonded objects has no effect, except when <Link to="/magic-wondrous/universal_solvent">universal solvent</Link> is applied to the bond. Sovereign glue is dissolved by universal solvent.</p>
<p>The price and creation cost given are per ounce.</p>
<h3 id="magic-wondrous-sovereign_glue-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/make_whole">make whole</Link>; <strong>Cost</strong> 1,200 gp</p>
</>};
const _sovereign_shabti = {title: "Sovereign Shabti", jsx: <><h2 id="magic-wondrous-sovereign_shabti-sovereign-shabti">Sovereign Shabti</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_84_pyramid_of_the_sky_pharaoh">Pathfinder #84: Pyramid of the Sky Pharaoh pg. 91</Link><br/><strong>Aura</strong> strong conjuration; <strong>CL</strong> 17th<br/><strong>Slot</strong> none; <strong>Price</strong> 130,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>During its creation, a sovereign shabti is bound to a single member of royalty who willingly donates 3 drops of her blood and writes her own name upon a strip of parchment. These are placed within a hollow figurine typically made of gold, jade, or gemstone that, when completed, has hardness 5 and 5 hit points.</p>
<p>If the sovereign shabti still exists when the bound individual dies, its magic takes effect. The figurine's power speeds the spirit along the River of Souls, assuring it safely reaches the Boneyard. The soul is judged 2d12 hours after dying, at which point the figurine expels its power to create a new being, a living 1st-level <Link to="/race/shabti">shabti</Link> duplicate of the bound individual. If the soul was condemned to torment or labor, the shabti goes in its place - the bound individual's spirit traveling to some favorable corner of a plane matching her alignment. If the soul was to be rewarded, the shabti appears on to the fringes of Axis. Once the shabti has been created, the bound individual cannot be returned to life by any means short of divine intervention. The sovereign shabti - which does not travel with the bound soul - crumbles as soon as it creates a shabti.</p>
<h3 id="magic-wondrous-sovereign_shabti-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/trap_the_soul">trap the soul</Link>, <Link to="/spell/true_resurrection">true resurrection</Link>, 3 drops of royal blood, a royal name; <strong>Cost</strong> 65,000 gp</p>
</>};
const _spartoi_seeds = {title: "Spartoi Seeds", jsx: <><h2 id="magic-wondrous-spartoi_seeds-spartoi-seeds">Spartoi Seeds</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_28_the_infernal_syndrome">Pathfinder #28: The Infernal Syndrome pg. 89</Link><br/><strong>Aura</strong> strong conjuration; <strong>CL</strong> varies<br/><strong>Slot</strong> none; <strong>Price</strong> 3,300 gp; <strong>Weight</strong> -</p>
<p>Spartoi seeds appear as teeth stained by ash. The teeth themselves typically take the form of tiny dragon teeth, though some appear to come from a serpent, wolf, or human. When a tooth is cast upon the earth as a standard action, a <Link to="/monster/spartolos">spartolos</Link> under the user's command erupts on the following round. The spartolos lasts for 1 hour or until destroyed. A spartolos's equipment vanishes if its owner is destroyed or after an hour.</p>
<p>These seeds are typically found in simple pouches of leather or velvet containing 2d4 teeth. Up to six seeds can be sown by a single standard action.</p>
<h3 id="magic-wondrous-spartoi_seeds-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/create_undead">create undead</Link>; <strong>Cost</strong> 1,650 gp</p>
</>};
const _spectral_searchlight = {title: "Spectral Searchlight", jsx: <><h2 id="magic-wondrous-spectral_searchlight-spectral-searchlight">Spectral Searchlight</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_71_rasputin_must_die">Pathfinder #71: Rasputin Must Die! pg. 61</Link><br/><strong>Aura</strong> faint divination and evocation [light]; <strong>CL</strong> 3rd<br/><strong>Slot</strong> none; <strong>Price</strong> 24,050 gp; <strong>Weight</strong> 200 lbs.</p>
<p>Created by Rasputin and the Russian inventor Viktor Miloslav, this carbon-arc spotlight provides normal light in a 360-foot line and increases the <Link to="/rule/light_level">light level</Link> by one step in the area beyond that, out to a 720-foot line (darkness becomes dim light and dim light becomes normal light). A spectral searchlight also reveals ethereal or invisible creatures or objects in its area of effect. Spectral searchlights are normally mounted in watchtowers or atop two-wheeled carts for easier transport.</p>
<h3 id="magic-wondrous-spectral_searchlight-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/continual_flame">continual flame</Link>, <Link to="/spell/see_invisibility">see invisibility</Link>; <strong>Cost</strong> 12,050 gp</p>
</>};
